window.__ARXIV_DATA__ = {"papers":[{"id":"2607.11886v1","title":"Read It Back: Pretrained MLLMs Are Zero-Shot Reward Models for Text-to-Image Generation","abstract":"In this paper, we propose SpectraReward, a training-free reward function that turns pretrained MLLMs into off-the-shelf reward models for image-generation reinforcement learning. Instead of asking the MLLM to judge a generated image or answer decomposed verification questions, SpectraReward measures how well the original prompt can be recovered from the generated image through a single image-conditioned, teacher-forced forward pass. We use the average image-conditioned prompt log-likelihood as the reward, directly reusing the MLLM's pretrained image-text alignment ability without preference labels, reward-model fine-tuning. We further introduce Self-SpectraReward, a special case for unified multimodal models where the policy's own understanding branch serves as the reward model for its generation branch, forming a closed-loop self-improving framework without external reward models or external knowledge. Extensive experiments validate SpectraReward through a broad image-generation RL study covering two diffusion models, three RL algorithms, nine reward MLLM backbones from four MLLM families spanning 4B to 235B parameters, and five out-of-distribution text-to-image benchmarks. Results show that both SpectraReward and Self-SpectraReward significantly and consistently improve generation performance and outperform prior MLLM-derived reward training methods. Further analysis reveals that larger reward MLLMs are not always better, while Self-SpectraReward can match or surpass much larger external reward models, suggesting that reward-policy alignment is a key factor for effective image-generation RL. Project Page: https://huangrh99.github.io/SpectraReward/","authors":["Runhui Huang","Qihui Zhang","Zhe Liu","Yu Gao","Jie Wu","Hengshuang Zhao"],"published":"2026-07-13T17:59:58Z","updated":"2026-07-13T17:59:58Z","abstract_url":"https://arxiv.org/abs/2607.11886v1","html_url":"https://arxiv.org/html/2607.11886v1","pdf_url":"https://arxiv.org/pdf/2607.11886v1.pdf","matched_keywords":["multimodal","diffusion"],"source_used":"html","source_text_chars":56240,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal, diffusion 相关；摘要显示其主要贡献为：In this paper, we propose SpectraReward, a training-free reward function that turns pretrained MLLMs into off-the-shelf reward models for image-generation reinforcement learning. Instead of asking the MLLM to judge a generated image or answer decomposed verif...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:25+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11885v1","title":"Latent-Identity Tuning in Text-to-Image Personalization Models","abstract":"Generating and editing a person's face demands high precision, as even minor modifications can significantly alter a subject's perceived identity. Current personalization and editing methods built on general-purpose text-to-image models, however, often lack the precision required for fine-grained facial edits. We present a method for fine-grained identity tuning in text-to-image personalization models. Unlike standard image editing, which operates on a given image, identity tuning modifies the latent representation of a specific identity, enabling the generation of diverse images that consistently depict the same edited identity. To enable fine-grained latent identity tuning, we explore the latent space of a pre-trained, frozen encoder for text-to-image personalization. Our approach requires no additional training. Instead, it leverages the existing architecture of a frozen encoder to uncover latent semantic directions. This space consists of a set of latent tokens that play distinct roles in capturing different aspects of an identity and often correspond to specific spatial or semantic facial regions. We show that meaningful directions can be identified within this space and within subspaces defined by selected tokens, enabling localized, fine-grained, and semantically coherent edits. We validate our approach through qualitative and quantitative experiments that demonstrate diverse localized facial edits while preserving cross-image identity consistency. Project page at: https://garibida.github.io/IdentityTuning/","authors":["Daniel Garibi","Ronen Kamenetsky","Hadar Averbuch-Elor","Daniel Cohen-Or","Or Patashnik"],"published":"2026-07-13T17:59:49Z","updated":"2026-07-13T17:59:49Z","abstract_url":"https://arxiv.org/abs/2607.11885v1","html_url":"https://arxiv.org/html/2607.11885v1","pdf_url":"https://arxiv.org/pdf/2607.11885v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":73803,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：Generating and editing a person's face demands high precision, as even minor modifications can significantly alter a subject's perceived identity. Current personalization and editing methods built on general-purpose text-to-image models, however, often lack t...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:25+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11862v1","title":"Evidence-Backed Video Question Answering","abstract":"Current Video Large Language Models (Video LLMs) excel in question answering (QA) but largely operate as black boxes, providing textual answers without verifiable visual grounding. Existing explainability efforts rely on textual rationales or sparse bounding boxes, which struggle to capture complex video dynamics such as occlusions and non-rigid deformations. We propose Evidence-Backed Video Question Answering (E-VQA), a novel task requiring models to jointly output a semantic answer and precise spatio-temporal evidence: temporal segments and dense, tracked object segmentation masklets. To support this, we introduce ST-Evidence, the first human-verified benchmark for both discriminative and generative pixel-level grounding. Evaluations of state-of-the-art models reveal a critical decoupling between QA accuracy and true visual perception that scaling alone fails to bridge. To address this, we develop scalable, automated generation pipelines to create ST-Evidence-Instruct, a 160k-scale dataset bridging high-level reasoning with fine-grained grounding. Fine-tuning grounded Video LLMs on this data yields substantial gains over the corresponding size-matched UniPixel baselines (e.g., +27.2 t-mean and +13.8 J&F on a 7B model), establishing a robust baseline for explainable, evidence-backed video understanding. Code and data are available at https://github.com/SalesforceAIResearch/EVQA.","authors":["Shijie Wang","Honglu Zhou","Ziyang Wang","Ran Xu","Caiming Xiong","Silvio Savarese","Chen Sun","Juan Carlos Niebles"],"published":"2026-07-13T17:49:10Z","updated":"2026-07-13T17:49:10Z","abstract_url":"https://arxiv.org/abs/2607.11862v1","html_url":"https://arxiv.org/html/2607.11862v1","pdf_url":"https://arxiv.org/pdf/2607.11862v1.pdf","matched_keywords":["video"],"source_used":"html","source_text_chars":50968,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video 相关；摘要显示其主要贡献为：Current Video Large Language Models (Video LLMs) excel in question answering (QA) but largely operate as black boxes, providing textual answers without verifiable visual grounding. Existing explainability efforts rely on textual rationales or sparse bounding...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:25+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11844v1","title":"Beyond the Single Camera: Agentic Multi-View Reasoning in Sports Video Understanding","abstract":"Recent Multimodal Large Language Models (MLLMs) achieve strong performance on single-view video understanding benchmarks. However, sports videos involve dense occlusion, rapid motion, and complex interactions that are difficult to resolve from a single viewpoint. In practice, sports events are recorded from multiple camera angles, providing complementary evidence used by referees. Yet, no existing benchmark evaluates MLLMs on multi-view sports video understanding. To address this gap, we introduce SportMV-Bench, a comprehensive benchmark built from official match recordings, through a dedicated pipeline combining LLM-based generation, MLLM-based verification, and human filtering to ensure quality and consistency. SportMV-Bench containing 787 multi-view video bundles and 2592 question-answer pairs across three categories: Perception-Aware Recognition (PAR), Rule-aware Event Interpretation (REI), and Adjudicative Decision Reasoning(ADR). Our analysis shows that current MLLMs fail to effectively exploit multi-view information, with the bottlenecks lying in fine-grained visual perception and view selection rather than logical reasoning or domain knowledge. We propose SportMV-Agent, an agentic framework that orchestrates an iterative loop of active view selection, perception tool execution, and evidence-grounded reasoning, achieving a significant 14.46% relative improvement over the strongest MLLM baseline.","authors":["Kerui Chen","Jinglu Wang","Xiaoyi Zhang","Yan Lu"],"published":"2026-07-13T17:34:36Z","updated":"2026-07-13T17:34:36Z","abstract_url":"https://arxiv.org/abs/2607.11844v1","html_url":"https://arxiv.org/html/2607.11844v1","pdf_url":"https://arxiv.org/pdf/2607.11844v1.pdf","matched_keywords":["video","agent","multimodal"],"source_used":"html","source_text_chars":61906,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, agent, multimodal 相关；摘要显示其主要贡献为：Recent Multimodal Large Language Models (MLLMs) achieve strong performance on single-view video understanding benchmarks. However, sports videos involve dense occlusion, rapid motion, and complex interactions that are difficult to resolve from a single viewpo...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:25+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11839v1","title":"LoRA-Based Cascaded Multimodal Fusion for Action Recognition in Medical Training Environments","abstract":"This paper presents a cascaded Low-Rank Adaptation (LoRA)-based multimodal fusion framework for action and activity recognition in healthcare-oriented training environments. The proposed architecture combines parameter-efficient modality-specific adaptation with sequential fusion, enabling modalities to be integrated in stages without retraining previously learned components. Rather than assuming a fixed fusion structure, the framework first integrates more closely related modalities and then incorporates additional heterogeneous modalities, supporting scalable adaptation across datasets with different modality sets.We evaluate the framework on two healthcare-oriented training environment datasets: NurViD and the Nurse Training dataset. Across these datasets, preliminary results suggest that the proposed cascaded fusion strategy improves over individual modality models and provides competitive performance relative to previously reported dataset-specific baselines. Overall, these findings indicate that cascaded LoRA-based fusion is a promising parameter-efficient approach for integrating heterogeneous modalities in medical training action and activity recognition tasks. github: https://github.com/anonymous0-ai/LoRA-Based-Cascaded-Multimodal-Fusion-.git.","authors":["Divya Mereddy","Jeevan Beedareddy"],"published":"2026-07-13T17:27:58Z","updated":"2026-07-13T17:27:58Z","abstract_url":"https://arxiv.org/abs/2607.11839v1","html_url":"https://arxiv.org/html/2607.11839v1","pdf_url":"https://arxiv.org/pdf/2607.11839v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":1367,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：This paper presents a cascaded Low-Rank Adaptation (LoRA)-based multimodal fusion framework for action and activity recognition in healthcare-oriented training environments. The proposed architecture combines parameter-efficient modality-specific adaptation w...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"abstract","created_at":"2026-07-14T03:53:25+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11836v1","title":"Cycle-World: Mitigating Error Accumulation in Long-term Video World Models via Reverse-Prediction Cycle Consistency","abstract":"Autoregressive diffusion models have enabled high-quality video generation, yet their sequential nature inherently suffers from error accumulation. In long-horizon video synthesis, minor prediction deviations compound over time, inevitably leading to unconstrained generative drift, structural collapse, and severe visual degradation. To address this, we propose Cycle-World, a novel framework designed for stable and temporally consistent long-video generation. Our approach tackles error drift by enforcing strict temporal reversibility across both the training and inference phases. Theoretically, we demonstrate that forward generative drift can be strictly bottlenecked by a cycle-consistency objective. During training, we integrate an efficient reverse-prediction model to implicitly embed causal constraints into the forward generator, compelling it to produce reversible sequences that tightly adhere to the natural video manifold. At inference time, we repurpose this frozen reverse model as a runtime corrector. Through gradient-based cycle guidance, it iteratively refines the generated latent representations, actively suppressing accumulated errors before they are committed to the historical context. Extensive experiments on the VBench benchmark demonstrate that Cycle-World's dual-phase synergy significantly mitigates error drift, achieving state-of-the-art overall generation quality and long-horizon temporal consistency in 60-second synthesis.","authors":["Zihan Su","Teng Hu","Jiangning Zhang","Ruiyan Wang","Ran Yi","Lizhuang Ma","Dacheng Tao"],"published":"2026-07-13T17:27:13Z","updated":"2026-07-13T17:27:13Z","abstract_url":"https://arxiv.org/abs/2607.11836v1","html_url":"https://arxiv.org/html/2607.11836v1","pdf_url":"https://arxiv.org/pdf/2607.11836v1.pdf","matched_keywords":["video","representation","diffusion"],"source_used":"html","source_text_chars":78154,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, representation, diffusion 相关；摘要显示其主要贡献为：Autoregressive diffusion models have enabled high-quality video generation, yet their sequential nature inherently suffers from error accumulation. In long-horizon video synthesis, minor prediction deviations compound over time, inevitably leading to unconstr...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:25+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11818v1","title":"MM-ToolSandBox: A Unified Framework for Evaluating Visual Tool-Calling Agents","abstract":"We introduce MM-ToolSandBox, a benchmark and evaluation framework for visually grounded tool-calling agents. The framework provides a stateful execution environment spanning 500+ tools across 16 application domains, supporting multi-image, multi-turn tasks where agents must ground progressively arriving visual inputs into executable tool calls while handling realistic conversational phenomena (goal revisions, error corrections, state mutations). An automated scenario generation pipeline produces diverse, visually grounded scenarios through information-flow-guided planning and multi-stage quality filtering, yielding 258 human-verified nominal scenarios and 50 variants targeting interactive UI applications. Evaluating 12 state-of-the-art models, from 4B open-weight to frontier proprietary systems, shows that current models still lack robust visual tool-calling capability: even the best model achieves below 50% success rate. Our failure analysis further reveals that visual precision, not only planning, is a primary bottleneck for capable models: 53% of failures stem from incorrect information extraction from images despite otherwise correct task workflows. A planning-to-precision crossover emerges with scale: smaller models fail at deciding what to do, while larger models fail at perceiving what they see, suggesting fundamentally different research directions for improving models at different capability levels. The framework and the benchmark are publicly available at https://github.com/apple/ml-mmtoolsandbox","authors":["Kaixin Ma","Di Feng","Alexander Metz","Jiarui Lu","Eshan Verma","Afshin Dehghan"],"published":"2026-07-13T17:13:09Z","updated":"2026-07-13T17:13:09Z","abstract_url":"https://arxiv.org/abs/2607.11818v1","html_url":"https://arxiv.org/html/2607.11818v1","pdf_url":"https://arxiv.org/pdf/2607.11818v1.pdf","matched_keywords":["agent"],"source_used":"abstract","source_text_chars":1610,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 agent 相关；摘要显示其主要贡献为：We introduce MM-ToolSandBox, a benchmark and evaluation framework for visually grounded tool-calling agents. The framework provides a stateful execution environment spanning 500+ tools across 16 application domains, supporting multi-image, multi-turn tasks wh...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"abstract","created_at":"2026-07-14T03:53:26+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11798v1","title":"StoryTeller: Training-Free Narrative Grounding for Long-Form Audio Description","abstract":"Long-form audio description (AD) requires more than describing visible actions: it must preserve characters, events, relationships, and story context across scenes so that blind and low-vision (BLV) audiences can follow a film. Modern video-language models (VLMs) are effective on short clips, but they often treat each moment independently, producing descriptions that miss who characters are, why events matter, and how the current scene connects to earlier narrative context. We propose StoryTeller, a training-free framework for story-aware long-form AD. Instead of relying only on local visual cues, StoryTeller maintains a verified narrative memory that carries forward story-relevant information across scenes, enabling later descriptions to remain coherent, grounded, and contextually informative. Given only raw video and a movie title, StoryTeller can optionally retrieve public movie metadata to resolve names and story context, while accepting only facts that are supported by the video through semantic filtering and VLM verification. The method requires no subtitles, scripts, AD transcripts, aligned captions, character banks, precomputed face identities, or task-specific fine-tuning. To evaluate whether generated AD preserves narrative information, we introduce StoryAD-QA, a question-answering benchmark that tests whether a language model can answer story-context questions using only the generated descriptions. Experiments on standard AD benchmarks and diverse long-form videos show that StoryTeller consistently improves narrative coherence, factual grounding, and story comprehension over strong baselines in automatic, QA-based, and human evaluations.","authors":["Seung Hyun Hahm","Minh T. Dinh","SouYoung Jin"],"published":"2026-07-13T16:50:03Z","updated":"2026-07-13T16:50:03Z","abstract_url":"https://arxiv.org/abs/2607.11798v1","html_url":"https://arxiv.org/html/2607.11798v1","pdf_url":"https://arxiv.org/pdf/2607.11798v1.pdf","matched_keywords":["video"],"source_used":"html","source_text_chars":43642,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video 相关；摘要显示其主要贡献为：Long-form audio description (AD) requires more than describing visible actions: it must preserve characters, events, relationships, and story context across scenes so that blind and low-vision (BLV) audiences can follow a film. Modern video-language models (V...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:26+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11754v1","title":"Higher-Order Cell Tracking Transformer","abstract":"Reconstructing lineages from live-imaging microscopy requires linking cell detections across time, including through cell divisions. A common approach is to construct a candidate graph and associate cell segmentations (nodes) across frames. However, these and other existing methods overlook two structural obstacles in candidate tracking graphs: (i) cell divisions entangle distinct lineage paths in the node embedding space, and (ii) edges sharing a node have near-random label agreement, so the candidate-graph topology carries no useful information for graph neural networks to aggregate. We propose the \\textbf{Higher-Order Cell Tracking Transformer} (HOCT), an edge-centric architecture in which candidate cell links attend to one another under a 3D geometric prior, resolving both issues. Evaluated on the Cell Tracking Challenge and a bacteria division benchmark, HOCT achieves state-of-the-art results without deep pre-trained image encoders. Moreover, the proposed approach is easier to fine-tune, quickly reducing tracking errors by 59% with 400 annotations in a human-in-the-loop setting, outperforming LoRA fine-tuning of competing transformer baselines (6.75% improvement).","authors":["Jordão Bragantini","Ilan Theodoro","Loïc A. Royer"],"published":"2026-07-13T16:12:29Z","updated":"2026-07-13T16:12:29Z","abstract_url":"https://arxiv.org/abs/2607.11754v1","html_url":"https://arxiv.org/html/2607.11754v1","pdf_url":"https://arxiv.org/pdf/2607.11754v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":101424,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Reconstructing lineages from live-imaging microscopy requires linking cell detections across time, including through cell divisions. A common approach is to construct a candidate graph and associate cell segmentations (nodes) across frames. However, these and...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:26+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11732v1","title":"GFR-SAM: Training-Free Referring Camouflaged Object Segmentation via Cross-Image Prompting","abstract":"Referring Camouflaged Object Detection (Ref-COD) requires segmenting hidden targets guided by reference cues. While supervised methods are annotation-heavy and training-free approaches via sparse point-prompting are sensitive to localization errors, we propose GFR-SAM, a robust three-stage training-free framework. GFR-SAM shifts the paradigm from fragile point-matching to a \"Generate-Filter-Refine\" pipeline. First, we introduce In-Context Exemplar-guided Segmentation, empowering SAM3 with cross-image inference to generate candidate masks via holistic visual exemplars, bypassing its native intra-image constraints. Second, a Region-Global Contrastive Filtering module ranks candidates through DINOv3-based prototypical alignment, effectively suppressing background distractors. Finally, a Geometric-Semantic Refinement module synergizes bounding box and text prompts to recover fine-grained boundaries and enhance instance recall. Evaluated on the R2C7K benchmark, GFR-SAM outperforms existing training-free methods by 8.7\\% in weighted F-measure ($F_β^w$) and competes with supervised state-of-the-art counterparts. Ultimately, this work underscores the potential of unlocking SAM3's latent capability for cross-image In-Context prompting, establishing a robust, training-free paradigm that effectively bridges the gap between general-purpose foundation models and specialized, label-intensive perception tasks without the need for task-specific fine-tuning.","authors":["Yilong Yang","Jianxin Tian","Shengchuan Zhang","Liujuan Cao"],"published":"2026-07-13T15:55:45Z","updated":"2026-07-13T15:55:45Z","abstract_url":"https://arxiv.org/abs/2607.11732v1","html_url":"https://arxiv.org/html/2607.11732v1","pdf_url":"https://arxiv.org/pdf/2607.11732v1.pdf","matched_keywords":["instance"],"source_used":"html","source_text_chars":55653,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 instance 相关；摘要显示其主要贡献为：Referring Camouflaged Object Detection (Ref-COD) requires segmenting hidden targets guided by reference cues. While supervised methods are annotation-heavy and training-free approaches via sparse point-prompting are sensitive to localization errors, we propos...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:26+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11710v1","title":"SVI360: Spherical Video Interpolation","abstract":"This paper addresses the problem of omnidirectional video interpolation, which plays an essential role in applications such as virtual reality and immersive video enhancement. Existing video interpolation methods are not well-suited for spherical videos, as they have difficulty handling severe distortions close to the poles. To address this issue, we propose SVI360, a dual-branch framework that combines the image frame and its rotated orthogonal view to deal with these distortions. The core methodological aspect of the approach is to reinforce equivariance of the flow displacements between the original and orthogonal views to improve intermediate frame prediction. Experiments show that our method outperforms state-of-the-art approaches in interpolation quality while maintaining accurate optical flow in four different public benchmarks. Code and pre-trained models are available at: https://icb-vision-ai.github.io/video360_interpolation/","authors":["Le-Kim Nguyen","Renato Martins","Pascal Vasseur","Cedric Demonceaux"],"published":"2026-07-13T15:37:52Z","updated":"2026-07-13T15:37:52Z","abstract_url":"https://arxiv.org/abs/2607.11710v1","html_url":"https://arxiv.org/html/2607.11710v1","pdf_url":"https://arxiv.org/pdf/2607.11710v1.pdf","matched_keywords":["video"],"source_used":"html","source_text_chars":53971,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video 相关；摘要显示其主要贡献为：This paper addresses the problem of omnidirectional video interpolation, which plays an essential role in applications such as virtual reality and immersive video enhancement. Existing video interpolation methods are not well-suited for spherical videos, as t...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:26+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11681v1","title":"Illuminant-Adaptive 3D Lookup Tables for Camera Color Correction","abstract":"Color correction is a key component of camera image signal processing (ISP) pipelines, encompassing illuminant discounting and colorimetric mapping of device-dependent sensor responses to device-independent color spaces, such as CIE XYZ. Despite extensive research, accurate color correction remains challenging due to the non-linear relationship between camera sensor responses and CIE XYZ color space, as well as to the increasing presence of highly chromatic and spectrally complex LED illuminants. We propose a color correction framework based on illuminant-adaptive three-dimensional lookup tables (LUTs), which we call Color Correction LUT (C$^2$LUT). Our method combines a chromaticity-aware illuminant representation with a non-linear color transformation, enabling accurate correction under illuminants spanning a wide range of chromaticities and spectral complexities. We employ Tucker tensor decomposition to represent the LUTs, ensuring that computational requirements remain sufficiently low for deployment in camera ISPs. In addition, we introduce a large-scale illuminants dataset comprising 1,473 spectral power distributions, with different chromaticities and spectral profiles. Experiments across multiple cameras, illuminants, reflectance datasets, and real captured images demonstrate consistent improvements over existing methods for color correction, reducing CIE $ΔE_{00}$ by up to 20% and angular error by up to 18% while remaining compatible with modern camera hardware constraints. Code and datasets are available at https://github.com/claudiom4sir/C2LUT.","authors":["Claudio Rota","Luca Cogo","Simone Bianco","Raimondo Schettini"],"published":"2026-07-13T15:19:35Z","updated":"2026-07-13T15:19:35Z","abstract_url":"https://arxiv.org/abs/2607.11681v1","html_url":"https://arxiv.org/html/2607.11681v1","pdf_url":"https://arxiv.org/pdf/2607.11681v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":1647,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation 相关；摘要显示其主要贡献为：Color correction is a key component of camera image signal processing (ISP) pipelines, encompassing illuminant discounting and colorimetric mapping of device-dependent sensor responses to device-independent color spaces, such as CIE XYZ. Despite extensive res...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"abstract","created_at":"2026-07-14T03:53:26+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11673v1","title":"ABot-3DWorld 0: A Universal World Model to Explore Any 3D Space","abstract":"We present ABot-3DWorld 0, a universal multimodal 3D world model that turns text, image, and video inputs into high-fidelity, explorable 3D worlds. At the heart of our framework is a unified Spatial Generative Primitive (SGP), a compact tuple of a high-quality panorama and a spatial point cloud that delivers an efficient description of any 3D space. Multimodal inputs are first lifted into this primitive; a 3D-consistent panoramic video generator then explores the primitive along a planned trajectory; finally, our panoramic video reconstruction engine converts the generated video into a clean, photorealistic 3D Gaussian Splatting (3DGS) world. This pipeline covers two regimes: rich inputs (multi-view sets, casual video) are lifted into the SGP through a geometry-rigorous recovery that mirrors the observed scene, while a single image or sentence is completed generatively into a creative world. The result is one low-barrier engine for general 3D content creation that further anchors generated worlds to geographic points of interest, enabling map-native spatial exploration at consumer scale. Experiments show that ABot-3DWorld 0 sets the state of the art among open-source methods and demonstrates stronger scene fidelity than Marble under rich multimodal inputs.","authors":["Mingchao Sun","Luyang Tang","Yu Liu","Xu Yan","Zhan Li","Yunwei Zhang","Fei Yu","Zengye Ge","Yumin Liu","Jiacheng Zhang","Yongchang Zhang","Jiawei Zhang","Zhicheng Liu","Zhongxu Sun","Tianjian Ouyang","Wenzheng Chen","Shixing Yang","Nianfei Fan","Guodong Sun","Huan Li","Zheng Zhou","Yongze Li","Yingliang Peng","Mengmeng Du","Yuan Liu","Haozhe Shi","Chunnuo Gong","Chengzhen Yu","Chunxue Jia","Yang Liu","Shiying Zeng","Junnan Lai","Hang Zhang","Ning Guo","Baoquan Chen","Mu Xu","Hongyu Pan"],"published":"2026-07-13T15:14:48Z","updated":"2026-07-13T15:14:48Z","abstract_url":"https://arxiv.org/abs/2607.11673v1","html_url":"https://arxiv.org/html/2607.11673v1","pdf_url":"https://arxiv.org/pdf/2607.11673v1.pdf","matched_keywords":["video","3d","multimodal"],"source_used":"abstract","source_text_chars":1341,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, 3d, multimodal 相关；摘要显示其主要贡献为：We present ABot-3DWorld 0, a universal multimodal 3D world model that turns text, image, and video inputs into high-fidelity, explorable 3D worlds. At the heart of our framework is a unified Spatial Generative Primitive (SGP), a compact tuple of a high-qualit...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"abstract","created_at":"2026-07-14T03:53:26+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11655v1","title":"Feature-Space Guided Diffusion for Realistic Ultrasound Image Synthesis","abstract":"Conditional diffusion models can generate anatomically plausible medical ultrasound (US) images, but anatomical plausibility alone does not ensure realistic B-mode appearance. Most US pipelines adapt standard generative architectures and condition them on anatomical masks, or use guidance mechanisms that reinforce the same anatomical signal. However, B-mode US images are shaped by acquisition-dependent properties such as speckle texture, tissue contrast, and attenuation. Using a frozen US foundation model, we show that standard conditional diffusion baselines remain separated from real images in representation space. In this work, we propose Feature-Space Candidate Guidance (FSCG), a training-free sampling strategy to reduce this gap. At sampling time, FSCG applies local k-NN feature correction and selects the best of multiple stochastic candidates according to their feature-space energy. In this way, the mask defines the anatomy, while FSCG steers samples toward the real US domain. Across three different datasets, FSCG reduces average FID64 by 56\\%, FID192 by 57\\%, and nearest-neighbour feature distance by 47\\% over standard conditional diffusion sampling, outperforming alternative inference-time guidance baselines. The results suggest that domain-aware feature representations can reveal and reduce realism gaps in medical diffusion synthesis without retraining the generator. Our code is available at https://github.com/marinadominguez/FSCG.","authors":["Marina Domínguez","Nélida Mirabet-Herranz","Valery Naranjo"],"published":"2026-07-13T15:05:21Z","updated":"2026-07-13T15:05:21Z","abstract_url":"https://arxiv.org/abs/2607.11655v1","html_url":"https://arxiv.org/html/2607.11655v1","pdf_url":"https://arxiv.org/pdf/2607.11655v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"html","source_text_chars":32219,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation, diffusion 相关；摘要显示其主要贡献为：Conditional diffusion models can generate anatomically plausible medical ultrasound (US) images, but anatomical plausibility alone does not ensure realistic B-mode appearance. Most US pipelines adapt standard generative architectures and condition them on ana...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:27+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11644v1","title":"Motion4Motion: Motion Transfer Across Subjects at Inference","abstract":"This work explores the motion transfer from one video to another, which is crucial in animation for diverse characters. Previously, video motion transfer has been largely explored between human and human-like characters, enabling a lot of applications in digital creation. However, these approaches encounter a main limitation. Specifically, related technical pipelines heavily rely on a predefined human skeleton structure and accordingly require skeleton-conditional model training. On the one hand, these methods are difficult to generalize to diverse characters, such as animals from different species, while preserving their unique motion styles. On the other hand, labeled data in diverse skeletons is limited, which additionally restricts the large-scale training for the task. In this paper, we jump out of the skeleton-based motion transfer framework and propose a training-free motion transfer framework, named Motion4Motion. Motion4Motionmodels the motion flow of the character in a video instead of skeletons, which makes motion transfer across species easier. Extensive experimental results and novel applications show our methods outperform baselines impressively. Project page is available at https://lhchen.top/Motion4Motion.","authors":["Ling-Hao Chen","Zixin Yin","Duomin Wang","Xianfang Zeng","Gang Yu"],"published":"2026-07-13T14:58:57Z","updated":"2026-07-13T14:58:57Z","abstract_url":"https://arxiv.org/abs/2607.11644v1","html_url":"https://arxiv.org/html/2607.11644v1","pdf_url":"https://arxiv.org/pdf/2607.11644v1.pdf","matched_keywords":["video"],"source_used":"html","source_text_chars":61310,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video 相关；摘要显示其主要贡献为：This work explores the motion transfer from one video to another, which is crucial in animation for diverse characters. Previously, video motion transfer has been largely explored between human and human-like characters, enabling a lot of applications in digi...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:27+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11588v1","title":"FoundationGeo: Learning Spatial Pixel-Wise Fields for Monocular Metric Geometry","abstract":"We present FoundationGeo, a two-stage framework that explicitly bridges relative and metric prediction via spatial calibration and principled data design. Stage 1 learns a high-fidelity, affine-invariant geometry model by initializing with DINOv3 and training on a curated 10.2M-sample multi-domain corpus with complementary local-detail supervision, yielding sharp boundaries and strong cross-domain generalization. Stage 2 moves beyond global scaling by introducing lightweight pixel-wise calibration fields for metric estimation: a scale field for spatially varying metric alignment and a ray-direction correction field that mitigates directional bias in point-map geometry, together producing metrically consistent 3D point maps. Beyond model design, we identify camera intrinsic coverage, especially focal length distribution mismatch between training and test data, as a key bottleneck for zero-shot metric generalization: performance drops sharply when test intrinsics fall outside the training distribution. To address this, we synthesize additional training data across diverse focal lengths using a Blender-based data engine, repairing under-covered focal regimes and improving robustness under intrinsic shift. Extensive zero-shot evaluations across seven benchmarks show that FoundationGeo significantly strengthens cross-domain robustness, staying near the top across diverse domains while avoiding the sharp cross-domain performance drops observed in other methods. This consistency translates into the best overall performance, surpassing heavier baselines by over 5.2% on average.","authors":["Muxin Liu","Xiaoyang Lyu","Tianhe Ren","Peng Dai","Xiaoshan Wu","Zhiyue Zhang","Jiaqi Zhang","Jiehong Lin","Shaoshuai Shi","Xiaojuan Qi"],"published":"2026-07-13T14:10:01Z","updated":"2026-07-13T14:10:01Z","abstract_url":"https://arxiv.org/abs/2607.11588v1","html_url":"https://arxiv.org/html/2607.11588v1","pdf_url":"https://arxiv.org/pdf/2607.11588v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":79048,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：We present FoundationGeo, a two-stage framework that explicitly bridges relative and metric prediction via spatial calibration and principled data design. Stage 1 learns a high-fidelity, affine-invariant geometry model by initializing with DINOv3 and training...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:27+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11581v1","title":"Actor as Its Own Critic: Unifying Region Understanding and Localization via CycleGRPO","abstract":"This paper introduces Actor as Its Own Critic, a unified reinforcement learning framework, Cycle Group Relative Policy Optimization (CycleGRPO), that jointly optimizes region understanding and localization for Multimodal Large Language Models (MLLMs). Unlike existing separate pipelines, we leverage the inherent duality between the two tasks to construct a self-evaluating reinforcement learning paradigm: \"region $\\to$ text $\\to$ region''. Specifically, a single MLLM first acts as the actor to generate region captions, then immediately transitions to a critic to ground its generated text back in the spatial domain. Therefore, CycleGRPO requires only region inputs, e.g., masks or bounding boxes, entirely bypassing the need for textual ground truths. A quality-aware token-level cycle-consistency reward is employed to assess the semantic discriminability of text captions via their physical localization accuracy. Empirically, built upon SAMTok, our CycleGRPO framework successfully bootstraps both capabilities simultaneously. Without any task-specific fine-tuning, the framework yields consistent performance gains across a wide range of benchmarks, including region captioning, region VQA, grounded dialogue, and referring segmentation. Overall, CycleGRPO offers a straightforward and scalable way to advance pixel-level capabilities in MLLMs. Code and models are released at https://github.com/devinxzhang/CycleGRPO.","authors":["Xin Zhang","Haochen Wang","Yikang Zhou","Jason Li","Robby T. Tan"],"published":"2026-07-13T14:00:57Z","updated":"2026-07-13T14:00:57Z","abstract_url":"https://arxiv.org/abs/2607.11581v1","html_url":"https://arxiv.org/html/2607.11581v1","pdf_url":"https://arxiv.org/pdf/2607.11581v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":60107,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：This paper introduces Actor as Its Own Critic, a unified reinforcement learning framework, Cycle Group Relative Policy Optimization (CycleGRPO), that jointly optimizes region understanding and localization for Multimodal Large Language Models (MLLMs). Unlike...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:27+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11578v1","title":"DiffEEG: A Self-Supervised Denoising Diffusion Model for Learning EEG Generic Representations","abstract":"Deep learning for EEG-based seizure detection faces critical challenges: severe annotation scarcity and extreme class imbalance, where ictal events comprise less than 10\\% of clinical recordings. We present DiffEEG, a 9.6M-parameter self-supervised foundation model that addresses both limitations through denoising diffusion pre-training and reinforcement learning (RL)-based fine-tuning. Pre-trained on 1.3M unlabeled segments from the Temple University Hospital Seizure Corpus (TUHSZ), DiffEEG learns generic neural representations via a 1D U-Net with multi-head self-attention. For downstream adaptation, a reinforced decision layer employs policy gradient optimization to directly maximize F1-score, prioritizing sensitivity to rare seizure events over overall accuracy. Under strict patient-wise evaluation (279 patients, Leave-One-Fold-Out), DiffEEG achieves 61\\% accuracy and 59\\% F1 for 4-class seizure subtyping, and 81\\% accuracy with 85\\% weighted F1 for binary detection, maintaining clinically viable seizure recall (59\\%) despite extreme imbalance (6.7\\% prevalence). Segment-level evaluation establishes an upper bound of 97.6\\% accuracy, confirming strong architectural capacity. DiffEEG demonstrates that diffusion-based pre-training combined with metric-aware reinforcement learning enables clinically deployable seizure monitoring with minimal labeled data requirements.","authors":["Abdulkader Helwan","Lina Abou-Abbas","Hussein El Amouri","Belkacem Chikhaoui","Khadidja Henni"],"published":"2026-07-13T13:59:45Z","updated":"2026-07-13T13:59:45Z","abstract_url":"https://arxiv.org/abs/2607.11578v1","html_url":"https://arxiv.org/html/2607.11578v1","pdf_url":"https://arxiv.org/pdf/2607.11578v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"html","source_text_chars":66723,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation, diffusion 相关；摘要显示其主要贡献为：Deep learning for EEG-based seizure detection faces critical challenges: severe annotation scarcity and extreme class imbalance, where ictal events comprise less than 10\\% of clinical recordings. We present DiffEEG, a 9.6M-parameter self-supervised foundation...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:27+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11562v1","title":"MonkeyOCRv2: A Visual-Text Foundation Model for Document AI","abstract":"Mainstream visual encoders are pretrained on natural images and cannot be effectively applied to document images without document-oriented adaptation, as dense text and fine-grained character strokes demand character-level visual perception. We present MonkeyOCRv2, a visual-text pretrained model for document AI. First, we construct MonkeyDoc v2, to our knowledge the largest document-image pretraining corpus, comprising 113 million images spanning 17 languages. Second, we propose a pretraining strategy that jointly learns image-to-text generation and pixel-level document reconstruction: the former aligns visual representations with textual content, while the latter preserves character strokes and layout details. Extensive experiments are conducted on five representative document analysis tasks, including text recognition, formula recognition, text detection, document tampering detection, and overlapping text segmentation. Replacing the original encoders with MonkeyOCRv2 consistently improves performance across all five tasks. Finally, we validate its effectiveness as the vision encoder of multimodal large language models on the more challenging tasks of document parsing and document understanding. Kept frozen and paired with a lightweight language model, it yields a 0.7B document parsing model that sets a new open-source state-of-the-art on MDPBench, a recent benchmark spanning digital-born and photographed documents across 17 languages, surpassing the previous best 3B dots.mocr by 2.8% absolute with a vision encoder roughly 11$\\times$ smaller. The frozen encoder also powers a document understanding model that outperforms counterparts built on CLIP, DINO, and SAM across eight benchmarks under identical training settings. These results suggest that document-oriented visual pretraining can serve as a foundation for document intelligence in its own right.","authors":["Yuliang Liu","Zhang Li","Ziyang Zhang","Shuo Zhang","Qiang Liu","Jiajun Song","Zidun Guo","Xinhan Wang","Handong Zheng","Yang Liu","Dongliang Luo","Zhiyin Ma","Jiarui Zhang","Xiang Bai"],"published":"2026-07-13T13:43:39Z","updated":"2026-07-13T13:43:39Z","abstract_url":"https://arxiv.org/abs/2607.11562v1","html_url":"https://arxiv.org/html/2607.11562v1","pdf_url":"https://arxiv.org/pdf/2607.11562v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"html","source_text_chars":124148,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation, multimodal 相关；摘要显示其主要贡献为：Mainstream visual encoders are pretrained on natural images and cannot be effectively applied to document images without document-oriented adaptation, as dense text and fine-grained character strokes demand character-level visual perception. We present Monkey...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:27+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11560v1","title":"Technical Report on the CVPR 2026@AdvML Workshop Challenge","abstract":"Vision-language agents (VLAs) are increasingly used to interpret complex driving scenes and support safety-critical reasoning. This report presents the CVPR 2026@AdvML Workshop Challenge on adversarial multimodal attacks against autonomous-driving VLAs. Built on DriveLM-style multi-view visual question answering, the challenge represents each scene with six synchronized camera images and a structured collection of driving-related question-answer pairs. Participants generate adversarial images and suffix-only textual perturbations that induce model responses to deviate from reference answers while preserving image fidelity and limiting textual cost. The competition comprises two phases, with Phase II adding a hidden black-box model to assess transferability. We describe the task design, submission rules, evaluation protocol, and leaderboard results, and then examine five leading submissions for which technical reports were available. Across these reports, several recurring patterns emerge: image-side attacks are favored by the suffix penalty; scene-level, multi-view optimization is more effective than treating views in isolation; QA types and graph structure provide useful priors for allocating attack budget; feature-space objectives can improve black-box transfer; and typographic content embedded in camera images exposes a persistent vulnerability in driving VLAs. These findings provide a practical reference for future robustness evaluation and defense design in multimodal autonomous-driving systems.","authors":["Tianyuan Zhang","Zonglei Jing","Jiangfan Liu","Ligong Zhang","Ke Ma","Chengzhi Sun","Xiaohai Xu","Zhirui Zhang","Qianqian Xu","Qingming Huang","Hanyu Fang","Junhua Liu","Zheng Wang","Xiaoliang Liu","Yuanbo Li","Shuai Gui","Bin Wang","Menghe Zheng","Jing Nie","Hanyang Meng","Zeyang Zhang","Xiang Zhang","Yongxuan Zhu","Rui Ding","Hainan Li","Yongkang Zhang","Zhilei Zhu","Xianglong Kong","Jin Hu","Zonghao Ying","Yisong Xiao","Lei Chen","Haotong Qin","Jiakai Wang","Aishan Liu","Ruikai Li","Julia Karbing","Yinpeng Dong","Zhenfei Yin","Shao Jing","Xia Hu","Jingyi Xu","Juntao Dai","Xinyun Chen","Vishal M. Patel","Xianglong Liu","Dawn Song","Alan Yuille","Philip H. S. Torr","Dacheng Tao"],"published":"2026-07-13T13:42:48Z","updated":"2026-07-13T13:42:48Z","abstract_url":"https://arxiv.org/abs/2607.11560v1","html_url":"https://arxiv.org/html/2607.11560v1","pdf_url":"https://arxiv.org/pdf/2607.11560v1.pdf","matched_keywords":["agent","multimodal"],"source_used":"html","source_text_chars":107204,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 agent, multimodal 相关；摘要显示其主要贡献为：Vision-language agents (VLAs) are increasingly used to interpret complex driving scenes and support safety-critical reasoning. This report presents the CVPR 2026@AdvML Workshop Challenge on adversarial multimodal attacks against autonomous-driving VLAs. Built...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:27+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11548v1","title":"Training-Free Off-Screen Player Imputation for Broadcast-Based Spatial Football Analytics","abstract":"Spatial football metrics such as pitch control assume access to the positions of all 22 players, yet the most widely available source of positional data -- the broadcast main camera -- shows only 10-16 of them at any moment. We quantify the resulting distortion with an open, reproducible benchmark: a simulated broadcast viewport applied to open full-pitch tracking data (Metrica Sports; three matches, one held out from method development). Ignoring off-screen players -- the visible-only baseline implied whenever a video-based game-state-reconstruction (GSR) pipeline adds no imputation layer -- inflates hidden-zone pitch-control error to 25.1-26.9 percentage points and a mean absolute control-share error of 11.1-13.4 points across the three matches. We then evaluate a ladder of training-free, online imputation baselines that use only observations from the match being analysed. The best overall on these decision-relevant metrics, role-anchored centroid voting (each visible player votes for the full-team centroid by subtracting its running role offset, attenuating the viewport-induced subset bias), roughly halves hidden-zone error (to 12.2-13.8 points) and cuts control-share error to 28-48% of the ignore policy at every viewport width from 36 m to 60 m in all three matches. For occlusions <=9.6 s -- the regime of the closest learned prior work -- it reaches binwise median position errors of 3.3-8.9 m; but 50-57% of hidden-player observations lie beyond that regime. Integrated end-to-end into a broadcast-video GSR pipeline, imputation moves a downstream possession-quality score (Space-Creation Index) by 15.6 and 17.2 points on two real World Cup broadcast windows, flipping the verdict class in one.","authors":["Seongjin Choi"],"published":"2026-07-13T13:33:45Z","updated":"2026-07-13T13:33:45Z","abstract_url":"https://arxiv.org/abs/2607.11548v1","html_url":"https://arxiv.org/html/2607.11548v1","pdf_url":"https://arxiv.org/pdf/2607.11548v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11533v1","title":"Adaptive Routing for Efficient Diffusion Transformer-Based PNI Prediction","abstract":"Perineural invasion (PNI) is a critical prognostic factor in cholangiocarcinoma. However, its preoperative prediction from magnetic resonance imaging (MRI) remains challenging due to subtle imaging features that extend beyond tumor boundaries into surrounding regions. Conventional convolutional neural networks are limited in capturing long-range spatial dependencies. Transformer-based architectures improve global modeling of volumetric MRI by aggregating spatially distributed contextual cues, yet capturing subtle and noise-sensitive patterns in peritumoral regions remains challenging. Diffusion-based classifiers offer an alternative formulation by leveraging denoising-based class scoring to better capture such subtle patterns. However, these approaches introduce substantial computational overhead due to the combination of transformer-based modeling and iterative denoising processes. To address these challenges, we formulate PNI prediction as a diffusion-based classification problem and implement the denoising network using a transformer-based representation. To improve computational efficiency, we introduce adaptive routing across attention heads, spatial tokens, and MLP width. Experimental results demonstrate that the proposed approach achieves an AUC of 0.731 with 257.57 GFLOPs.","authors":["Youngung Han","Dohyun Kweon","Kyeonghun Kim","Hyunsu Go","Jina Jeong","Suah Park","Induk Um","Junga Kim","Anna Jung","Yului Jeong","Sungha Park","Jinyong Jun","Pa Hong","Woo Kyoung Jeong","Won Jae Lee","Ken Ying-Kai Liao","Hyuk-Jae Lee","Nam-Joon Kim"],"published":"2026-07-13T13:18:21Z","updated":"2026-07-13T13:18:21Z","abstract_url":"https://arxiv.org/abs/2607.11533v1","html_url":"https://arxiv.org/html/2607.11533v1","pdf_url":"https://arxiv.org/pdf/2607.11533v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11523v1","title":"Vinci2: Providing Proactive Assistance in Continuous Egocentric Videos","abstract":"When should an intelligent assistant speak up without being asked? Continuous egocentric video offers rich, evolving context that enables a new form of assistance: one that is proactive rather than merely reactive. Yet existing approaches either wait passively for user queries or treat every detected event as requiring a response, without considering the user's history, current activity, or whether assistance would actually be welcome. We reframe proactive assistance as a context-dependent decision problem: the agent must not only perceive what is happening, but reason over accumulated temporal context to determine when and whether to intervene. To this end, we present Vinci2, a proactive egocentric assistance system that advances the on-device assistant Vinci from reactive response toward proactivity. On the evaluation side, we present EgoServe, the first large-scale benchmark for proactive assistance in continuous egocentric video. EgoServe comprises over 3,000 service instances organized along 4 temporal memory horizons, ranging from immediate safety alerts to long-term habit coaching, across 10 service categories. On the modeling side, we propose EgoMemo, a training-free, memory-augmented agent that maintains three complementary memory representations: multi-scale temporal summaries, a semantic knowledge graph, and visual embedding archives. At each timestep, EgoMemo performs retrieval-augmented reasoning to determine whether assistance is warranted and, if so, produces contextually grounded responses. Experiments demonstrate that EgoMemo establishes strong baselines on EgoServe while remaining competitive on existing egocentric benchmarks. Our benchmark and code are publicly available at \\href{https://sitonggong.github.io/EgoServe-page/}{Vinci2}.","authors":["Gong Sitong","Tianyu Yan","Caixin Kang","Bo Zheng","Xiang Ruan","Huchuan Lu","Kaipeng Zhang","Yoichi Sato","Yifei Huang"],"published":"2026-07-13T13:09:45Z","updated":"2026-07-13T13:09:45Z","abstract_url":"https://arxiv.org/abs/2607.11523v1","html_url":"https://arxiv.org/html/2607.11523v1","pdf_url":"https://arxiv.org/pdf/2607.11523v1.pdf","matched_keywords":["video","retrieval","agent","representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11509v1","title":"CFR-Net:Collaborative Feature Refnement Network for Medical Image Anomaly Detection","abstract":"Medical image anomaly detection remains challenging because networks pretrained on natural images often exhibit limited adaptability to medical images, where abnormal patterns appear as fine-grained local shifts, multi-scale contextual mismatches, and orientation-sensitive structural deviations. To address this, we propose the Collaborative Feature Refinement Network (CFR-Net), which combines shared teacher-student feature refinement before decoding with cross-space consistency after decoding. CFR-Net refines frozen teacher features and trainable student features using a Multi-Path Feature Refinement Module (MPFRM) with shared parameters, imposing common multi-path refinement rules on generic visual references and representations adapted to the medical domain, thereby mitigating domain discrepancy while modeling local, multi-scale, and orientation-sensitive feature characteristics. A variance-sensitive objective and dynamic ``homework set'' reorganization further support layer-adaptive consistency learning. Experiments on medical benchmarks show that CFR-Net achieves competitive anomaly classification and strong anomaly localization performance when trained on normal data.","authors":["Zihan Nie","Muhao Xu","Wei Feng","Yuan Cui","Hua Wei","Sijie Niu","Yi Wan","Xunbin Wei","Weiye Song","Zongyuan Ge"],"published":"2026-07-13T12:59:21Z","updated":"2026-07-13T12:59:21Z","abstract_url":"https://arxiv.org/abs/2607.11509v1","html_url":"https://arxiv.org/html/2607.11509v1","pdf_url":"https://arxiv.org/pdf/2607.11509v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11500v1","title":"HyperGS: Fast and Generalizable Gaussian Video Representation","abstract":"Gaussian Splatting has emerged as an effective representation for video, but existing methods rely on per-video optimization. This leads to slow encoding and limits generalization across videos. To amortize this optimization, we propose HyperGS, a feedforward, optimization-free approach that directly predicts Gaussian representations from any video in a single forward pass, speeding up encoding and decoding by orders of magnitude while generalizing to out-of-distribution videos at higher resolutions. In HyperGS, we design a factorized spatiotemporal Transformer to extract tokens from video, and a learnable query-based Transformer to obtain 8-parameter Gaussian representations for each video frame. We find that naively predicting Gaussians across diverse videos induces a needle-like degeneration that collapses training, and address this with a rank-based geometric regularizer whose strength adapts dynamically to stabilize optimization. HyperGS achieves encoding at $10^4$--$10^5\\times$ the speed of per-video Gaussian optimization at matched reconstruction quality while generalizing zero-shot to $720p$ video, enabling higher-resolution rendering without re-encoding. HyperGS improves PSNR by +2.9--3.1 dB over the prior video encoders on K400, SSv2, and UCF101 at a smaller video representation size. By predicting explicit 2D Gaussians in a single forward pass, HyperGS combines the fast, flexible rendering of Gaussian Splatting with the speed and generalization of feedforward prediction, advancing Gaussians as a practical direction for fast and generalizable video representation.","authors":["Fatimah Zohra","Chen Zhao","Shuming Liu","Yahya Al Malallah","Bernard Ghanem"],"published":"2026-07-13T12:53:02Z","updated":"2026-07-13T12:53:02Z","abstract_url":"https://arxiv.org/abs/2607.11500v1","html_url":"https://arxiv.org/html/2607.11500v1","pdf_url":"https://arxiv.org/pdf/2607.11500v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11487v1","title":"LightMem-Ego: Your AI Memory for Everyday Life","abstract":"Personal AI assistants on mobile and wearable devices continuously perceive users' daily lives through visual and audio streams. However, answering queries about past experiences requires lightweight multimodal memory that can continuously accumulate, organize, and retrieve long-term experiences, which remains challenging. To address this challenge, we present LightMem-Ego, a lightweight streaming multimodal memory system for everyday-life assistance. The system continuously captures egocentric visual and audio streams, aligns them on a shared timeline, and organizes them into a hierarchical memory consisting of current, short-term, and long-term memory. Given a user query, LightMem-Ego dynamically routes retrieval to the appropriate memory level and generates answers grounded in multimodal evidence. The demonstration can be deployed on smartphones and AI glasses, supporting object finding, conversation recall, life summarization, routine discovery, and personalized assistance. Code is available at https://github.com/zjunlp/LightMem-Ego.","authors":["Yijun Chen","Boyi Xiao","Yixian Zhao","Haoting Xia","Buqiang Xu","Jizhan Fang","Yanya Li","Yaqi Zheng","Xuehai Wang","Zirui Xue","Liuxin Zhang","Hui Li","Ningyu Zhang"],"published":"2026-07-13T12:40:17Z","updated":"2026-07-13T12:40:17Z","abstract_url":"https://arxiv.org/abs/2607.11487v1","html_url":"https://arxiv.org/html/2607.11487v1","pdf_url":"https://arxiv.org/pdf/2607.11487v1.pdf","matched_keywords":["retrieval","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11434v1","title":"Direct Image-to-Modern Vietnamese Translation of Han-Nom Manuscripts via Multimodal RLHF Preference Alignment","abstract":"Translating Han-Nom manuscripts into modern Vietnamese is challenging because historical pages are often degraded, the script contains rare logographic characters, and parallel supervision is limited. We propose a multimodal RLHF preference-alignment framework that conditions Vietnamese generation on manuscript images and aligned Han-Nom source text. The model combines four streams: CLIP ViT-L/14@336 for visual features, bert-base-chinese for Han-Nom representations, vinai/phobert-base for Vietnamese representations, and T5-small encoder states. Modality-specific projections and a fusion block compress the resulting 2,048-dimensional concatenation into a shared 512-dimensional representation. Starting from the same supervised fine-tuned policy, we compare PPO, DPO, and KTO under matched work-level macro-averaged evaluation. DPO achieves the best BLEU-4, ROUGE-L, BERTScore, semantic similarity, CER, WER, and token accuracy, whereas PPO obtains the highest precision, recall, and F1. KTO remains competitive through its desirable-undesirable utility objective. All preference-aligned policies improve the BLEU-4 and semantic-similarity scores available for the SFT baseline. These results indicate that multimodal preference optimization complements supervised learning by improving lexical and semantic quality in low-resource historical translation.","authors":["Thi Kim Trang Vo","Nghia Hieu Nguyen","Ha Minh Tan"],"published":"2026-07-13T11:40:45Z","updated":"2026-07-13T11:40:45Z","abstract_url":"https://arxiv.org/abs/2607.11434v1","html_url":"https://arxiv.org/html/2607.11434v1","pdf_url":"https://arxiv.org/pdf/2607.11434v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11419v1","title":"Video Transformer for Remote Identity Document Hologram Detection","abstract":"Remote identity authentification using Identification Documents has been a major challenge for several years. DeepFakes advent and the development of AI-guided tools helps fraudsters creating counterfeit ID Documents. Ensuring the authenticity of ID Documents has become a real clue in the seurization of remote authentification. This need is all the more pressing given the increasing digitization of administrative and transactional processes. To ensure widespread accessibility, the system should rely solely on video captured via mobile devices. In this specific context, confirming the authenticity of ID is a real challenge as many security features needs specific device like infrared sensor for instance. Among underutilized but promising security features, holographic printings hold a special place. Difficult to counterfeit, they produce distinctive visual effects according enlightment, making them both detectable in a video captured by a smartphone camera and difficult to imitate. In this paper, we propose a Remote Identity Document Verification System (RIDVS) and an approach based on a video transformer for detecting holograms in simple videos captured by smartphones. Our system is designed for a smartphone-based capture process, followed by a server-side verification. The hologram detection method builds on a robust model previously validated in a related research domain. We demonstrate that it outperforms existing SotA methods, achieving near-perfect accuracy even when trained on medium- to small-sized datasets. In particular, we report improvements of +26.86\\% in Recall and +17.93\\% in accuracy over the best MIDV-Holo baseline. This study includes several experiments that evaluate the model adaptation to frugality, both for training samples and computational resources.","authors":["Joris Voerman","Nicolas Sidere","Jean-Christophe Burie"],"published":"2026-07-13T11:24:54Z","updated":"2026-07-13T11:24:54Z","abstract_url":"https://arxiv.org/abs/2607.11419v1","html_url":"https://arxiv.org/html/2607.11419v1","pdf_url":"https://arxiv.org/pdf/2607.11419v1.pdf","matched_keywords":["video","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11385v1","title":"Diffusion MRI preprocessing affects ADC estimation and automatic PI-RADS v2.1 classification in bi-parametric prostate MRI","abstract":"Diffusion-weighted imaging (DWI) is acquired as part of bi-parametric prostate MRI, but suffers from artifacts that degrade downstream quantitative and diagnostic performance. While DWI preprocessing is standard in brain imaging, its adoption in prostate imaging remains limited and lacks standardized pipelines. This study investigated the effect of different DWI preprocessing strategies on apparent diffusion coefficient (ADC) estimation and automatic Prostate Imaging Reporting and Data System (PI-RADS) classification. 268 cases were derived from the fastMRI prostate cohort by sequentially applying denoising, Gibbs-ringing correction, and diffeomorphic registration for susceptibility distortion correction. ADC maps were compared using linear least squares (LLS) and iteratively-weighted LLS (IWLLS). A 3-class DenseNet classifier was trained to predict PI-RADS scores from multi-channel MRI inputs. ADC analysis revealed statistically significant differences across preprocessing pipelines, with LLS and IWLLS producing numerically equivalent maps. Linear relationships between ADC values were preserved across most datasets (PCC ~0.99), while distortion correction realigned DWI to T2w anatomy and altered ADC values accordingly (PCC ~0.90). Classification showed the best AUROC and sensitivity for high-risk PI-RADS classes in the fully processed dataset. False-negative analysis revealed this dataset produced the least overconfident incorrect predictions on high-risk classes, which is a desirable property for clinical triage. DWI preprocessing, particularly distortion correction, enhances both ADC map quality and the predictive power of deep learning models for PI-RADS classification, supporting the need for optimized preprocessing pipelines in prostate MRI.","authors":["Christos Kanakis","Mathias Perslev","Tim Schakel","Silvia Ingala","Akshay Pai","Dennis Klomp","Chantal M. W. Tax"],"published":"2026-07-13T10:45:13Z","updated":"2026-07-13T10:45:13Z","abstract_url":"https://arxiv.org/abs/2607.11385v1","html_url":"https://arxiv.org/html/2607.11385v1","pdf_url":"https://arxiv.org/pdf/2607.11385v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11341v1","title":"The In-Car Sign Language Corpus (ICSL): A Multi-Modal Resource for Constrained-Space Sign Language Recognition","abstract":"This paper addresses the challenges of using sign language within shared mobility services, such as taxis, carpools, or ride-sharing platforms. The use of sign language recognition (SLR) in real-world, confined environments, specifically vehicle interiors remains largely unexplored. To motivate research in this area, we present the In-Car Sign Language (ICSL) dataset for Brazilian Sign Language (Libras), with the long-term goal of improving public transport accessibility for the Deaf and Hard-of-Hearing community. The dataset consists of: (1) high-precision laboratory motion capture (MoCap) data to establish an idealized linguistic baseline and (2) real-world multi-modal in-car recordings captured using a 2D camera and 3D Time-of-Flight sensors. The dataset provides a basis for comparative analyses between synthesized signing avatar animations and recorded real signing interpreter videos, which enable future research into robust \"in-the-wild\" SLR models and domain adaptation. We describe in detail the use cases, the setup, the data collection protocol, and the metadata structure of the corpus. In total, we recorded a multimodal dataset exceeding 1.5 million frames, comprising the synchronized multimodal streams described above featuring Libras users across various in-car scenarios. The corpus is provided with gloss annotation of lexical signs and non-lexical sign language elements specially designed to support the training and evaluation of deep neural networks for constrained space recognition. In-vehicle signing offers a technically significant example of a constrained, occluded, and non-frontal environment. While recognizing the diverse communication strategies already employed by the Deaf community, identifying automotive-specific limitations provides a useful stepping stone for research into enhancing in-car accessibility and passenger quality of life.","authors":["Raviteja Boddu","Guilherme Vieira Leite","Joed Lopes da Silva","Ângelo Benetti","Isabela Barbieri","Natália de Melo Afonso","Thyago Santos","Helio Pedrini","Felipe Venâncio Barbosa","José Mario De Martino","Munir Georges","Alessandro Zimmer"],"published":"2026-07-13T10:03:46Z","updated":"2026-07-13T10:03:46Z","abstract_url":"https://arxiv.org/abs/2607.11341v1","html_url":"https://arxiv.org/html/2607.11341v1","pdf_url":"https://arxiv.org/pdf/2607.11341v1.pdf","matched_keywords":["video","3d","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11312v1","title":"SLVMBench: Skill Learning from Video Memory","abstract":"We introduce Skill Learning from Video Memory (SLVMBench), the first benchmark that jointly evaluates whether video large language models (video-LLMs) can learn skills from long video memory and apply them to real-time tasks. SLVMBench presents models with 2-3 hour video streams that contain a tutorial video embedded in a stream of arbitrary irrelevant videos, resembling real-world human learning practices. Video-LLMs are asked to apply the acquired skill to answer real-time questions about an ongoing video. Unlike long-video understanding benchmarks that emphasize passive comprehension and skill-learning benchmarks that rely on short, immediate demonstrations, SLVMBench tests the full pipeline of memorizing and extracting procedural knowledge, as well as transferring it to real-time tasks. Moreover, rigorous human annotations feature sub-second-level temporal calibration, manually engineered questions eliminating common-sense guessing, and collated tutorials to ensure coverage of the required skills. Evaluations on state-of-the-art proprietary and open-source video LLMs show that video-LLMs struggle substantially with learning and applying skill knowledge from videos. Moreover, performance degrades markedly when the skill knowledge is placed within a long video memory. These results reveal a key limitation of existing video LLMs and position SLVMBench as the first benchmark for studying real-time skill acquisition and application from long-context video memory.","authors":["Yudong Yang","Guangzhi Sun","Yixuan Li","Chao Zhang"],"published":"2026-07-13T09:26:13Z","updated":"2026-07-13T09:26:13Z","abstract_url":"https://arxiv.org/abs/2607.11312v1","html_url":"https://arxiv.org/html/2607.11312v1","pdf_url":"https://arxiv.org/pdf/2607.11312v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11295v1","title":"Metadata Supervised MRI Representations for Modelling and Controlling Acquisition Variability","abstract":"Magnetic resonance imaging exhibits substantial acquisition variability, where identical anatomy can appear markedly different across scanners and imaging protocols. Consequently, learned representations entangle biological structure with acquisition-dependent appearance, limiting interpretability, generalisation, and clinical deployment. We show that these sources of variation can be separated by jointly modelling MRI images and DICOM metadata. Using large-scale clinical brain MRI data, we learn representations that separate anatomical structure from contrast-dependent appearance. Resulting contrast representations organise heterogeneous acquisitions, support sequence understanding, and detect image--metadata inconsistencies, whereas anatomical representations suppress acquisition-specific variation while preserving biologically relevant information. Building on these disentangled representations, we introduce a unified anatomy-preserving harmonisation model for cross-modality and cross-site adaptation, conditioned on image or acquisition metadata. Our findings suggest that acquisition variability is a structured component of the imaging process that can be modelled, audited, and controlled, providing a foundation for acquisition-aware representation learning in large-scale medical imaging.","authors":["Mehmet Yigit Avci","Pedro Borges","Virginia Fernandez","Natalia Glazman","Paul Wright","Mehmet Yigitsoy","Sebastien Ourselin","Jorge Cardoso"],"published":"2026-07-13T09:12:23Z","updated":"2026-07-13T09:12:23Z","abstract_url":"https://arxiv.org/abs/2607.11295v1","html_url":"https://arxiv.org/html/2607.11295v1","pdf_url":"https://arxiv.org/pdf/2607.11295v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11285v1","title":"SalientGS: Unified SfM-to-3DGS with Importance-Guided MCMC Gaussian Allocation","abstract":"Reconstructing 3D scenes from unordered images remains bottlenecked by expensive Structure-from-Motion (SfM) preprocessing and frozen pose interfaces. We present SalientGS, a unified SfM-to-3D Gaussian Splatting (3DGS) pipeline. Its central contribution is importance-guided Markov Chain Monte Carlo (MCMC) Gaussian allocation, which aggregates multi-view residuals into per-Gaussian underfit and redundancy signals. These signals define a smooth importance-weighted sampling distribution that biases both birth and relocation toward underfit regions. This reallocates capacity from well-fit areas without altering the underlying stochastic gradient Langevin dynamics (SGLD). SalientGS achieves end-to-end reconstruction in 15 minutes with state-of-the-art perceptual quality. The supplementary material provides dedicated sections for Per-Scene Qualitative Comparisons and Per-Image Learned Perceptual Image Patch Similarity (LPIPS) Analysis, including failure cases. Code and evaluation scripts are available at https://github.com/Six-Bit-TX/SalientGS.","authors":["Tianyu Xiong","Rui Li","Suning Ge","Jiaqi Yang"],"published":"2026-07-13T09:06:49Z","updated":"2026-07-13T09:06:49Z","abstract_url":"https://arxiv.org/abs/2607.11285v1","html_url":"https://arxiv.org/html/2607.11285v1","pdf_url":"https://arxiv.org/pdf/2607.11285v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11281v1","title":"The Devil Is in the Leakage: A Disentangled Dual-Purification Framework for High-Fidelity Hairstyle Transfer","abstract":"Hairstyle transfer aims to synthesize a photorealistic portrait by transplanting the hairstyle from a reference image onto a source subject while preserving the source identity. Recent foundation models show strong generative capability, but they struggle with the zero-shot disentanglement required for precise local editing, often entangling the reference hairstyle with its original identity and pose. Existing diffusion-based pipelines typically decompose the task by first generating a \"bald\" image from the source and then injecting hairstyle features from the reference. However, we show that this paradigm suffers from a fundamental leakage problem. Identity Leakage in Hairstyle occurs when hairstyle features retain reference identity or pose information, while Flaw Leakage in Bald arises when residual artifacts in the bald image are propagated into the final synthesis. To address both issues, we propose the Dual-Purification Framework (DPF), which introduces two complementary training-time regularizers. Adversarial Hairstyle Purification (AHP) purifies hairstyle features by suppressing identity predictability under a mutual-information-inspired adversarial objective. Contrastive Geometric Purification (CGP) regularizes the ControlNet pathway with a contrastive objective, reducing the model's reliance on geometric artifacts in the bald condition. By jointly purifying the hairstyle representation and geometric pathway, DPF achieves high-fidelity, identity-preserving hairstyle transfer and state-of-the-art performance on diverse benchmarks.","authors":["Jijie Li","Jiankuo Zhao","Xiangyu Zhu","Zhen Lei"],"published":"2026-07-13T09:00:42Z","updated":"2026-07-13T09:00:42Z","abstract_url":"https://arxiv.org/abs/2607.11281v1","html_url":"https://arxiv.org/html/2607.11281v1","pdf_url":"https://arxiv.org/pdf/2607.11281v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11257v1","title":"LaGuadia: Language-Guided Adaptive Distillation from Pathology Foundation Models","abstract":"Pathology Foundation Models (PFMs) offer powerful Whole Slide Image (WSI) representations but suffer from massive computational costs. While Knowledge Distillation (KD) can create efficient student models, existing multi-teacher methods often use suboptimal uniform weighting that ignores tissue heterogeneity. We propose LaGuadia (Language-Guided Adaptive DistillAtion), a framework that develops a compact pathology image encoder by dynamically integrating expertise from multiple PFMs under clinical linguistic guidance. Our approach utilizes a multi-stage pipeline: first, extracting visually observable clinical keywords from pathology reports; second, aligning visual features with these keywords via a Vision-Language meta-teacher (MedSigLIP) to provide dense semantic guidance; and finally, performing adaptive KD where teacher contributions are weighted based on their semantic alignment with the clinical narrative. Experiments on WSI captioning, visual question answering, and slide-level classification tasks demonstrate that an 87M parameter LaGuadia student model matches or exceeds foundation-scale models such as GigaPath and UNI, achieving strong factual consistency and robust generalization. These results highlight clinical language as an effective semantic anchor for building efficient and reliable digital pathology systems. Code is available at https://github.com/hvcl/LaGuadia.","authors":["Gangsu Kim","Won-Ki Jeong"],"published":"2026-07-13T08:38:21Z","updated":"2026-07-13T08:38:21Z","abstract_url":"https://arxiv.org/abs/2607.11257v1","html_url":"https://arxiv.org/html/2607.11257v1","pdf_url":"https://arxiv.org/pdf/2607.11257v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11233v1","title":"Structure-Detail Decoupled Autoregressive Generation for Fast and High-Fidelity Virtual Try-On","abstract":"Virtual try-on (VTON) is a bi-conditional image generation problem that requires not only accurate person preservation but also faithful garment deformation and detail synthesis. Diffusion-based VTON methods can jointly model these factors in a compressed latent space, but suffer from high-frequency detail loss due to inherent latent compression, even with costly multi-step denoising. Recent visual autoregressive (VAR) models offer a promising alternative for high-quality generation with faster inference, yet remain unexplored for VTON due to the lack of effective bi-conditioning mechanisms. To bridge this gap, we first introduce VAR-VTON, a VAR-based VTON model that incorporates garment conditioning and structural guidance for efficient latent-space VTON. Despite its efficacy, latent-space generation still struggles to preserve fine-grained garment details. We argue that different VTON sub-tasks should be addressed in different representation spaces: structural synthesis such as garment warping and person layout is suited to the latent space, whereas fine-grained detail recovery should be tackled in the pixel space. Motivated by this insight, we further propose STAR-VTON, a Two-Stage AutoRegressive framework that builds upon VAR-VTON by decoupling latent-space structural synthesis from pixel-space detail recovery. Our idea is to resort to a matching-informed refiner to establish dense correspondences between the stage-one generation and the source garment to directly map fine-grained pixel-space details. Extensive experiments show that STAR-VTON achieves an impressive efficiency-fidelity trade-off: VAR-VTON runs at least $4\\times$ faster than diffusion-based counterparts without degrading quality, and the pixel-space refiner effectively restores fine details and acts as a plug-and-play module that can benefit existing VTON approaches.","authors":["Lu Yang","Xiaonan Hu","Yanan Li","Daqi Liu","Xiang Bai","Hao Lu"],"published":"2026-07-13T08:21:43Z","updated":"2026-07-13T08:21:43Z","abstract_url":"https://arxiv.org/abs/2607.11233v1","html_url":"https://arxiv.org/html/2607.11233v1","pdf_url":"https://arxiv.org/pdf/2607.11233v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11221v1","title":"HandFlow: Fully Generative 4D Hand Recovery with Flow Matching","abstract":"Accurate monocular 4D hand reconstruction remains challenging. Per-frame discriminative regressors lack temporal context and often produce jittery predictions. Temporal models improve consistency by aggregating information across frames, but they are typically deterministic regressors, making them vulnerable to ambiguous observations caused by occlusion and motion blur. Generative modeling offers a natural alternative by learning a prior over plausible hand motion sequences, enabling coherent hand-state recovery when visual evidence is incomplete or unreliable. Motivated by this observation, we present HandFlow, a fully generative flow-matching framework for temporally coherent 3D hand pose and shape estimation from monocular video. Given visual and skeletal observations, HandFlow denoises an entire temporal window of MANO parameters through a single ODE integration. To support this, we use a Flux-style dual-stream transformer that attends across the full sequence to capture long-range dependencies without autoregressive decoding, and a confidence-aware continuous masking mechanism that blends observed features with learnable mask tokens to handle noisy or missing observations. Experiments on DexYCB and HOT3D show that HandFlow achieves state-of-the-art performance, with particularly large gains in world-space accuracy and temporal smoothness. It reduces world-space pose error by over 30% compared with the strongest baseline and achieves the lowest acceleration error among all evaluated methods, while remaining competitive in per-frame pose accuracy. Moreover, on a single GPU HandFlow reconstructs a 150-frame sequence at 47 fps, about 12x faster than the fastest prior video-based method, with reconstruction itself accounting for only a small fraction of the end-to-end latency.","authors":["Mingxi Xu","Bowen Duan","Yi Gu","Zhengyang Shen","Renjing Xu","Yutao Yue"],"published":"2026-07-13T08:13:42Z","updated":"2026-07-13T08:13:42Z","abstract_url":"https://arxiv.org/abs/2607.11221v1","html_url":"https://arxiv.org/html/2607.11221v1","pdf_url":"https://arxiv.org/pdf/2607.11221v1.pdf","matched_keywords":["video","3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11199v1","title":"DynEval: Holistic Evaluations of T2I Generative Models in the Wild","abstract":"Recent advances in text-to-image (T2I) generation have led to models capable of producing highly realistic images. Yet, reliably evaluating their outputs remains challenging, especially at scale. Existing automatic evaluators, often relying on a static prompt set, struggle to capture subtle failure modes such as partial prompt misalignment, compositional errors, or visually plausible but semantically incorrect generations. In this work, we introduce DynEval, a Dynamic Evaluation framework designed to jointly assess text-to-image alignment and image quality of T2I models. To support scalable training beyond limited human-annotated data, we construct two large datasets. First, we build GenDB, a collection of 500K prompt-image pairs generated from human-written prompts drawn from DiffusionDB using a tiered prompt-model generation strategy. Second, building upon GenDB, we construct DynEvalInstruct, a 250K instruction dataset comprising prompt-image-response triplets distilled from a structured evaluation pipeline that decomposes evaluation into text-image alignment and visual quality reasoning. Using this dataset, we perform full fine-tuning of a compact evaluator through a curriculum learning strategy to effectively distill the superior evaluation capabilities of a larger teacher vision-language model, resulting in DynEval-2B and DynEval-4B. In extensive comparisons against existing evaluators across 11 benchmarks, our evaluator achieves a higher overall correlation with human judgments. Furthermore, it provides fine-grained analysis of the capabilities and failure modes of 36 T2I models across 42 subcategories and 9 semantic dimensions.","authors":["Shyam Marjit","Dheeraj Baiju","Anuj Shikarkhane","Akhil Sakthieswaran","Sayak Paul","Anirban Chakraborty"],"published":"2026-07-13T07:50:54Z","updated":"2026-07-13T07:50:54Z","abstract_url":"https://arxiv.org/abs/2607.11199v1","html_url":"https://arxiv.org/html/2607.11199v1","pdf_url":"https://arxiv.org/pdf/2607.11199v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11196v1","title":"Slot-RAE: Streamlining Object-Centric Learning via Direct Representation Auto-Encoders","abstract":"Deploying object-centric models for real-world scene understanding typically requires complex pipelines to achieve both robust scene decomposition and high-fidelity generation. Recent diffusion-based approaches have improved visual quality, but they almost universally rely on heavy, pretrained generative priors (e.g., Stable Diffusion) and external VAE latent spaces. In this paper, we propose Slot-RAE, a much simpler, fully integrated framework that operates directly within the continuous semantic feature space of visual foundation models (e.g., DINOv3). Slot-RAE employs a feature-space diffusion process using a Diffusion Transformer (DiT) decoder and a Representation Alignment (REPA) head. Unlike existing diffusion-based objectcentric methods that rely heavily on subsidized text-toimage priors, the generative core of Slot-RAE (Slot Attention and the DiT) is trained from scratch within the frozen VFM feature space. This eliminates the need for VAE bottlenecks and task-agnostic generative pre-training. Experiments on the COCO dataset demonstrate that despite its architectural simplicity, Slot-RAE achieves state-of-the-art results. It delivers comparable unsupervised object discovery, higher-fidelity image reconstruction, and robust zero-shot compositionality, all while being significantly faster and more computationally efficient than existing object-centric latent diffusion models.","authors":["Alexandre Chapin","Emmanuel Dellandrea","Liming Chen"],"published":"2026-07-13T07:47:09Z","updated":"2026-07-13T07:47:09Z","abstract_url":"https://arxiv.org/abs/2607.11196v1","html_url":"https://arxiv.org/html/2607.11196v1","pdf_url":"https://arxiv.org/pdf/2607.11196v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11192v1","title":"GDP.pdf: Benchmarking Grounded Multimodal Reasoning over Professional PDF Documents","abstract":"A large share of day-to-day work in professional domains happens inside PDF files: benefits packets, leases, datasheets, clinical guidelines, construction plans. Benchmarks for document AI have generally measured the required capabilities in isolation: OCR, layout analysis, chart reasoning, table QA, document VQA. A high score on any one of them does not necessarily reveal whether a model can answer a realistic question that someone in the field would actually ask about a specific PDF. GDP.pdf is a benchmark built to measure this directly. It consists of question-document pairs authored by working professionals in ten fields, and a candidate question was kept only when at least two frontier multimodal models failed it in a way that mattered: a wrong answer, missed decisive evidence, or a fabricated claim, rather than a superficial difference such as style. Each item comes with a rubric of atomic criteria, so we can report a graded rubric score as well as a strict task-level pass rate, and each item is tagged against a taxonomy of eleven capabilities in three tiers, spanning text extraction and grounding, table and chart comprehension, cross-referencing, spatial reasoning, and abstention on unsupported queries. We evaluated seven frontier models on the 100-item benchmark. The best model passed only 15% of the items and the worst passed 1%. Most errors trace back to a small set of recurring loss patterns: misaligned tables, misread charts, skipped footnotes and exclusions, miscounted floor-plan symbols, scan noise, and amendments that supersede earlier text. The full 100-item benchmark is publicly available at https://huggingface.co/datasets/surgeai/GDP.pdf","authors":["Suhaas Garre","Emily Ritchie","Sushant Mehta","Edwin Chen"],"published":"2026-07-13T07:44:07Z","updated":"2026-07-13T07:44:07Z","abstract_url":"https://arxiv.org/abs/2607.11192v1","html_url":"https://arxiv.org/html/2607.11192v1","pdf_url":"https://arxiv.org/pdf/2607.11192v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11173v1","title":"When Depth Is Better Told Than Shown: Depth-Ordinal Prompting for Vision-Language Spatial Reasoning","abstract":"Vision-language models (VLMs) are expected to reason about physical space -- which object is closer, what lies behind what, and how objects are arranged in 3D -- yet they still struggle with such spatial judgments. A natural remedy is to show the model a depth map, but we find that this can make performance worse. We show that depth is not absent: it reaches the language model, but becomes difficult to access for downstream reasoning, while rendered pseudo-depth maps act as noisy auxiliary images that frozen VLMs cannot easily regulate. We propose Depth-Ordinal Prompting (DOP), a training-free method that converts monocular depth into a single question-targeted ordinal text cue at the queried objects, without adding a depth image, training a module, injecting features, or using labels. Our key finding is form dependence: the same depth signal can hurt when shown as an image but help when told as text.Across benchmarks, models, and depth estimators, DOP improves spatial reasoning when pseudo-depth provides reliable object-level ordering and remains largely neutral in strong original-image regimes. It is also competitive with the strongest training-free depth-prompting alternative while being simpler and more targeted.","authors":["Quynh Vo","Phuc Dao","Cong-Duy Nguyen","Thong Nguyen"],"published":"2026-07-13T07:13:01Z","updated":"2026-07-13T07:13:01Z","abstract_url":"https://arxiv.org/abs/2607.11173v1","html_url":"https://arxiv.org/html/2607.11173v1","pdf_url":"https://arxiv.org/pdf/2607.11173v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11170v1","title":"TC-MAF: Train-Calibrated Bounded Multi-Evidence Fusion for Multimodal Industrial Anomaly Detection","abstract":"Multimodal anomaly detection benefits from complementary RGB and 3D evidence, yet auxiliary RGB reconstruction is not equally reliable across product categories and class-wise test-time policy selection is usually unavailable. We propose TC-MAF, a base-anchored multi-evidence fusion design that combines a multimodal detector, complementary Dinomaly evidence, and a small cross-modal consistency cue under one fixed pixel-level fusion formula. A lightweight training-dispersion confidence (TDC) term scales auxiliary participation using only normal training statistics. On MVTec-3D, TC-MAF reaches 0.979 image-level AUROC and 0.990 pixel-level AUPRO, achieving the best mean results on both detection and localization among the compared multimodal methods. Systematic ablations show that the fusion structure itself is the dominant factor, while TDC provides a smaller but reproducible calibration gain over no calibration or arbitrary calibration. Additional experiments show that the same design remains effective under a pooled-statistics variant, auxiliary-branch and backbone substitutions, few-shot settings, a missing-3D setting, and cross-dataset evaluation on Eyecandies. Code is available at https://anonymous.4open.science/r/TC_MAF-C3BB.","authors":["Ming Deng","Sijin Sun","Xiaochuan Hu","Xing Wu"],"published":"2026-07-13T07:07:54Z","updated":"2026-07-13T07:07:54Z","abstract_url":"https://arxiv.org/abs/2607.11170v1","html_url":"https://arxiv.org/html/2607.11170v1","pdf_url":"https://arxiv.org/pdf/2607.11170v1.pdf","matched_keywords":["3d","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11168v1","title":"SISA-Rec: A Semantically Integrated Sequential Recommender with Contrastive Alignment","abstract":"Recommendation systems help users recommend relevant items from a large collection of choices. Present work on transformer-based sequential recommendation learns user preferences from interaction logs, but it mostly focuses on item identifiers and doesn't fully use the semantic meaning of items. This limitation becomes a major challenge in sparse and cold-start scenarios where historical interaction data is limited. To solve this problem, we introduce SISA-Rec (Semantically Integrated Sequential Recommendation), a transformer-based framework that embeds semantic context directly into sequential modeling. Our approach fuses item ID embeddings with BERT-based text embeddings via a gated fusion module, injects semantic similarity into the self-attention mechanism, and leverages an attention-based aggregation module to construct comprehensive user representations. Finally, a joint learning objective which combines Bayesian Personalized Ranking (BPR) and contrastive alignment loss, aligns the underlying behavioral and semantic spaces. Experiments were conducted on the two highly sparse Amazon Beauty and Amazon Toys \\& Games datasets, both having 99.93\\% sparsity. The results show that SISA-Rec outperforms state-of-the-art baseline models across all evaluation metrics. Compared with the BERT4Rec \\cite{petrov2022systematic}, SISA-Rec improves HR@10 by 16.6\\% and NDCG@10 by 10.3\\% on Amazon Beauty, and HR@10 by 23.1\\% and NDCG@10 by 17.9\\% on Amazon Toys \\& Games. Cold-start analysis further shows that the proposed model achieves the largest improvements for users with limited interaction historical records. This showcases the value of semantic information when user behavior data is scarce. Overall, the results demonstrate that integrating semantic information into the attention mechanism leads to more accurate and reliable recommendations.","authors":["Soohan Abbasi","Shahid Munir Shah","Rafia Shaikh","Mahmoud Aljawarneh"],"published":"2026-07-13T07:03:51Z","updated":"2026-07-13T07:03:51Z","abstract_url":"https://arxiv.org/abs/2607.11168v1","html_url":"https://arxiv.org/html/2607.11168v1","pdf_url":"https://arxiv.org/pdf/2607.11168v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11120v1","title":"Simple Features and Honest Calibration for Ambivalence and Hesitancy Recognition in Video","abstract":"We address ambivalence and hesitancy (A/H) recognition in the ABAW 2026 BAH Challenge: given a short interview video, predict whether the person shows signs of A/H. Our system combines affect-specialised text, audio, and visual representations with a small set of readable linguistic hesitation cues, fused by a reliability gate we call Affective Marker Fusion (AMF), and finished with a simple AP-weighted ensemble at a fixed decision threshold. We also introduce \\emph{ASR-erased time}: speech recognisers delete fillers and hesitation pauses from the transcript, but the chunk timestamps keep the time those events took, and sixteen features built from these gaps form the strongest and most independent non-verbal channel we measured (AP $0.718$, correlation $0.11$--$0.36$ with all other members). Across controlled experiments we find three things: cross-modal conflict design does not reliably help on BAH; language is by far the strongest channel while affect-specialised audio is a useful second; and calibration matters more than architecture. Fitting ensemble weights and a threshold on the small validation split overfits: it scores $0.741$ macro-F1 on validation but only $0.690$ on the untouched test set. AP-weighting at a fixed threshold instead reaches $\\mathbf{0.731}$ on test.","authors":["Vikas Kumar","Aditya Mishra","Haroon R. Lone"],"published":"2026-07-13T05:52:40Z","updated":"2026-07-13T05:52:40Z","abstract_url":"https://arxiv.org/abs/2607.11120v1","html_url":"https://arxiv.org/html/2607.11120v1","pdf_url":"https://arxiv.org/pdf/2607.11120v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11118v1","title":"GHOST: Geometry-Guided Hallucination of Opaque Surface Textures","abstract":"Transparent objects pose a fundamental challenge for depth estimation and 3D reconstruction due to their violation of Lambertian assumptions, leading to severe geometry degradation in downstream tasks. To address this, we propose a novel geometry-guided preprocessing framework \\textbf{GHOST} that leverages visual foundation models to transform transparent regions into opaque, structurally consistent representations without requiring downstream model retraining. Specifically, our pipeline utilizes (1) \\textbf{TransDINO} and (2) \\textbf{TransDecomp} to disentangle masks and transparency physical properties, while (3) \\textbf{DAF-Net} recovers surface normal priors to encode geometric curvature. Subsequently, (4) \\textbf{GeoSemTransNet} integrates these multi-modal cues to synthesize a texture-rich opaque RGB image that preserves the transparent object's 3D structure. Extensive experiments demonstrate that our method significantly enhances the accuracy of state-of-the-art depth estimation and reconstruction models on transparent objects by restoring essential photometric cues.","authors":["Langxu Zhao","Zuan Gu","Tianhan Gao"],"published":"2026-07-13T05:50:19Z","updated":"2026-07-13T05:50:19Z","abstract_url":"https://arxiv.org/abs/2607.11118v1","html_url":"https://arxiv.org/html/2607.11118v1","pdf_url":"https://arxiv.org/pdf/2607.11118v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11106v1","title":"Beyond the Eye: Efficient Multimodal Reasoning via Self-Regulated Implicit Visual Tools","abstract":"Recent multimodal large language models (MLLMs) have made remarkable progress on fine-grained perception tasks under the \"Thinking with Images\" (TwI) paradigm by iteratively performing various visual tool operations. However, this paradigm relies heavily on frequent external tool calls and repeated image re-encoding, which leads to substantial computational overhead and inference latency. To address these issues, we propose Beyond the Eye (BEE), a novel implicit visual tool paradigm centered on self-regulated capability. BEE directly incorporates visual tool invocation behaviors into the training objective and encourages the model to develop a self-regulated invocation mechanism. This design enables the model to adaptively balance internal knowledge and implicit tools, avoiding redundant tool usage while substantially reducing inference latency. Specifically, BEE involves a two-stage training process: (1) Formalized Chain-of-Thought (CoT) Supervised Fine-tuning (SFT). We construct CoT trajectories with structured tool slots and mixed invocation states. This stage activates the model's implicit tool representations and adaptive switching capability. (2) Self-regulated Reward-Driven Alignment. To address redundant tool usage caused by ambiguous cognitive boundaries, we first introduce the Net Tool Gain (NTG) metric to quantify this phenomenon. Based on this observation, we further propose a self-regulated reward mechanism. This mechanism penalizes ineffective tool dependency and encourages the model to perform knowledge routing, ensuring that implicit tools are invoked only when the model's internal knowledge is insufficient. BEE achieves state-of-the-art performance in fine-grained visual perception while remaining competitive in general reasoning tasks and achieving substantial gains in inference efficiency.","authors":["Xiuwei Chen","Quanlin Chen","Wentao Hu","Zisheng Chen","Kun Xiang","Zehua Ma","Mingyang Zhang","Jianhua Han","Hanhui Li","Hang Xu","Xiaodan Liang"],"published":"2026-07-13T05:32:00Z","updated":"2026-07-13T05:32:00Z","abstract_url":"https://arxiv.org/abs/2607.11106v1","html_url":"https://arxiv.org/html/2607.11106v1","pdf_url":"https://arxiv.org/pdf/2607.11106v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11099v1","title":"Desc++: Efficient Descriptor Enhancement for Data Association in Existing Visual SLAM Systems","abstract":"Reliable visual data association is fundamental to visual SLAM (V-SLAM), as it directly determines the quality of the camera pose estimation and map consistency. However, the handcrafted descriptors used by most mature real-time systems degrade under illumination and viewpoint changes, while learning-based front-ends that address this weakness typically require replacing the extraction-and-matching pipeline and introduce substantial computational overhead. Descriptor enhancement offers a compromise by refining existing descriptors within their original format, yet current methods rely on simplified attention mechanisms whose limited contextual modeling constrains the achievable matching quality. To resolve this trade-off between contextual expressiveness and efficiency, we propose Desc++, a lightweight enhancement module that jointly encodes descriptor representations and keypoint geometry and aggregates spatial context through a hybrid architecture that combines order-agnostic global attention with geometry-aware sequential modeling in linear time. The enhanced descriptors retain their original dimensionality and matching interface, enabling integration into deployed V-SLAM systems without modifying the pipeline. Experiments across descriptor matching, correspondence analysis, and system-level benchmarks with four different V-SLAM systems demonstrate that Desc++ improves matching accuracy over the state-of-the-art enhancement method, translates these gains into more accurate and stable trajectory estimation, and achieves a favorable balance between accuracy and efficiency for practical integration into existing real-time V-SLAM pipelines.","authors":["Ting-Wei Ou","Huang-Ting Lin","Kuu-Young Young"],"published":"2026-07-13T05:15:13Z","updated":"2026-07-13T05:15:13Z","abstract_url":"https://arxiv.org/abs/2607.11099v1","html_url":"https://arxiv.org/html/2607.11099v1","pdf_url":"https://arxiv.org/pdf/2607.11099v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11097v1","title":"Revisiting Matching Response and Swept Feature Volumes for Wide-baseline Omnidirectional Stereo","abstract":"In this paper, we propose a training strategy for confidence estimation in omnidirectional stereo, targeting the ambiguous matches that frequently occur in wide-baseline setups. Reinterpreting the matching responses produced by the 3D encoder decoder block, we show that their expectation values provide intrinsic confidence signals. Building on this, our method directly penalizes ambiguous responses without auxiliary heads, multi-pass inference, or additional modules, resulting in more efficient and generalized predictions. Beyond confidence, we introduce swept feature volume resampling, where response features produced by 3D CNNs are resampled using regressed positive matching indices and then processed by 2D CNNs to predict meta-information such as surface normals. This joint learning introduces auxiliary geometric regularization and improves depth coherence by leveraging additional contextual cues during response aggregation stage. Experimental results demonstrate that our approach enhances both confidence estimation and surface normal prediction while maintaining deployment practicality for autonomous mobility applications.","authors":["Seungjin Jeon","Jongwoo Lim","Changhee Won"],"published":"2026-07-13T05:09:06Z","updated":"2026-07-13T05:09:06Z","abstract_url":"https://arxiv.org/abs/2607.11097v1","html_url":"https://arxiv.org/html/2607.11097v1","pdf_url":"https://arxiv.org/pdf/2607.11097v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11096v1","title":"Difference-Driven Gating: Adaptive Feature Fusion for U-Net Decoder","abstract":"The U-Net style models have been widely used in many applications. A critical step in these models is to reconstruct the lower-level features using a top-down decoder. This reconstruction requires precise fusion of high-level semantics and low-level details. Existing attention-based fusion methods typically derive attention weights from the top-down decoder features (global) alone or the correlation between the top-down decoder features and the bottom-up encoder features (local), then modulate the encoder features using these weights. In this work, we explore a different paradigm: deriving attention weights from the difference between the two feature streams. To this end, we propose two difference-based gating approaches: Feature-difference gating (FDG), which directly uses the absolute difference between global and local features to generate adaptive gating maps, and Entropy-difference gating (EDG), which measures the representational certainty of each stream via information entropy and uses their signed entropy difference to derive the attention weights. Both methods produce coupled gating maps that simultaneously modulate the global and local features. Experiments on different tasks including medical image segmentation, remote sensing image cloud removal and speech separation showed that both methods outperformed existing attention-based fusion methods, and EDG performed better. The results suggested a new paradigm for multi-scale feature fusion in the U-Net style structures.","authors":["Kai Li","Xuechao Zou","Jiashen Fu","Zijun Yan","Xintong Wang","Xiaolin Hu"],"published":"2026-07-13T05:06:35Z","updated":"2026-07-13T05:06:35Z","abstract_url":"https://arxiv.org/abs/2607.11096v1","html_url":"https://arxiv.org/html/2607.11096v1","pdf_url":"https://arxiv.org/pdf/2607.11096v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11081v1","title":"Controlling Motion Transfer in Diffusion Transformers via Attention Heads","abstract":"Diffusion Transformers (DiTs) have advanced video generation with high-quality, temporally coherent results. However, extending them to motion transfer, which requires following reference motion while aligning with a target prompt, remains challenging due to limited understanding of motion and structure representations within DiTs. We analyze video DiTs at the attention-head level and identify distinct heads specialized for motion and spatial structure. Based on this insight, we propose a head-aware controllable motion transfer framework that requires no parameter updates. Our method refines motion cues from motion-specialized heads via semantic correspondence guidance and preserves structure through selective feature injection. This head-level control not only enables accurate motion transfer but also provides an interpretable foundation for controllable video generation with DiTs.","authors":["Sunyoung Jung","Jiwoo Park","Yoonseok Choi","Kyobin Choo","Ming-Hsuan Yang","Seong Jae Hwang"],"published":"2026-07-13T04:44:14Z","updated":"2026-07-13T04:44:14Z","abstract_url":"https://arxiv.org/abs/2607.11081v1","html_url":"https://arxiv.org/html/2607.11081v1","pdf_url":"https://arxiv.org/pdf/2607.11081v1.pdf","matched_keywords":["video","representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11078v1","title":"Do Video-LLMs Actually Watch? Diagnosing Character-Tracking Failures in Long-Form Video","abstract":"Can a Video Large Language Model (Video-LLM) follow one person through a long video, keeping track of who they are well enough to report, in order, how their outfit changes across a full TV episode? Benchmarks increasingly score this kind of task, and the strongest open-source 7--8B models now reach 37--38% on InfiniBench's global appearance task, which asks exactly that. But does that score come from tracking the named character, or from something easier? We test this with a nine-condition diagnostic protocol applied to three architecturally distinct open-source Video-LLMs, with Gemini~2.5~Flash as a frontier reference, and find the accuracy does not come from character tracking. When we change the character named in the question to a different cast member, leaving the video and answer options untouched, the models change their answer only 4--31% of the time, so they are largely ignoring who the question asks about. Breaking that test down by the gender of the swapped name shows why: the models react more when the name is changed to a different-gender character than to a same-gender one (a 13--28 point gap), picking up coarse gender cues but unable to tell same-gender individuals apart. This shallow processing surfaces again when we drop the multiple-choice options and ask the same questions open-endedly: open-source accuracy drops 18--25 points, with none of 151 answers fully correct, versus a 12-point drop for Gemini. Further checks rule out the obvious innocent explanations, adding subtitles, using the most informative frames, or doubling the number of frames all leave character tracking unimproved, so the bottleneck is not how much video the model sees but how it ties that video to the person the question names. We release a diagnostic toolkit for auditing what such benchmark scores actually measure.","authors":["Mohammad Al-Ratrout","Shayla Sharmin","Aditya Raikwar","Roghayeh Leila Barmaki"],"published":"2026-07-13T04:37:07Z","updated":"2026-07-13T04:37:07Z","abstract_url":"https://arxiv.org/abs/2607.11078v1","html_url":"https://arxiv.org/html/2607.11078v1","pdf_url":"https://arxiv.org/pdf/2607.11078v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11071v1","title":"DDR-Net: Haze-Aware Dual-Domain Refinement for Single-Image Dehazing","abstract":"Single-image dehazing aims to recover clear scenes from haze-degraded images. It remains challenging due to the atmospheric scattering and the complexity of real-world haze distributions. Although recent end-to-end networks have achieved promising performance, two issues still limit their effectiveness: insufficient feature refinement at the bottleneck stage and weak local structural representation in encoder-decoder architectures. Thus, we propose a Haze-Aware Dual-Domain Refinement Network (DDR-Net) for single-image dehazing. Our method is built upon three modules: Haze Prior Extractor (HPE) provides multi-scale haze-aware priors by operating directly on downsampled hazy images; Detail-Enhanced Blocks (DE Blocks) serve as the core feature extraction units, capturing multi-scale structural information and enhancing edge and texture recovery via gradient-aware convolutions; and Spatial-Frequency Bottleneck Refinement (SFBR) at the bottleneck jointly exploits spatial and frequency information to refine bottleneck features. DDR-Net achieves more effective feature representation and reconstruction for haze removal. Extensive experiments on real-world benchmarks demonstrate that our method outperforms existing dehazing approaches. It achieves competitive performance on synthetic datasets.","authors":["Xinye Zheng","Ye Yu","Qiang Lu","Jinsheng Luo","Yiran Cui","Yongbin Cheng"],"published":"2026-07-13T04:20:22Z","updated":"2026-07-13T04:20:22Z","abstract_url":"https://arxiv.org/abs/2607.11071v1","html_url":"https://arxiv.org/html/2607.11071v1","pdf_url":"https://arxiv.org/pdf/2607.11071v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11064v1","title":"WiFi-JEPA: Self-supervised Learning for WiFi-CSI 3D Human Pose Estimation","abstract":"WiFi Channel State Information (CSI) enables privacy-preserving human pose sensing in camera-denied environments, but existing WiFi-based pose estimators often fail under environment shifts and rely on costly camera-based annotation pipelines that limit scale. We propose WiFi-JEPA, a self-supervised framework that learns CSI-native representations by predicting masked latent embeddings instead of reconstructing raw CSI signals that may contain hardware-specific artifacts. WiFi-JEPA makes three contributions: (i) CSI-specific tokenization and link masking tailored to the CSI tensor over channel, time, and link (C,T,L); masking entire Tx-Rx antenna links forces the model to predict one spatial link view from others, capturing cross-link correlations informative of 3D spatial structure. (ii) A ray-tracing CSI simulation pipeline that generates diverse unlabeled CSI from randomized geometric primitives, providing scalable pre-training data without pose annotations. (iii) State-of-the-art results on Person-in-WiFi-3D: WiFi-JEPA outperforms prior WiFi-CSI baselines on both single- and multi-person 3D pose estimation under the same evaluation protocol. We also show that simulated CSI provides complementary pre-training signal to real CSI, and that four vision-native SSL objectives degrade performance below training from scratch, whereas WiFi-JEPA consistently improves downstream pose estimation.","authors":["Doeon Kim","Jungyoon Lee","Seongsin Kim","Seong-heum Kim"],"published":"2026-07-13T04:05:07Z","updated":"2026-07-13T04:05:07Z","abstract_url":"https://arxiv.org/abs/2607.11064v1","html_url":"https://arxiv.org/html/2607.11064v1","pdf_url":"https://arxiv.org/pdf/2607.11064v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11040v1","title":"FSFVE: Few Shot Compressed Face Video Enhancement","abstract":"Videocalling has become a popular form of communication in the world today, with many companies providing free services for it. However, there are still millions of people around the world that experience poor quality videocalls due to limitations in bandwidth. This despite, most people having the required hardware. In this paper we present a novel framework for enhancing highly compressed videocalls. We show, that with as little as 10 frames of the face, we can rapidly (in under 100 seconds) train a model to enhance that instance of the videocall. The model can be trained either prior to or during the call, enhancing the rest of the call by producing better quality video. The video conferencing application need not be modified - it can be off the shelf with our system as a layer on top that trains quickly then simply lets the video conferencing application (e.g. Zoom) run as usual, where our system intercepts and improves images before they are displayed. The model is designed to run in realtime on low-compute devices such as a typical laptop CPU. Experimentally, we show that the model significantly improves quality of compressed face video both quantitatively as well as perceptually. Code can be found at https://github.com/varun-jois/FSFVE.","authors":["Varun Ramesh Jois","Antonella DiLillo","James Storer"],"published":"2026-07-13T03:12:07Z","updated":"2026-07-13T03:12:07Z","abstract_url":"https://arxiv.org/abs/2607.11040v1","html_url":"https://arxiv.org/html/2607.11040v1","pdf_url":"https://arxiv.org/pdf/2607.11040v1.pdf","matched_keywords":["video","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11034v1","title":"RTFVE: Realtime Face Video Enhancement","abstract":"There's been a surge in adoption of video conferencing applications for both personal and business use cases. However, the bandwidth limitations faced by many users worldwide may restrict the optimal use of such applications. Although deep learning offers a solution for enhancing low bit rate videos, most models today are either hard to incorporate with modern compression standards or require specialized hardware to run such as significant GPUs making these models impractical. To address these issues, we introduce the Realtime Face Video Enhancement (RTFVE) model which can be easily incorporated with any video decoder and can run in realtime on ordinary CPUs. Experiments show that our model improves perceptual quality over the compressed video baseline at multiple low bitrate settings. The source code will be made available at https://github.com/varun-jois/RTFVE.","authors":["Varun Ramesh Jois","Antonella DiLillo","James Storer"],"published":"2026-07-13T02:58:44Z","updated":"2026-07-13T02:58:44Z","abstract_url":"https://arxiv.org/abs/2607.11034v1","html_url":"https://arxiv.org/html/2607.11034v1","pdf_url":"https://arxiv.org/pdf/2607.11034v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11029v1","title":"Learning to Navigate Efficiently with Only 0.58M Trainable Parameters","abstract":"Recent progress in visual navigation has largely been driven by scale: end-to-end policies with hundreds of millions of parameters trained on billions of frames or large-scale simulated data. We ask how much of this scale a single task family actually requires, and what structure can substitute for it. We propose a decomposed navigation model in which operations with known closed-form structure, such as projective geometry, occupancy, and coordinate transforms, are computed analytically and serve as interfaces between three small learned modules: an egress predictor that grounds the episode goal as a local subgoal in the current view, a navigation predictor that estimates a goal-conditioned posterior over where trajectories travel, and an endpoint-pinned residual diffusion generator that samples trajectory shapes from this posterior. The system trains only 0.58M out of a total of 22.7M parameters, on 44k frames in under one GPU-hour, yet approaches the performance of state-of-the-art models on navigation tasks across 6060 point-goal episodes and 60 environments, while having 233x fewer trainable parameters, the lowest collision rate among all evaluated methods, and 50 Hz inference speed. The decomposition further transfers to no-goal exploration by retraining only the 123k-parameter egress head, and its failure modes under sensor corruption are transparent and analytically correctable.","authors":["Edward Beng Wai Tan","Siew-Kei Lam"],"published":"2026-07-13T02:49:55Z","updated":"2026-07-13T02:49:55Z","abstract_url":"https://arxiv.org/abs/2607.11029v1","html_url":"https://arxiv.org/html/2607.11029v1","pdf_url":"https://arxiv.org/pdf/2607.11029v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.10998v1","title":"Temporal Feature Distillation for Label-Efficient Precise Event Spotting in Sports Videos","abstract":"Precise Event Spotting (PES) requires distinguishing visually similar yet semantically distinct adjacent frames, making it fundamentally different from image classification and coarse action recognition. Although self-distillation methods such as DINO have shown strong representation learning ability in images, we find that directly applying them to PES is ineffective: without supervised guidance, subtle but crucial motion cues are often suppressed as noise, leading to representations that are insensitive to precise event boundaries. To address this, we propose Temporal Feature Distillation, a semi-supervised objective that aligns temporally informative backbone features, rather than projection-head outputs, to preserve motion-sensitive and boundary-aware cues for frame-level localization. A supervised warm-up with a ramp-up schedule further stabilizes training by ensuring that meaningful event cues are learned before unlabeled distillation begins. We also introduce Transformer Gate Shift, a multi-scale gated shifting module that injects motion-aware temporal information into Vision Transformers. Experiments on four fine-grained sports benchmarks show consistent improvements over fully supervised and semi-supervised baselines. Under 10\\% supervision on FSPerf, our method improves mAP by 4.54 points over the strongest competing approach, and with only 80\\% labeled data, it matches or surpasses the fully supervised 100\\% baseline on two of the four datasets.","authors":["Hao Xu","Xinyu Wei","Sam Wells","Sunil Aryal"],"published":"2026-07-13T01:53:46Z","updated":"2026-07-13T01:53:46Z","abstract_url":"https://arxiv.org/abs/2607.10998v1","html_url":"https://arxiv.org/html/2607.10998v1","pdf_url":"https://arxiv.org/pdf/2607.10998v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.10995v1","title":"AsySplat: Efficient Asymmetric 3D Gaussian Splatting for Long-Sequence Scene Modeling","abstract":"Recent generalizable 3D Gaussian Splatting models have advanced long-sequence novel view synthesis (NVS), but at the cost of substantial redundant computation. We identify that the redundancy can be mitigated based on two observations: (i) high-precision geometry is not strictly required for high-quality NVS; (ii) appearance learning is generally easier than geometry recovery. Motivated by these insights, we propose an asymmetric architecture that decouples geometry and appearance modeling. The geometry branch processes coarse-grained tokens with most of the parameters for multi-view reconstruction, while the appearance branch operates on fine-grained tokens to capture details using significantly fewer parameters. The two branches interact through bilateral connections, enabling mutual guidance for their respective tasks. This task-aware asymmetry reduces the computational redundancy and allocates the computation more judiciously, thereby increasing parameter efficiency and enabling smaller models to achieve strong performance. On 32-view 960P inputs, our model matches optimization-based methods while delivering nearly 800x speedup, and surpasses the zero-shot performance of state-of-the-art generalizable models with markedly fewer parameters and reduced training/inference overhead, achieving an overall efficiency improvement.","authors":["Yingji Zhong","Dave Zhenyu Chen","Fuzhao Ou","Youyu Chen","Zhihao Li","Lanqing Hong","Dan Xu"],"published":"2026-07-13T01:39:19Z","updated":"2026-07-13T01:39:19Z","abstract_url":"https://arxiv.org/abs/2607.10995v1","html_url":"https://arxiv.org/html/2607.10995v1","pdf_url":"https://arxiv.org/pdf/2607.10995v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.10992v1","title":"LoSA-Net: A Localized and Scale-Adaptive Network for Boundary-Sensitive Prediction of Perineural Invasion in 3D MRI","abstract":"Perineural invasion (PNI) is a clinically relevant indicator of tumor aggressiveness and can influence surgical decision-making, motivating interest in reliable preoperative assessment. The subtle MRI features of PNI, however, often resemble nearby anatomy, complicating noninvasive prediction. These fine perineural cues are easily attenuated by routine downsampling or overly global feature aggregation, reducing the effectiveness of conventional volumetric models. We present LoSA-Net, a localized and scale-adaptive architecture for boundary-sensitive PNI prediction in 3D MRI. Talking Neighborhood Attention (TNA) preserves nerve-aligned detail through localized self-attention with head-wise mixing, and Scale-Adaptive Feature Mixing (SAFM) modulates the receptive field using multi-scale depthwise processing. Cross-Scale Refinement and Alignment (CSRA) maintains consistency between semantic context and high-resolution boundaries across stages. In contrast-enhanced MRI scans from 168 patients with cholangiocarcinoma, LoSA-Net achieves an AUC of 0.7567 and outperforms representative convolutional and transformer baselines under matched preprocessing and optimization settings.","authors":["Youngung Han","Hyunsu Go","Kyeonghun Kim","Induk Um","Junga Kim","Jaewon Jung","Woo Kyoung Jeong","Won Jae Lee","Pa Hong","Ken Ying-Kai Liao","Hyuk-Jae Lee","Nam-Joon Kim"],"published":"2026-07-13T01:31:01Z","updated":"2026-07-13T01:31:01Z","abstract_url":"https://arxiv.org/abs/2607.10992v1","html_url":"https://arxiv.org/html/2607.10992v1","pdf_url":"https://arxiv.org/pdf/2607.10992v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.10991v1","title":"Think When It Matters: Conditional VLM Reasoning for Social Navigation with RL Policies","abstract":"As mobile robots become more integrated into everyday human environments, social robot navigation is becoming essential for ensuring human comfort, safety, and trust. While reinforcement learning (RL) navigation policies provide the fast inference and reactive behavior necessary for real-time deployment, they still lack flexible semantic reasoning capabilities and often fail to generalize to complex social scenarios. Recent approaches have increasingly turned to vision-language models (VLMs) in place of RL policies to improve semantic and social reasoning in robot navigation. Nevertheless, their high computational cost and slow inference remain major barriers to real-time deployment. To overcome these limitations, we introduce HUMA (Hybrid Understanding for Multi-modal social Navigation), a hybrid architecture that dynamically balances the computational efficiency of RL policies with the deep semantic understanding of VLMs. Our approach uses a reactive RL policy to handle low-density, routine navigation tasks, while conditioning it on a post-trained high-level VLM when a human enters sensitive situations, such as the robot's proximity zone. We evaluate HUMA on the Social-MP3D and Social-HM3D benchmarks, where it achieves task success improvements of 20% and 3%, respectively, while significantly reducing personal space violations and human collisions against state-of-the-art baselines. Extensive ablation studies validate each architectural component, and real-world deployment on the Mirokaï mobile robot further demonstrates the practical viability of our approach.","authors":["Ali Ahmadi","Hamed Rahimi","Adrien Jacquet Cretides","Marie Samson","Mahdi Khoramshahi","Mohamed Chetouani"],"published":"2026-07-13T01:27:27Z","updated":"2026-07-13T01:27:27Z","abstract_url":"https://arxiv.org/abs/2607.10991v1","html_url":"https://arxiv.org/html/2607.10991v1","pdf_url":"https://arxiv.org/pdf/2607.10991v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.10990v1","title":"TreeSoc: Tree-Structured Dynamic Reasoning and Tool Synergy for Soccer Video Understanding","abstract":"Automated understanding of complex soccer scenarios from video remains a significant challenge for contemporary vision-language models (VLMs), which suffer from shallow cross-modal alignment and exhibit fundamental limitations in multi-step reasoning and coordinated tool integration. We present TreeSoc, a structured reasoning framework that reformulates soccer video question answering as a hierarchical search problem rather than a single-pass prediction. Specifically, TreeSoc employs a dynamic depth-first search (DFS) mechanism that decomposes complex queries into sequentially ordered sub-tasks, enabling iterative reasoning refinement through explicit intermediate states. This tree-structured decomposition naturally supports adaptive tool routing, wherein domain-specific modules are selectively activated and their outputs incorporated at each reasoning node to produce contextually grounded predictions. On SoccerBench, TreeSoc achieves state-of-the-art performance, with accuracies of 85.2%, 87.4%, and 82.2% on TextQA, ImageQA, and VideoQA, respectively. Additionally, TreeSoc further demonstrates strong cross-domain generalization, attaining 74.16% accuracy on NExT-QA. These results establish structured, tool-augmented tree reasoning as an effective paradigm for robust video understanding. Code is available at: https://github.com/thanhnhan29/TreeSoc.","authors":["Thanh-Nhan Vo","Thanh-Khoi Nguyen","Trong-Thuan Nguyen","Trung-Hoang Le","Minh-Triet Tran"],"published":"2026-07-13T01:27:20Z","updated":"2026-07-13T01:27:20Z","abstract_url":"https://arxiv.org/abs/2607.10990v1","html_url":"https://arxiv.org/html/2607.10990v1","pdf_url":"https://arxiv.org/pdf/2607.10990v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.10988v1","title":"MMA-Former: Multi-Window Mixture-of-Head Attention Transformer for Adaptive PNI Prediction in 3D MRI","abstract":"Perineural invasion (PNI) is a critical prognostic factor in cholangiocarcinoma. Non-invasive prediction from 3D MRI is challenging, demanding models that efficiently capture both fine-grained details and global context. We propose the Multi-window Mixture-of-Head Attention Transformer (MMA-Former), a novel end-to-end 3D architecture featuring a Coarse-Fine Transformer (CFT) structure for parallel multi-scale feature extraction. We advance this structure by integrating a novel Window-Specific Mixture-of-Head attention (WS-MoH) mechanism. Unlike standard Multi-Head Self Attention (MSA), WS-MoH generates a representation for each 3D window and dynamically routes the entire window to specialized or common attention heads. This enables spatially adaptive feature extraction tailored to the local context of each window, enhancing specialization and reducing redundancy without increasing parameters. Evaluated on a retrospective dataset of 168 T1-weighted MRI scans, MMA-Former achieved an AUC of 0.752, outperforming other 3D architectures, including the best CNN (AUC of 0.708) and Transformer baselines (AUC of 0.681).","authors":["Youngung Han","Induk Um","Kyeonghun Kim","Junga Kim","Hyunsu Go","Jaewon Jung","Woo Kyoung Jeong","Won Jae Lee","Pa Hong","Ken Ying-Kai Liao","Hyuk-Jae Lee","Nam-Joon Kim"],"published":"2026-07-13T01:22:16Z","updated":"2026-07-13T01:22:16Z","abstract_url":"https://arxiv.org/abs/2607.10988v1","html_url":"https://arxiv.org/html/2607.10988v1","pdf_url":"https://arxiv.org/pdf/2607.10988v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.10984v1","title":"EquiFusion: Kinematics-Agnostic Human Motion Prediction via Equivariant Latent Diffusion","abstract":"Existing Stochastic 3D Human Motion Prediction models are fundamentally constrained by hard-coding the skeleton kinematics, severely limiting generalization, preventing cross-dataset training, and requiring complex data retargeting. We introduce EquiFusion, the first kinematics-agnostic model to solve this bottleneck, implementing a latent diffusion model with a permutation equivariant architecture. EquiFusion treats the kinematics' connectivity as an explicit input parameter, ensuring its internal computations are inherently agnostic to joint ordering and graph structure. This novel design enables truly cross-dataset generalization to unseen kinematics and unlocks novel zero-shot directions, such as motion prediction from partial or occluded observations and targeted limb generation. EquiFusion achieves state-of-the-art results on major benchmarks, being up to 75% more compact than previous kinematics-specific methods, while achieving faster training and inference. EquiFusion thus establishes a new, flexible standard for robust human motion prediction. Model and training code are available at https://ceveloper.github.io/publications/equifusion/.","authors":["Cecilia Curreli","Florian Hofherr","Dominik Muhle","Abhishek Saroha","Riccardo Marin","Daniel Cremers"],"published":"2026-07-13T01:16:18Z","updated":"2026-07-13T01:16:18Z","abstract_url":"https://arxiv.org/abs/2607.10984v1","html_url":"https://arxiv.org/html/2607.10984v1","pdf_url":"https://arxiv.org/pdf/2607.10984v1.pdf","matched_keywords":["3d","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.10953v1","title":"Learning Anatomy-Grounded CT Vision-Language Representations with Organ-Hierarchical Report Knowledge","abstract":"Medical vision-language pretraining (VLP) from paired CT images and radiology reports enables scalable representation learning, but most existing methods align either whole scans with entire reports or local image regions with text fragments. These formulations underuse a key property of radiology reports: findings are organized around anatomical structures, with abnormalities described by organs, disease concepts, locations, and severity-related attributes. We propose OKA-CT, an organ-hierarchical knowledge-augmented framework for CT-report VLP. OKA-CT first converts free-text reports into organ-conditioned knowledge using radiology report parsing and LLM-assisted semantic structuring. The extracted hierarchy is used across two learning stages. Stage~1 injects anatomy-grounded evidence into the CT visual representation through fine-grained organ-conditioned supervision, while Stage~2 uses organ-specific report evidence to guide structured report-CT contrastive learning, where hierarchy-derived semantic soft targets treat non-paired cases with shared organ-level findings as weak semantic positives rather than uniform negatives. A lightweight query-based global branch further aggregates disease-relevant volumetric evidence for whole-scan representation. On CT-RATE and RAD-ChestCT datasets, OKA-CT achieves zero-shot abnormality diagnosis AUROCs of 84.9 and 72.2, outperforming prior CT VLP baselines. Retrieval and patch-occlusion analyses further show improved report-image alignment and stronger sensitivity to disease-associated anatomical regions.","authors":["Guoliang You","Hongming Li","Yuanwang Zhang","Yong Fan"],"published":"2026-07-12T23:09:23Z","updated":"2026-07-12T23:09:23Z","abstract_url":"https://arxiv.org/abs/2607.10953v1","html_url":"https://arxiv.org/html/2607.10953v1","pdf_url":"https://arxiv.org/pdf/2607.10953v1.pdf","matched_keywords":["retrieval","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"}],"favorites":[],"latest":{"generated_at_utc":"2026-07-14T03:53:24+00:00","category":"cs.CV","keywords":["video","retrieval","3d","agent","representation","instance","multimodal","diffusion"],"fetch_window_hours":72,"daily_window_hours":30,"match_count":64,"new_or_recent_papers":[{"id":"2607.11886v1","title":"Read It Back: Pretrained MLLMs Are Zero-Shot Reward Models for Text-to-Image Generation","abstract":"In this paper, we propose SpectraReward, a training-free reward function that turns pretrained MLLMs into off-the-shelf reward models for image-generation reinforcement learning. Instead of asking the MLLM to judge a generated image or answer decomposed verification questions, SpectraReward measures how well the original prompt can be recovered from the generated image through a single image-conditioned, teacher-forced forward pass. We use the average image-conditioned prompt log-likelihood as the reward, directly reusing the MLLM's pretrained image-text alignment ability without preference labels, reward-model fine-tuning. We further introduce Self-SpectraReward, a special case for unified multimodal models where the policy's own understanding branch serves as the reward model for its generation branch, forming a closed-loop self-improving framework without external reward models or external knowledge. Extensive experiments validate SpectraReward through a broad image-generation RL study covering two diffusion models, three RL algorithms, nine reward MLLM backbones from four MLLM families spanning 4B to 235B parameters, and five out-of-distribution text-to-image benchmarks. Results show that both SpectraReward and Self-SpectraReward significantly and consistently improve generation performance and outperform prior MLLM-derived reward training methods. Further analysis reveals that larger reward MLLMs are not always better, while Self-SpectraReward can match or surpass much larger external reward models, suggesting that reward-policy alignment is a key factor for effective image-generation RL. Project Page: https://huangrh99.github.io/SpectraReward/","authors":["Runhui Huang","Qihui Zhang","Zhe Liu","Yu Gao","Jie Wu","Hengshuang Zhao"],"published":"2026-07-13T17:59:58Z","updated":"2026-07-13T17:59:58Z","abstract_url":"https://arxiv.org/abs/2607.11886v1","html_url":"https://arxiv.org/html/2607.11886v1","pdf_url":"https://arxiv.org/pdf/2607.11886v1.pdf","matched_keywords":["multimodal","diffusion"],"source_used":"html","source_text_chars":56240,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal, diffusion 相关；摘要显示其主要贡献为：In this paper, we propose SpectraReward, a training-free reward function that turns pretrained MLLMs into off-the-shelf reward models for image-generation reinforcement learning. Instead of asking the MLLM to judge a generated image or answer decomposed verif...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:25+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11885v1","title":"Latent-Identity Tuning in Text-to-Image Personalization Models","abstract":"Generating and editing a person's face demands high precision, as even minor modifications can significantly alter a subject's perceived identity. Current personalization and editing methods built on general-purpose text-to-image models, however, often lack the precision required for fine-grained facial edits. We present a method for fine-grained identity tuning in text-to-image personalization models. Unlike standard image editing, which operates on a given image, identity tuning modifies the latent representation of a specific identity, enabling the generation of diverse images that consistently depict the same edited identity. To enable fine-grained latent identity tuning, we explore the latent space of a pre-trained, frozen encoder for text-to-image personalization. Our approach requires no additional training. Instead, it leverages the existing architecture of a frozen encoder to uncover latent semantic directions. This space consists of a set of latent tokens that play distinct roles in capturing different aspects of an identity and often correspond to specific spatial or semantic facial regions. We show that meaningful directions can be identified within this space and within subspaces defined by selected tokens, enabling localized, fine-grained, and semantically coherent edits. We validate our approach through qualitative and quantitative experiments that demonstrate diverse localized facial edits while preserving cross-image identity consistency. Project page at: https://garibida.github.io/IdentityTuning/","authors":["Daniel Garibi","Ronen Kamenetsky","Hadar Averbuch-Elor","Daniel Cohen-Or","Or Patashnik"],"published":"2026-07-13T17:59:49Z","updated":"2026-07-13T17:59:49Z","abstract_url":"https://arxiv.org/abs/2607.11885v1","html_url":"https://arxiv.org/html/2607.11885v1","pdf_url":"https://arxiv.org/pdf/2607.11885v1.pdf","matched_keywords":["representation"],"source_used":"html","source_text_chars":73803,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation 相关；摘要显示其主要贡献为：Generating and editing a person's face demands high precision, as even minor modifications can significantly alter a subject's perceived identity. Current personalization and editing methods built on general-purpose text-to-image models, however, often lack t...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:25+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11862v1","title":"Evidence-Backed Video Question Answering","abstract":"Current Video Large Language Models (Video LLMs) excel in question answering (QA) but largely operate as black boxes, providing textual answers without verifiable visual grounding. Existing explainability efforts rely on textual rationales or sparse bounding boxes, which struggle to capture complex video dynamics such as occlusions and non-rigid deformations. We propose Evidence-Backed Video Question Answering (E-VQA), a novel task requiring models to jointly output a semantic answer and precise spatio-temporal evidence: temporal segments and dense, tracked object segmentation masklets. To support this, we introduce ST-Evidence, the first human-verified benchmark for both discriminative and generative pixel-level grounding. Evaluations of state-of-the-art models reveal a critical decoupling between QA accuracy and true visual perception that scaling alone fails to bridge. To address this, we develop scalable, automated generation pipelines to create ST-Evidence-Instruct, a 160k-scale dataset bridging high-level reasoning with fine-grained grounding. Fine-tuning grounded Video LLMs on this data yields substantial gains over the corresponding size-matched UniPixel baselines (e.g., +27.2 t-mean and +13.8 J&F on a 7B model), establishing a robust baseline for explainable, evidence-backed video understanding. Code and data are available at https://github.com/SalesforceAIResearch/EVQA.","authors":["Shijie Wang","Honglu Zhou","Ziyang Wang","Ran Xu","Caiming Xiong","Silvio Savarese","Chen Sun","Juan Carlos Niebles"],"published":"2026-07-13T17:49:10Z","updated":"2026-07-13T17:49:10Z","abstract_url":"https://arxiv.org/abs/2607.11862v1","html_url":"https://arxiv.org/html/2607.11862v1","pdf_url":"https://arxiv.org/pdf/2607.11862v1.pdf","matched_keywords":["video"],"source_used":"html","source_text_chars":50968,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video 相关；摘要显示其主要贡献为：Current Video Large Language Models (Video LLMs) excel in question answering (QA) but largely operate as black boxes, providing textual answers without verifiable visual grounding. Existing explainability efforts rely on textual rationales or sparse bounding...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:25+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11844v1","title":"Beyond the Single Camera: Agentic Multi-View Reasoning in Sports Video Understanding","abstract":"Recent Multimodal Large Language Models (MLLMs) achieve strong performance on single-view video understanding benchmarks. However, sports videos involve dense occlusion, rapid motion, and complex interactions that are difficult to resolve from a single viewpoint. In practice, sports events are recorded from multiple camera angles, providing complementary evidence used by referees. Yet, no existing benchmark evaluates MLLMs on multi-view sports video understanding. To address this gap, we introduce SportMV-Bench, a comprehensive benchmark built from official match recordings, through a dedicated pipeline combining LLM-based generation, MLLM-based verification, and human filtering to ensure quality and consistency. SportMV-Bench containing 787 multi-view video bundles and 2592 question-answer pairs across three categories: Perception-Aware Recognition (PAR), Rule-aware Event Interpretation (REI), and Adjudicative Decision Reasoning(ADR). Our analysis shows that current MLLMs fail to effectively exploit multi-view information, with the bottlenecks lying in fine-grained visual perception and view selection rather than logical reasoning or domain knowledge. We propose SportMV-Agent, an agentic framework that orchestrates an iterative loop of active view selection, perception tool execution, and evidence-grounded reasoning, achieving a significant 14.46% relative improvement over the strongest MLLM baseline.","authors":["Kerui Chen","Jinglu Wang","Xiaoyi Zhang","Yan Lu"],"published":"2026-07-13T17:34:36Z","updated":"2026-07-13T17:34:36Z","abstract_url":"https://arxiv.org/abs/2607.11844v1","html_url":"https://arxiv.org/html/2607.11844v1","pdf_url":"https://arxiv.org/pdf/2607.11844v1.pdf","matched_keywords":["video","agent","multimodal"],"source_used":"html","source_text_chars":61906,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, agent, multimodal 相关；摘要显示其主要贡献为：Recent Multimodal Large Language Models (MLLMs) achieve strong performance on single-view video understanding benchmarks. However, sports videos involve dense occlusion, rapid motion, and complex interactions that are difficult to resolve from a single viewpo...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:25+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11839v1","title":"LoRA-Based Cascaded Multimodal Fusion for Action Recognition in Medical Training Environments","abstract":"This paper presents a cascaded Low-Rank Adaptation (LoRA)-based multimodal fusion framework for action and activity recognition in healthcare-oriented training environments. The proposed architecture combines parameter-efficient modality-specific adaptation with sequential fusion, enabling modalities to be integrated in stages without retraining previously learned components. Rather than assuming a fixed fusion structure, the framework first integrates more closely related modalities and then incorporates additional heterogeneous modalities, supporting scalable adaptation across datasets with different modality sets.We evaluate the framework on two healthcare-oriented training environment datasets: NurViD and the Nurse Training dataset. Across these datasets, preliminary results suggest that the proposed cascaded fusion strategy improves over individual modality models and provides competitive performance relative to previously reported dataset-specific baselines. Overall, these findings indicate that cascaded LoRA-based fusion is a promising parameter-efficient approach for integrating heterogeneous modalities in medical training action and activity recognition tasks. github: https://github.com/anonymous0-ai/LoRA-Based-Cascaded-Multimodal-Fusion-.git.","authors":["Divya Mereddy","Jeevan Beedareddy"],"published":"2026-07-13T17:27:58Z","updated":"2026-07-13T17:27:58Z","abstract_url":"https://arxiv.org/abs/2607.11839v1","html_url":"https://arxiv.org/html/2607.11839v1","pdf_url":"https://arxiv.org/pdf/2607.11839v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":1367,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：This paper presents a cascaded Low-Rank Adaptation (LoRA)-based multimodal fusion framework for action and activity recognition in healthcare-oriented training environments. The proposed architecture combines parameter-efficient modality-specific adaptation w...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"abstract","created_at":"2026-07-14T03:53:25+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11836v1","title":"Cycle-World: Mitigating Error Accumulation in Long-term Video World Models via Reverse-Prediction Cycle Consistency","abstract":"Autoregressive diffusion models have enabled high-quality video generation, yet their sequential nature inherently suffers from error accumulation. In long-horizon video synthesis, minor prediction deviations compound over time, inevitably leading to unconstrained generative drift, structural collapse, and severe visual degradation. To address this, we propose Cycle-World, a novel framework designed for stable and temporally consistent long-video generation. Our approach tackles error drift by enforcing strict temporal reversibility across both the training and inference phases. Theoretically, we demonstrate that forward generative drift can be strictly bottlenecked by a cycle-consistency objective. During training, we integrate an efficient reverse-prediction model to implicitly embed causal constraints into the forward generator, compelling it to produce reversible sequences that tightly adhere to the natural video manifold. At inference time, we repurpose this frozen reverse model as a runtime corrector. Through gradient-based cycle guidance, it iteratively refines the generated latent representations, actively suppressing accumulated errors before they are committed to the historical context. Extensive experiments on the VBench benchmark demonstrate that Cycle-World's dual-phase synergy significantly mitigates error drift, achieving state-of-the-art overall generation quality and long-horizon temporal consistency in 60-second synthesis.","authors":["Zihan Su","Teng Hu","Jiangning Zhang","Ruiyan Wang","Ran Yi","Lizhuang Ma","Dacheng Tao"],"published":"2026-07-13T17:27:13Z","updated":"2026-07-13T17:27:13Z","abstract_url":"https://arxiv.org/abs/2607.11836v1","html_url":"https://arxiv.org/html/2607.11836v1","pdf_url":"https://arxiv.org/pdf/2607.11836v1.pdf","matched_keywords":["video","representation","diffusion"],"source_used":"html","source_text_chars":78154,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, representation, diffusion 相关；摘要显示其主要贡献为：Autoregressive diffusion models have enabled high-quality video generation, yet their sequential nature inherently suffers from error accumulation. In long-horizon video synthesis, minor prediction deviations compound over time, inevitably leading to unconstr...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:25+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11818v1","title":"MM-ToolSandBox: A Unified Framework for Evaluating Visual Tool-Calling Agents","abstract":"We introduce MM-ToolSandBox, a benchmark and evaluation framework for visually grounded tool-calling agents. The framework provides a stateful execution environment spanning 500+ tools across 16 application domains, supporting multi-image, multi-turn tasks where agents must ground progressively arriving visual inputs into executable tool calls while handling realistic conversational phenomena (goal revisions, error corrections, state mutations). An automated scenario generation pipeline produces diverse, visually grounded scenarios through information-flow-guided planning and multi-stage quality filtering, yielding 258 human-verified nominal scenarios and 50 variants targeting interactive UI applications. Evaluating 12 state-of-the-art models, from 4B open-weight to frontier proprietary systems, shows that current models still lack robust visual tool-calling capability: even the best model achieves below 50% success rate. Our failure analysis further reveals that visual precision, not only planning, is a primary bottleneck for capable models: 53% of failures stem from incorrect information extraction from images despite otherwise correct task workflows. A planning-to-precision crossover emerges with scale: smaller models fail at deciding what to do, while larger models fail at perceiving what they see, suggesting fundamentally different research directions for improving models at different capability levels. The framework and the benchmark are publicly available at https://github.com/apple/ml-mmtoolsandbox","authors":["Kaixin Ma","Di Feng","Alexander Metz","Jiarui Lu","Eshan Verma","Afshin Dehghan"],"published":"2026-07-13T17:13:09Z","updated":"2026-07-13T17:13:09Z","abstract_url":"https://arxiv.org/abs/2607.11818v1","html_url":"https://arxiv.org/html/2607.11818v1","pdf_url":"https://arxiv.org/pdf/2607.11818v1.pdf","matched_keywords":["agent"],"source_used":"abstract","source_text_chars":1610,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 agent 相关；摘要显示其主要贡献为：We introduce MM-ToolSandBox, a benchmark and evaluation framework for visually grounded tool-calling agents. The framework provides a stateful execution environment spanning 500+ tools across 16 application domains, supporting multi-image, multi-turn tasks wh...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"abstract","created_at":"2026-07-14T03:53:26+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11798v1","title":"StoryTeller: Training-Free Narrative Grounding for Long-Form Audio Description","abstract":"Long-form audio description (AD) requires more than describing visible actions: it must preserve characters, events, relationships, and story context across scenes so that blind and low-vision (BLV) audiences can follow a film. Modern video-language models (VLMs) are effective on short clips, but they often treat each moment independently, producing descriptions that miss who characters are, why events matter, and how the current scene connects to earlier narrative context. We propose StoryTeller, a training-free framework for story-aware long-form AD. Instead of relying only on local visual cues, StoryTeller maintains a verified narrative memory that carries forward story-relevant information across scenes, enabling later descriptions to remain coherent, grounded, and contextually informative. Given only raw video and a movie title, StoryTeller can optionally retrieve public movie metadata to resolve names and story context, while accepting only facts that are supported by the video through semantic filtering and VLM verification. The method requires no subtitles, scripts, AD transcripts, aligned captions, character banks, precomputed face identities, or task-specific fine-tuning. To evaluate whether generated AD preserves narrative information, we introduce StoryAD-QA, a question-answering benchmark that tests whether a language model can answer story-context questions using only the generated descriptions. Experiments on standard AD benchmarks and diverse long-form videos show that StoryTeller consistently improves narrative coherence, factual grounding, and story comprehension over strong baselines in automatic, QA-based, and human evaluations.","authors":["Seung Hyun Hahm","Minh T. Dinh","SouYoung Jin"],"published":"2026-07-13T16:50:03Z","updated":"2026-07-13T16:50:03Z","abstract_url":"https://arxiv.org/abs/2607.11798v1","html_url":"https://arxiv.org/html/2607.11798v1","pdf_url":"https://arxiv.org/pdf/2607.11798v1.pdf","matched_keywords":["video"],"source_used":"html","source_text_chars":43642,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video 相关；摘要显示其主要贡献为：Long-form audio description (AD) requires more than describing visible actions: it must preserve characters, events, relationships, and story context across scenes so that blind and low-vision (BLV) audiences can follow a film. Modern video-language models (V...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:26+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11754v1","title":"Higher-Order Cell Tracking Transformer","abstract":"Reconstructing lineages from live-imaging microscopy requires linking cell detections across time, including through cell divisions. A common approach is to construct a candidate graph and associate cell segmentations (nodes) across frames. However, these and other existing methods overlook two structural obstacles in candidate tracking graphs: (i) cell divisions entangle distinct lineage paths in the node embedding space, and (ii) edges sharing a node have near-random label agreement, so the candidate-graph topology carries no useful information for graph neural networks to aggregate. We propose the \\textbf{Higher-Order Cell Tracking Transformer} (HOCT), an edge-centric architecture in which candidate cell links attend to one another under a 3D geometric prior, resolving both issues. Evaluated on the Cell Tracking Challenge and a bacteria division benchmark, HOCT achieves state-of-the-art results without deep pre-trained image encoders. Moreover, the proposed approach is easier to fine-tune, quickly reducing tracking errors by 59% with 400 annotations in a human-in-the-loop setting, outperforming LoRA fine-tuning of competing transformer baselines (6.75% improvement).","authors":["Jordão Bragantini","Ilan Theodoro","Loïc A. Royer"],"published":"2026-07-13T16:12:29Z","updated":"2026-07-13T16:12:29Z","abstract_url":"https://arxiv.org/abs/2607.11754v1","html_url":"https://arxiv.org/html/2607.11754v1","pdf_url":"https://arxiv.org/pdf/2607.11754v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":101424,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：Reconstructing lineages from live-imaging microscopy requires linking cell detections across time, including through cell divisions. A common approach is to construct a candidate graph and associate cell segmentations (nodes) across frames. However, these and...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:26+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11732v1","title":"GFR-SAM: Training-Free Referring Camouflaged Object Segmentation via Cross-Image Prompting","abstract":"Referring Camouflaged Object Detection (Ref-COD) requires segmenting hidden targets guided by reference cues. While supervised methods are annotation-heavy and training-free approaches via sparse point-prompting are sensitive to localization errors, we propose GFR-SAM, a robust three-stage training-free framework. GFR-SAM shifts the paradigm from fragile point-matching to a \"Generate-Filter-Refine\" pipeline. First, we introduce In-Context Exemplar-guided Segmentation, empowering SAM3 with cross-image inference to generate candidate masks via holistic visual exemplars, bypassing its native intra-image constraints. Second, a Region-Global Contrastive Filtering module ranks candidates through DINOv3-based prototypical alignment, effectively suppressing background distractors. Finally, a Geometric-Semantic Refinement module synergizes bounding box and text prompts to recover fine-grained boundaries and enhance instance recall. Evaluated on the R2C7K benchmark, GFR-SAM outperforms existing training-free methods by 8.7\\% in weighted F-measure ($F_β^w$) and competes with supervised state-of-the-art counterparts. Ultimately, this work underscores the potential of unlocking SAM3's latent capability for cross-image In-Context prompting, establishing a robust, training-free paradigm that effectively bridges the gap between general-purpose foundation models and specialized, label-intensive perception tasks without the need for task-specific fine-tuning.","authors":["Yilong Yang","Jianxin Tian","Shengchuan Zhang","Liujuan Cao"],"published":"2026-07-13T15:55:45Z","updated":"2026-07-13T15:55:45Z","abstract_url":"https://arxiv.org/abs/2607.11732v1","html_url":"https://arxiv.org/html/2607.11732v1","pdf_url":"https://arxiv.org/pdf/2607.11732v1.pdf","matched_keywords":["instance"],"source_used":"html","source_text_chars":55653,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 instance 相关；摘要显示其主要贡献为：Referring Camouflaged Object Detection (Ref-COD) requires segmenting hidden targets guided by reference cues. While supervised methods are annotation-heavy and training-free approaches via sparse point-prompting are sensitive to localization errors, we propos...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:26+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11710v1","title":"SVI360: Spherical Video Interpolation","abstract":"This paper addresses the problem of omnidirectional video interpolation, which plays an essential role in applications such as virtual reality and immersive video enhancement. Existing video interpolation methods are not well-suited for spherical videos, as they have difficulty handling severe distortions close to the poles. To address this issue, we propose SVI360, a dual-branch framework that combines the image frame and its rotated orthogonal view to deal with these distortions. The core methodological aspect of the approach is to reinforce equivariance of the flow displacements between the original and orthogonal views to improve intermediate frame prediction. Experiments show that our method outperforms state-of-the-art approaches in interpolation quality while maintaining accurate optical flow in four different public benchmarks. Code and pre-trained models are available at: https://icb-vision-ai.github.io/video360_interpolation/","authors":["Le-Kim Nguyen","Renato Martins","Pascal Vasseur","Cedric Demonceaux"],"published":"2026-07-13T15:37:52Z","updated":"2026-07-13T15:37:52Z","abstract_url":"https://arxiv.org/abs/2607.11710v1","html_url":"https://arxiv.org/html/2607.11710v1","pdf_url":"https://arxiv.org/pdf/2607.11710v1.pdf","matched_keywords":["video"],"source_used":"html","source_text_chars":53971,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video 相关；摘要显示其主要贡献为：This paper addresses the problem of omnidirectional video interpolation, which plays an essential role in applications such as virtual reality and immersive video enhancement. Existing video interpolation methods are not well-suited for spherical videos, as t...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:26+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11681v1","title":"Illuminant-Adaptive 3D Lookup Tables for Camera Color Correction","abstract":"Color correction is a key component of camera image signal processing (ISP) pipelines, encompassing illuminant discounting and colorimetric mapping of device-dependent sensor responses to device-independent color spaces, such as CIE XYZ. Despite extensive research, accurate color correction remains challenging due to the non-linear relationship between camera sensor responses and CIE XYZ color space, as well as to the increasing presence of highly chromatic and spectrally complex LED illuminants. We propose a color correction framework based on illuminant-adaptive three-dimensional lookup tables (LUTs), which we call Color Correction LUT (C$^2$LUT). Our method combines a chromaticity-aware illuminant representation with a non-linear color transformation, enabling accurate correction under illuminants spanning a wide range of chromaticities and spectral complexities. We employ Tucker tensor decomposition to represent the LUTs, ensuring that computational requirements remain sufficiently low for deployment in camera ISPs. In addition, we introduce a large-scale illuminants dataset comprising 1,473 spectral power distributions, with different chromaticities and spectral profiles. Experiments across multiple cameras, illuminants, reflectance datasets, and real captured images demonstrate consistent improvements over existing methods for color correction, reducing CIE $ΔE_{00}$ by up to 20% and angular error by up to 18% while remaining compatible with modern camera hardware constraints. Code and datasets are available at https://github.com/claudiom4sir/C2LUT.","authors":["Claudio Rota","Luca Cogo","Simone Bianco","Raimondo Schettini"],"published":"2026-07-13T15:19:35Z","updated":"2026-07-13T15:19:35Z","abstract_url":"https://arxiv.org/abs/2607.11681v1","html_url":"https://arxiv.org/html/2607.11681v1","pdf_url":"https://arxiv.org/pdf/2607.11681v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":1647,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d, representation 相关；摘要显示其主要贡献为：Color correction is a key component of camera image signal processing (ISP) pipelines, encompassing illuminant discounting and colorimetric mapping of device-dependent sensor responses to device-independent color spaces, such as CIE XYZ. Despite extensive res...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"abstract","created_at":"2026-07-14T03:53:26+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11673v1","title":"ABot-3DWorld 0: A Universal World Model to Explore Any 3D Space","abstract":"We present ABot-3DWorld 0, a universal multimodal 3D world model that turns text, image, and video inputs into high-fidelity, explorable 3D worlds. At the heart of our framework is a unified Spatial Generative Primitive (SGP), a compact tuple of a high-quality panorama and a spatial point cloud that delivers an efficient description of any 3D space. Multimodal inputs are first lifted into this primitive; a 3D-consistent panoramic video generator then explores the primitive along a planned trajectory; finally, our panoramic video reconstruction engine converts the generated video into a clean, photorealistic 3D Gaussian Splatting (3DGS) world. This pipeline covers two regimes: rich inputs (multi-view sets, casual video) are lifted into the SGP through a geometry-rigorous recovery that mirrors the observed scene, while a single image or sentence is completed generatively into a creative world. The result is one low-barrier engine for general 3D content creation that further anchors generated worlds to geographic points of interest, enabling map-native spatial exploration at consumer scale. Experiments show that ABot-3DWorld 0 sets the state of the art among open-source methods and demonstrates stronger scene fidelity than Marble under rich multimodal inputs.","authors":["Mingchao Sun","Luyang Tang","Yu Liu","Xu Yan","Zhan Li","Yunwei Zhang","Fei Yu","Zengye Ge","Yumin Liu","Jiacheng Zhang","Yongchang Zhang","Jiawei Zhang","Zhicheng Liu","Zhongxu Sun","Tianjian Ouyang","Wenzheng Chen","Shixing Yang","Nianfei Fan","Guodong Sun","Huan Li","Zheng Zhou","Yongze Li","Yingliang Peng","Mengmeng Du","Yuan Liu","Haozhe Shi","Chunnuo Gong","Chengzhen Yu","Chunxue Jia","Yang Liu","Shiying Zeng","Junnan Lai","Hang Zhang","Ning Guo","Baoquan Chen","Mu Xu","Hongyu Pan"],"published":"2026-07-13T15:14:48Z","updated":"2026-07-13T15:14:48Z","abstract_url":"https://arxiv.org/abs/2607.11673v1","html_url":"https://arxiv.org/html/2607.11673v1","pdf_url":"https://arxiv.org/pdf/2607.11673v1.pdf","matched_keywords":["video","3d","multimodal"],"source_used":"abstract","source_text_chars":1341,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video, 3d, multimodal 相关；摘要显示其主要贡献为：We present ABot-3DWorld 0, a universal multimodal 3D world model that turns text, image, and video inputs into high-fidelity, explorable 3D worlds. At the heart of our framework is a unified Spatial Generative Primitive (SGP), a compact tuple of a high-qualit...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"abstract","created_at":"2026-07-14T03:53:26+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11655v1","title":"Feature-Space Guided Diffusion for Realistic Ultrasound Image Synthesis","abstract":"Conditional diffusion models can generate anatomically plausible medical ultrasound (US) images, but anatomical plausibility alone does not ensure realistic B-mode appearance. Most US pipelines adapt standard generative architectures and condition them on anatomical masks, or use guidance mechanisms that reinforce the same anatomical signal. However, B-mode US images are shaped by acquisition-dependent properties such as speckle texture, tissue contrast, and attenuation. Using a frozen US foundation model, we show that standard conditional diffusion baselines remain separated from real images in representation space. In this work, we propose Feature-Space Candidate Guidance (FSCG), a training-free sampling strategy to reduce this gap. At sampling time, FSCG applies local k-NN feature correction and selects the best of multiple stochastic candidates according to their feature-space energy. In this way, the mask defines the anatomy, while FSCG steers samples toward the real US domain. Across three different datasets, FSCG reduces average FID64 by 56\\%, FID192 by 57\\%, and nearest-neighbour feature distance by 47\\% over standard conditional diffusion sampling, outperforming alternative inference-time guidance baselines. The results suggest that domain-aware feature representations can reveal and reduce realism gaps in medical diffusion synthesis without retraining the generator. Our code is available at https://github.com/marinadominguez/FSCG.","authors":["Marina Domínguez","Nélida Mirabet-Herranz","Valery Naranjo"],"published":"2026-07-13T15:05:21Z","updated":"2026-07-13T15:05:21Z","abstract_url":"https://arxiv.org/abs/2607.11655v1","html_url":"https://arxiv.org/html/2607.11655v1","pdf_url":"https://arxiv.org/pdf/2607.11655v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"html","source_text_chars":32219,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation, diffusion 相关；摘要显示其主要贡献为：Conditional diffusion models can generate anatomically plausible medical ultrasound (US) images, but anatomical plausibility alone does not ensure realistic B-mode appearance. Most US pipelines adapt standard generative architectures and condition them on ana...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:27+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11644v1","title":"Motion4Motion: Motion Transfer Across Subjects at Inference","abstract":"This work explores the motion transfer from one video to another, which is crucial in animation for diverse characters. Previously, video motion transfer has been largely explored between human and human-like characters, enabling a lot of applications in digital creation. However, these approaches encounter a main limitation. Specifically, related technical pipelines heavily rely on a predefined human skeleton structure and accordingly require skeleton-conditional model training. On the one hand, these methods are difficult to generalize to diverse characters, such as animals from different species, while preserving their unique motion styles. On the other hand, labeled data in diverse skeletons is limited, which additionally restricts the large-scale training for the task. In this paper, we jump out of the skeleton-based motion transfer framework and propose a training-free motion transfer framework, named Motion4Motion. Motion4Motionmodels the motion flow of the character in a video instead of skeletons, which makes motion transfer across species easier. Extensive experimental results and novel applications show our methods outperform baselines impressively. Project page is available at https://lhchen.top/Motion4Motion.","authors":["Ling-Hao Chen","Zixin Yin","Duomin Wang","Xianfang Zeng","Gang Yu"],"published":"2026-07-13T14:58:57Z","updated":"2026-07-13T14:58:57Z","abstract_url":"https://arxiv.org/abs/2607.11644v1","html_url":"https://arxiv.org/html/2607.11644v1","pdf_url":"https://arxiv.org/pdf/2607.11644v1.pdf","matched_keywords":["video"],"source_used":"html","source_text_chars":61310,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 video 相关；摘要显示其主要贡献为：This work explores the motion transfer from one video to another, which is crucial in animation for diverse characters. Previously, video motion transfer has been largely explored between human and human-like characters, enabling a lot of applications in digi...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:27+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11588v1","title":"FoundationGeo: Learning Spatial Pixel-Wise Fields for Monocular Metric Geometry","abstract":"We present FoundationGeo, a two-stage framework that explicitly bridges relative and metric prediction via spatial calibration and principled data design. Stage 1 learns a high-fidelity, affine-invariant geometry model by initializing with DINOv3 and training on a curated 10.2M-sample multi-domain corpus with complementary local-detail supervision, yielding sharp boundaries and strong cross-domain generalization. Stage 2 moves beyond global scaling by introducing lightweight pixel-wise calibration fields for metric estimation: a scale field for spatially varying metric alignment and a ray-direction correction field that mitigates directional bias in point-map geometry, together producing metrically consistent 3D point maps. Beyond model design, we identify camera intrinsic coverage, especially focal length distribution mismatch between training and test data, as a key bottleneck for zero-shot metric generalization: performance drops sharply when test intrinsics fall outside the training distribution. To address this, we synthesize additional training data across diverse focal lengths using a Blender-based data engine, repairing under-covered focal regimes and improving robustness under intrinsic shift. Extensive zero-shot evaluations across seven benchmarks show that FoundationGeo significantly strengthens cross-domain robustness, staying near the top across diverse domains while avoiding the sharp cross-domain performance drops observed in other methods. This consistency translates into the best overall performance, surpassing heavier baselines by over 5.2% on average.","authors":["Muxin Liu","Xiaoyang Lyu","Tianhe Ren","Peng Dai","Xiaoshan Wu","Zhiyue Zhang","Jiaqi Zhang","Jiehong Lin","Shaoshuai Shi","Xiaojuan Qi"],"published":"2026-07-13T14:10:01Z","updated":"2026-07-13T14:10:01Z","abstract_url":"https://arxiv.org/abs/2607.11588v1","html_url":"https://arxiv.org/html/2607.11588v1","pdf_url":"https://arxiv.org/pdf/2607.11588v1.pdf","matched_keywords":["3d"],"source_used":"html","source_text_chars":79048,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 3d 相关；摘要显示其主要贡献为：We present FoundationGeo, a two-stage framework that explicitly bridges relative and metric prediction via spatial calibration and principled data design. Stage 1 learns a high-fidelity, affine-invariant geometry model by initializing with DINOv3 and training...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:27+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11581v1","title":"Actor as Its Own Critic: Unifying Region Understanding and Localization via CycleGRPO","abstract":"This paper introduces Actor as Its Own Critic, a unified reinforcement learning framework, Cycle Group Relative Policy Optimization (CycleGRPO), that jointly optimizes region understanding and localization for Multimodal Large Language Models (MLLMs). Unlike existing separate pipelines, we leverage the inherent duality between the two tasks to construct a self-evaluating reinforcement learning paradigm: \"region $\\to$ text $\\to$ region''. Specifically, a single MLLM first acts as the actor to generate region captions, then immediately transitions to a critic to ground its generated text back in the spatial domain. Therefore, CycleGRPO requires only region inputs, e.g., masks or bounding boxes, entirely bypassing the need for textual ground truths. A quality-aware token-level cycle-consistency reward is employed to assess the semantic discriminability of text captions via their physical localization accuracy. Empirically, built upon SAMTok, our CycleGRPO framework successfully bootstraps both capabilities simultaneously. Without any task-specific fine-tuning, the framework yields consistent performance gains across a wide range of benchmarks, including region captioning, region VQA, grounded dialogue, and referring segmentation. Overall, CycleGRPO offers a straightforward and scalable way to advance pixel-level capabilities in MLLMs. Code and models are released at https://github.com/devinxzhang/CycleGRPO.","authors":["Xin Zhang","Haochen Wang","Yikang Zhou","Jason Li","Robby T. Tan"],"published":"2026-07-13T14:00:57Z","updated":"2026-07-13T14:00:57Z","abstract_url":"https://arxiv.org/abs/2607.11581v1","html_url":"https://arxiv.org/html/2607.11581v1","pdf_url":"https://arxiv.org/pdf/2607.11581v1.pdf","matched_keywords":["multimodal"],"source_used":"html","source_text_chars":60107,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 multimodal 相关；摘要显示其主要贡献为：This paper introduces Actor as Its Own Critic, a unified reinforcement learning framework, Cycle Group Relative Policy Optimization (CycleGRPO), that jointly optimizes region understanding and localization for Multimodal Large Language Models (MLLMs). Unlike...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:27+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11578v1","title":"DiffEEG: A Self-Supervised Denoising Diffusion Model for Learning EEG Generic Representations","abstract":"Deep learning for EEG-based seizure detection faces critical challenges: severe annotation scarcity and extreme class imbalance, where ictal events comprise less than 10\\% of clinical recordings. We present DiffEEG, a 9.6M-parameter self-supervised foundation model that addresses both limitations through denoising diffusion pre-training and reinforcement learning (RL)-based fine-tuning. Pre-trained on 1.3M unlabeled segments from the Temple University Hospital Seizure Corpus (TUHSZ), DiffEEG learns generic neural representations via a 1D U-Net with multi-head self-attention. For downstream adaptation, a reinforced decision layer employs policy gradient optimization to directly maximize F1-score, prioritizing sensitivity to rare seizure events over overall accuracy. Under strict patient-wise evaluation (279 patients, Leave-One-Fold-Out), DiffEEG achieves 61\\% accuracy and 59\\% F1 for 4-class seizure subtyping, and 81\\% accuracy with 85\\% weighted F1 for binary detection, maintaining clinically viable seizure recall (59\\%) despite extreme imbalance (6.7\\% prevalence). Segment-level evaluation establishes an upper bound of 97.6\\% accuracy, confirming strong architectural capacity. DiffEEG demonstrates that diffusion-based pre-training combined with metric-aware reinforcement learning enables clinically deployable seizure monitoring with minimal labeled data requirements.","authors":["Abdulkader Helwan","Lina Abou-Abbas","Hussein El Amouri","Belkacem Chikhaoui","Khadidja Henni"],"published":"2026-07-13T13:59:45Z","updated":"2026-07-13T13:59:45Z","abstract_url":"https://arxiv.org/abs/2607.11578v1","html_url":"https://arxiv.org/html/2607.11578v1","pdf_url":"https://arxiv.org/pdf/2607.11578v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"html","source_text_chars":66723,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation, diffusion 相关；摘要显示其主要贡献为：Deep learning for EEG-based seizure detection faces critical challenges: severe annotation scarcity and extreme class imbalance, where ictal events comprise less than 10\\% of clinical recordings. We present DiffEEG, a 9.6M-parameter self-supervised foundation...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:27+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11562v1","title":"MonkeyOCRv2: A Visual-Text Foundation Model for Document AI","abstract":"Mainstream visual encoders are pretrained on natural images and cannot be effectively applied to document images without document-oriented adaptation, as dense text and fine-grained character strokes demand character-level visual perception. We present MonkeyOCRv2, a visual-text pretrained model for document AI. First, we construct MonkeyDoc v2, to our knowledge the largest document-image pretraining corpus, comprising 113 million images spanning 17 languages. Second, we propose a pretraining strategy that jointly learns image-to-text generation and pixel-level document reconstruction: the former aligns visual representations with textual content, while the latter preserves character strokes and layout details. Extensive experiments are conducted on five representative document analysis tasks, including text recognition, formula recognition, text detection, document tampering detection, and overlapping text segmentation. Replacing the original encoders with MonkeyOCRv2 consistently improves performance across all five tasks. Finally, we validate its effectiveness as the vision encoder of multimodal large language models on the more challenging tasks of document parsing and document understanding. Kept frozen and paired with a lightweight language model, it yields a 0.7B document parsing model that sets a new open-source state-of-the-art on MDPBench, a recent benchmark spanning digital-born and photographed documents across 17 languages, surpassing the previous best 3B dots.mocr by 2.8% absolute with a vision encoder roughly 11$\\times$ smaller. The frozen encoder also powers a document understanding model that outperforms counterparts built on CLIP, DINO, and SAM across eight benchmarks under identical training settings. These results suggest that document-oriented visual pretraining can serve as a foundation for document intelligence in its own right.","authors":["Yuliang Liu","Zhang Li","Ziyang Zhang","Shuo Zhang","Qiang Liu","Jiajun Song","Zidun Guo","Xinhan Wang","Handong Zheng","Yang Liu","Dongliang Luo","Zhiyin Ma","Jiarui Zhang","Xiang Bai"],"published":"2026-07-13T13:43:39Z","updated":"2026-07-13T13:43:39Z","abstract_url":"https://arxiv.org/abs/2607.11562v1","html_url":"https://arxiv.org/html/2607.11562v1","pdf_url":"https://arxiv.org/pdf/2607.11562v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"html","source_text_chars":124148,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 representation, multimodal 相关；摘要显示其主要贡献为：Mainstream visual encoders are pretrained on natural images and cannot be effectively applied to document images without document-oriented adaptation, as dense text and fine-grained character strokes demand character-level visual perception. We present Monkey...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:27+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11560v1","title":"Technical Report on the CVPR 2026@AdvML Workshop Challenge","abstract":"Vision-language agents (VLAs) are increasingly used to interpret complex driving scenes and support safety-critical reasoning. This report presents the CVPR 2026@AdvML Workshop Challenge on adversarial multimodal attacks against autonomous-driving VLAs. Built on DriveLM-style multi-view visual question answering, the challenge represents each scene with six synchronized camera images and a structured collection of driving-related question-answer pairs. Participants generate adversarial images and suffix-only textual perturbations that induce model responses to deviate from reference answers while preserving image fidelity and limiting textual cost. The competition comprises two phases, with Phase II adding a hidden black-box model to assess transferability. We describe the task design, submission rules, evaluation protocol, and leaderboard results, and then examine five leading submissions for which technical reports were available. Across these reports, several recurring patterns emerge: image-side attacks are favored by the suffix penalty; scene-level, multi-view optimization is more effective than treating views in isolation; QA types and graph structure provide useful priors for allocating attack budget; feature-space objectives can improve black-box transfer; and typographic content embedded in camera images exposes a persistent vulnerability in driving VLAs. These findings provide a practical reference for future robustness evaluation and defense design in multimodal autonomous-driving systems.","authors":["Tianyuan Zhang","Zonglei Jing","Jiangfan Liu","Ligong Zhang","Ke Ma","Chengzhi Sun","Xiaohai Xu","Zhirui Zhang","Qianqian Xu","Qingming Huang","Hanyu Fang","Junhua Liu","Zheng Wang","Xiaoliang Liu","Yuanbo Li","Shuai Gui","Bin Wang","Menghe Zheng","Jing Nie","Hanyang Meng","Zeyang Zhang","Xiang Zhang","Yongxuan Zhu","Rui Ding","Hainan Li","Yongkang Zhang","Zhilei Zhu","Xianglong Kong","Jin Hu","Zonghao Ying","Yisong Xiao","Lei Chen","Haotong Qin","Jiakai Wang","Aishan Liu","Ruikai Li","Julia Karbing","Yinpeng Dong","Zhenfei Yin","Shao Jing","Xia Hu","Jingyi Xu","Juntao Dai","Xinyun Chen","Vishal M. Patel","Xianglong Liu","Dawn Song","Alan Yuille","Philip H. S. Torr","Dacheng Tao"],"published":"2026-07-13T13:42:48Z","updated":"2026-07-13T13:42:48Z","abstract_url":"https://arxiv.org/abs/2607.11560v1","html_url":"https://arxiv.org/html/2607.11560v1","pdf_url":"https://arxiv.org/pdf/2607.11560v1.pdf","matched_keywords":["agent","multimodal"],"source_used":"html","source_text_chars":107204,"summary":{"model":"fallback-no-api","core_contribution":"该论文与 agent, multimodal 相关；摘要显示其主要贡献为：Vision-language agents (VLAs) are increasingly used to interpret complex driving scenes and support safety-critical reasoning. This report presents the CVPR 2026@AdvML Workshop Challenge on adversarial multimodal attacks against autonomous-driving VLAs. Built...","method":"未配置 OPENAI_API_KEY，方法细节未调用模型总结。","source_used":"html","created_at":"2026-07-14T03:53:27+00:00","status":"fallback"},"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11548v1","title":"Training-Free Off-Screen Player Imputation for Broadcast-Based Spatial Football Analytics","abstract":"Spatial football metrics such as pitch control assume access to the positions of all 22 players, yet the most widely available source of positional data -- the broadcast main camera -- shows only 10-16 of them at any moment. We quantify the resulting distortion with an open, reproducible benchmark: a simulated broadcast viewport applied to open full-pitch tracking data (Metrica Sports; three matches, one held out from method development). Ignoring off-screen players -- the visible-only baseline implied whenever a video-based game-state-reconstruction (GSR) pipeline adds no imputation layer -- inflates hidden-zone pitch-control error to 25.1-26.9 percentage points and a mean absolute control-share error of 11.1-13.4 points across the three matches. We then evaluate a ladder of training-free, online imputation baselines that use only observations from the match being analysed. The best overall on these decision-relevant metrics, role-anchored centroid voting (each visible player votes for the full-team centroid by subtracting its running role offset, attenuating the viewport-induced subset bias), roughly halves hidden-zone error (to 12.2-13.8 points) and cuts control-share error to 28-48% of the ignore policy at every viewport width from 36 m to 60 m in all three matches. For occlusions <=9.6 s -- the regime of the closest learned prior work -- it reaches binwise median position errors of 3.3-8.9 m; but 50-57% of hidden-player observations lie beyond that regime. Integrated end-to-end into a broadcast-video GSR pipeline, imputation moves a downstream possession-quality score (Space-Creation Index) by 15.6 and 17.2 points on two real World Cup broadcast windows, flipping the verdict class in one.","authors":["Seongjin Choi"],"published":"2026-07-13T13:33:45Z","updated":"2026-07-13T13:33:45Z","abstract_url":"https://arxiv.org/abs/2607.11548v1","html_url":"https://arxiv.org/html/2607.11548v1","pdf_url":"https://arxiv.org/pdf/2607.11548v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11533v1","title":"Adaptive Routing for Efficient Diffusion Transformer-Based PNI Prediction","abstract":"Perineural invasion (PNI) is a critical prognostic factor in cholangiocarcinoma. However, its preoperative prediction from magnetic resonance imaging (MRI) remains challenging due to subtle imaging features that extend beyond tumor boundaries into surrounding regions. Conventional convolutional neural networks are limited in capturing long-range spatial dependencies. Transformer-based architectures improve global modeling of volumetric MRI by aggregating spatially distributed contextual cues, yet capturing subtle and noise-sensitive patterns in peritumoral regions remains challenging. Diffusion-based classifiers offer an alternative formulation by leveraging denoising-based class scoring to better capture such subtle patterns. However, these approaches introduce substantial computational overhead due to the combination of transformer-based modeling and iterative denoising processes. To address these challenges, we formulate PNI prediction as a diffusion-based classification problem and implement the denoising network using a transformer-based representation. To improve computational efficiency, we introduce adaptive routing across attention heads, spatial tokens, and MLP width. Experimental results demonstrate that the proposed approach achieves an AUC of 0.731 with 257.57 GFLOPs.","authors":["Youngung Han","Dohyun Kweon","Kyeonghun Kim","Hyunsu Go","Jina Jeong","Suah Park","Induk Um","Junga Kim","Anna Jung","Yului Jeong","Sungha Park","Jinyong Jun","Pa Hong","Woo Kyoung Jeong","Won Jae Lee","Ken Ying-Kai Liao","Hyuk-Jae Lee","Nam-Joon Kim"],"published":"2026-07-13T13:18:21Z","updated":"2026-07-13T13:18:21Z","abstract_url":"https://arxiv.org/abs/2607.11533v1","html_url":"https://arxiv.org/html/2607.11533v1","pdf_url":"https://arxiv.org/pdf/2607.11533v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11523v1","title":"Vinci2: Providing Proactive Assistance in Continuous Egocentric Videos","abstract":"When should an intelligent assistant speak up without being asked? Continuous egocentric video offers rich, evolving context that enables a new form of assistance: one that is proactive rather than merely reactive. Yet existing approaches either wait passively for user queries or treat every detected event as requiring a response, without considering the user's history, current activity, or whether assistance would actually be welcome. We reframe proactive assistance as a context-dependent decision problem: the agent must not only perceive what is happening, but reason over accumulated temporal context to determine when and whether to intervene. To this end, we present Vinci2, a proactive egocentric assistance system that advances the on-device assistant Vinci from reactive response toward proactivity. On the evaluation side, we present EgoServe, the first large-scale benchmark for proactive assistance in continuous egocentric video. EgoServe comprises over 3,000 service instances organized along 4 temporal memory horizons, ranging from immediate safety alerts to long-term habit coaching, across 10 service categories. On the modeling side, we propose EgoMemo, a training-free, memory-augmented agent that maintains three complementary memory representations: multi-scale temporal summaries, a semantic knowledge graph, and visual embedding archives. At each timestep, EgoMemo performs retrieval-augmented reasoning to determine whether assistance is warranted and, if so, produces contextually grounded responses. Experiments demonstrate that EgoMemo establishes strong baselines on EgoServe while remaining competitive on existing egocentric benchmarks. Our benchmark and code are publicly available at \\href{https://sitonggong.github.io/EgoServe-page/}{Vinci2}.","authors":["Gong Sitong","Tianyu Yan","Caixin Kang","Bo Zheng","Xiang Ruan","Huchuan Lu","Kaipeng Zhang","Yoichi Sato","Yifei Huang"],"published":"2026-07-13T13:09:45Z","updated":"2026-07-13T13:09:45Z","abstract_url":"https://arxiv.org/abs/2607.11523v1","html_url":"https://arxiv.org/html/2607.11523v1","pdf_url":"https://arxiv.org/pdf/2607.11523v1.pdf","matched_keywords":["video","retrieval","agent","representation","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11509v1","title":"CFR-Net:Collaborative Feature Refnement Network for Medical Image Anomaly Detection","abstract":"Medical image anomaly detection remains challenging because networks pretrained on natural images often exhibit limited adaptability to medical images, where abnormal patterns appear as fine-grained local shifts, multi-scale contextual mismatches, and orientation-sensitive structural deviations. To address this, we propose the Collaborative Feature Refinement Network (CFR-Net), which combines shared teacher-student feature refinement before decoding with cross-space consistency after decoding. CFR-Net refines frozen teacher features and trainable student features using a Multi-Path Feature Refinement Module (MPFRM) with shared parameters, imposing common multi-path refinement rules on generic visual references and representations adapted to the medical domain, thereby mitigating domain discrepancy while modeling local, multi-scale, and orientation-sensitive feature characteristics. A variance-sensitive objective and dynamic ``homework set'' reorganization further support layer-adaptive consistency learning. Experiments on medical benchmarks show that CFR-Net achieves competitive anomaly classification and strong anomaly localization performance when trained on normal data.","authors":["Zihan Nie","Muhao Xu","Wei Feng","Yuan Cui","Hua Wei","Sijie Niu","Yi Wan","Xunbin Wei","Weiye Song","Zongyuan Ge"],"published":"2026-07-13T12:59:21Z","updated":"2026-07-13T12:59:21Z","abstract_url":"https://arxiv.org/abs/2607.11509v1","html_url":"https://arxiv.org/html/2607.11509v1","pdf_url":"https://arxiv.org/pdf/2607.11509v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11500v1","title":"HyperGS: Fast and Generalizable Gaussian Video Representation","abstract":"Gaussian Splatting has emerged as an effective representation for video, but existing methods rely on per-video optimization. This leads to slow encoding and limits generalization across videos. To amortize this optimization, we propose HyperGS, a feedforward, optimization-free approach that directly predicts Gaussian representations from any video in a single forward pass, speeding up encoding and decoding by orders of magnitude while generalizing to out-of-distribution videos at higher resolutions. In HyperGS, we design a factorized spatiotemporal Transformer to extract tokens from video, and a learnable query-based Transformer to obtain 8-parameter Gaussian representations for each video frame. We find that naively predicting Gaussians across diverse videos induces a needle-like degeneration that collapses training, and address this with a rank-based geometric regularizer whose strength adapts dynamically to stabilize optimization. HyperGS achieves encoding at $10^4$--$10^5\\times$ the speed of per-video Gaussian optimization at matched reconstruction quality while generalizing zero-shot to $720p$ video, enabling higher-resolution rendering without re-encoding. HyperGS improves PSNR by +2.9--3.1 dB over the prior video encoders on K400, SSv2, and UCF101 at a smaller video representation size. By predicting explicit 2D Gaussians in a single forward pass, HyperGS combines the fast, flexible rendering of Gaussian Splatting with the speed and generalization of feedforward prediction, advancing Gaussians as a practical direction for fast and generalizable video representation.","authors":["Fatimah Zohra","Chen Zhao","Shuming Liu","Yahya Al Malallah","Bernard Ghanem"],"published":"2026-07-13T12:53:02Z","updated":"2026-07-13T12:53:02Z","abstract_url":"https://arxiv.org/abs/2607.11500v1","html_url":"https://arxiv.org/html/2607.11500v1","pdf_url":"https://arxiv.org/pdf/2607.11500v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11487v1","title":"LightMem-Ego: Your AI Memory for Everyday Life","abstract":"Personal AI assistants on mobile and wearable devices continuously perceive users' daily lives through visual and audio streams. However, answering queries about past experiences requires lightweight multimodal memory that can continuously accumulate, organize, and retrieve long-term experiences, which remains challenging. To address this challenge, we present LightMem-Ego, a lightweight streaming multimodal memory system for everyday-life assistance. The system continuously captures egocentric visual and audio streams, aligns them on a shared timeline, and organizes them into a hierarchical memory consisting of current, short-term, and long-term memory. Given a user query, LightMem-Ego dynamically routes retrieval to the appropriate memory level and generates answers grounded in multimodal evidence. The demonstration can be deployed on smartphones and AI glasses, supporting object finding, conversation recall, life summarization, routine discovery, and personalized assistance. Code is available at https://github.com/zjunlp/LightMem-Ego.","authors":["Yijun Chen","Boyi Xiao","Yixian Zhao","Haoting Xia","Buqiang Xu","Jizhan Fang","Yanya Li","Yaqi Zheng","Xuehai Wang","Zirui Xue","Liuxin Zhang","Hui Li","Ningyu Zhang"],"published":"2026-07-13T12:40:17Z","updated":"2026-07-13T12:40:17Z","abstract_url":"https://arxiv.org/abs/2607.11487v1","html_url":"https://arxiv.org/html/2607.11487v1","pdf_url":"https://arxiv.org/pdf/2607.11487v1.pdf","matched_keywords":["retrieval","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11434v1","title":"Direct Image-to-Modern Vietnamese Translation of Han-Nom Manuscripts via Multimodal RLHF Preference Alignment","abstract":"Translating Han-Nom manuscripts into modern Vietnamese is challenging because historical pages are often degraded, the script contains rare logographic characters, and parallel supervision is limited. We propose a multimodal RLHF preference-alignment framework that conditions Vietnamese generation on manuscript images and aligned Han-Nom source text. The model combines four streams: CLIP ViT-L/14@336 for visual features, bert-base-chinese for Han-Nom representations, vinai/phobert-base for Vietnamese representations, and T5-small encoder states. Modality-specific projections and a fusion block compress the resulting 2,048-dimensional concatenation into a shared 512-dimensional representation. Starting from the same supervised fine-tuned policy, we compare PPO, DPO, and KTO under matched work-level macro-averaged evaluation. DPO achieves the best BLEU-4, ROUGE-L, BERTScore, semantic similarity, CER, WER, and token accuracy, whereas PPO obtains the highest precision, recall, and F1. KTO remains competitive through its desirable-undesirable utility objective. All preference-aligned policies improve the BLEU-4 and semantic-similarity scores available for the SFT baseline. These results indicate that multimodal preference optimization complements supervised learning by improving lexical and semantic quality in low-resource historical translation.","authors":["Thi Kim Trang Vo","Nghia Hieu Nguyen","Ha Minh Tan"],"published":"2026-07-13T11:40:45Z","updated":"2026-07-13T11:40:45Z","abstract_url":"https://arxiv.org/abs/2607.11434v1","html_url":"https://arxiv.org/html/2607.11434v1","pdf_url":"https://arxiv.org/pdf/2607.11434v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11419v1","title":"Video Transformer for Remote Identity Document Hologram Detection","abstract":"Remote identity authentification using Identification Documents has been a major challenge for several years. DeepFakes advent and the development of AI-guided tools helps fraudsters creating counterfeit ID Documents. Ensuring the authenticity of ID Documents has become a real clue in the seurization of remote authentification. This need is all the more pressing given the increasing digitization of administrative and transactional processes. To ensure widespread accessibility, the system should rely solely on video captured via mobile devices. In this specific context, confirming the authenticity of ID is a real challenge as many security features needs specific device like infrared sensor for instance. Among underutilized but promising security features, holographic printings hold a special place. Difficult to counterfeit, they produce distinctive visual effects according enlightment, making them both detectable in a video captured by a smartphone camera and difficult to imitate. In this paper, we propose a Remote Identity Document Verification System (RIDVS) and an approach based on a video transformer for detecting holograms in simple videos captured by smartphones. Our system is designed for a smartphone-based capture process, followed by a server-side verification. The hologram detection method builds on a robust model previously validated in a related research domain. We demonstrate that it outperforms existing SotA methods, achieving near-perfect accuracy even when trained on medium- to small-sized datasets. In particular, we report improvements of +26.86\\% in Recall and +17.93\\% in accuracy over the best MIDV-Holo baseline. This study includes several experiments that evaluate the model adaptation to frugality, both for training samples and computational resources.","authors":["Joris Voerman","Nicolas Sidere","Jean-Christophe Burie"],"published":"2026-07-13T11:24:54Z","updated":"2026-07-13T11:24:54Z","abstract_url":"https://arxiv.org/abs/2607.11419v1","html_url":"https://arxiv.org/html/2607.11419v1","pdf_url":"https://arxiv.org/pdf/2607.11419v1.pdf","matched_keywords":["video","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11385v1","title":"Diffusion MRI preprocessing affects ADC estimation and automatic PI-RADS v2.1 classification in bi-parametric prostate MRI","abstract":"Diffusion-weighted imaging (DWI) is acquired as part of bi-parametric prostate MRI, but suffers from artifacts that degrade downstream quantitative and diagnostic performance. While DWI preprocessing is standard in brain imaging, its adoption in prostate imaging remains limited and lacks standardized pipelines. This study investigated the effect of different DWI preprocessing strategies on apparent diffusion coefficient (ADC) estimation and automatic Prostate Imaging Reporting and Data System (PI-RADS) classification. 268 cases were derived from the fastMRI prostate cohort by sequentially applying denoising, Gibbs-ringing correction, and diffeomorphic registration for susceptibility distortion correction. ADC maps were compared using linear least squares (LLS) and iteratively-weighted LLS (IWLLS). A 3-class DenseNet classifier was trained to predict PI-RADS scores from multi-channel MRI inputs. ADC analysis revealed statistically significant differences across preprocessing pipelines, with LLS and IWLLS producing numerically equivalent maps. Linear relationships between ADC values were preserved across most datasets (PCC ~0.99), while distortion correction realigned DWI to T2w anatomy and altered ADC values accordingly (PCC ~0.90). Classification showed the best AUROC and sensitivity for high-risk PI-RADS classes in the fully processed dataset. False-negative analysis revealed this dataset produced the least overconfident incorrect predictions on high-risk classes, which is a desirable property for clinical triage. DWI preprocessing, particularly distortion correction, enhances both ADC map quality and the predictive power of deep learning models for PI-RADS classification, supporting the need for optimized preprocessing pipelines in prostate MRI.","authors":["Christos Kanakis","Mathias Perslev","Tim Schakel","Silvia Ingala","Akshay Pai","Dennis Klomp","Chantal M. W. Tax"],"published":"2026-07-13T10:45:13Z","updated":"2026-07-13T10:45:13Z","abstract_url":"https://arxiv.org/abs/2607.11385v1","html_url":"https://arxiv.org/html/2607.11385v1","pdf_url":"https://arxiv.org/pdf/2607.11385v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11341v1","title":"The In-Car Sign Language Corpus (ICSL): A Multi-Modal Resource for Constrained-Space Sign Language Recognition","abstract":"This paper addresses the challenges of using sign language within shared mobility services, such as taxis, carpools, or ride-sharing platforms. The use of sign language recognition (SLR) in real-world, confined environments, specifically vehicle interiors remains largely unexplored. To motivate research in this area, we present the In-Car Sign Language (ICSL) dataset for Brazilian Sign Language (Libras), with the long-term goal of improving public transport accessibility for the Deaf and Hard-of-Hearing community. The dataset consists of: (1) high-precision laboratory motion capture (MoCap) data to establish an idealized linguistic baseline and (2) real-world multi-modal in-car recordings captured using a 2D camera and 3D Time-of-Flight sensors. The dataset provides a basis for comparative analyses between synthesized signing avatar animations and recorded real signing interpreter videos, which enable future research into robust \"in-the-wild\" SLR models and domain adaptation. We describe in detail the use cases, the setup, the data collection protocol, and the metadata structure of the corpus. In total, we recorded a multimodal dataset exceeding 1.5 million frames, comprising the synchronized multimodal streams described above featuring Libras users across various in-car scenarios. The corpus is provided with gloss annotation of lexical signs and non-lexical sign language elements specially designed to support the training and evaluation of deep neural networks for constrained space recognition. In-vehicle signing offers a technically significant example of a constrained, occluded, and non-frontal environment. While recognizing the diverse communication strategies already employed by the Deaf community, identifying automotive-specific limitations provides a useful stepping stone for research into enhancing in-car accessibility and passenger quality of life.","authors":["Raviteja Boddu","Guilherme Vieira Leite","Joed Lopes da Silva","Ângelo Benetti","Isabela Barbieri","Natália de Melo Afonso","Thyago Santos","Helio Pedrini","Felipe Venâncio Barbosa","José Mario De Martino","Munir Georges","Alessandro Zimmer"],"published":"2026-07-13T10:03:46Z","updated":"2026-07-13T10:03:46Z","abstract_url":"https://arxiv.org/abs/2607.11341v1","html_url":"https://arxiv.org/html/2607.11341v1","pdf_url":"https://arxiv.org/pdf/2607.11341v1.pdf","matched_keywords":["video","3d","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11312v1","title":"SLVMBench: Skill Learning from Video Memory","abstract":"We introduce Skill Learning from Video Memory (SLVMBench), the first benchmark that jointly evaluates whether video large language models (video-LLMs) can learn skills from long video memory and apply them to real-time tasks. SLVMBench presents models with 2-3 hour video streams that contain a tutorial video embedded in a stream of arbitrary irrelevant videos, resembling real-world human learning practices. Video-LLMs are asked to apply the acquired skill to answer real-time questions about an ongoing video. Unlike long-video understanding benchmarks that emphasize passive comprehension and skill-learning benchmarks that rely on short, immediate demonstrations, SLVMBench tests the full pipeline of memorizing and extracting procedural knowledge, as well as transferring it to real-time tasks. Moreover, rigorous human annotations feature sub-second-level temporal calibration, manually engineered questions eliminating common-sense guessing, and collated tutorials to ensure coverage of the required skills. Evaluations on state-of-the-art proprietary and open-source video LLMs show that video-LLMs struggle substantially with learning and applying skill knowledge from videos. Moreover, performance degrades markedly when the skill knowledge is placed within a long video memory. These results reveal a key limitation of existing video LLMs and position SLVMBench as the first benchmark for studying real-time skill acquisition and application from long-context video memory.","authors":["Yudong Yang","Guangzhi Sun","Yixuan Li","Chao Zhang"],"published":"2026-07-13T09:26:13Z","updated":"2026-07-13T09:26:13Z","abstract_url":"https://arxiv.org/abs/2607.11312v1","html_url":"https://arxiv.org/html/2607.11312v1","pdf_url":"https://arxiv.org/pdf/2607.11312v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11295v1","title":"Metadata Supervised MRI Representations for Modelling and Controlling Acquisition Variability","abstract":"Magnetic resonance imaging exhibits substantial acquisition variability, where identical anatomy can appear markedly different across scanners and imaging protocols. Consequently, learned representations entangle biological structure with acquisition-dependent appearance, limiting interpretability, generalisation, and clinical deployment. We show that these sources of variation can be separated by jointly modelling MRI images and DICOM metadata. Using large-scale clinical brain MRI data, we learn representations that separate anatomical structure from contrast-dependent appearance. Resulting contrast representations organise heterogeneous acquisitions, support sequence understanding, and detect image--metadata inconsistencies, whereas anatomical representations suppress acquisition-specific variation while preserving biologically relevant information. Building on these disentangled representations, we introduce a unified anatomy-preserving harmonisation model for cross-modality and cross-site adaptation, conditioned on image or acquisition metadata. Our findings suggest that acquisition variability is a structured component of the imaging process that can be modelled, audited, and controlled, providing a foundation for acquisition-aware representation learning in large-scale medical imaging.","authors":["Mehmet Yigit Avci","Pedro Borges","Virginia Fernandez","Natalia Glazman","Paul Wright","Mehmet Yigitsoy","Sebastien Ourselin","Jorge Cardoso"],"published":"2026-07-13T09:12:23Z","updated":"2026-07-13T09:12:23Z","abstract_url":"https://arxiv.org/abs/2607.11295v1","html_url":"https://arxiv.org/html/2607.11295v1","pdf_url":"https://arxiv.org/pdf/2607.11295v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11285v1","title":"SalientGS: Unified SfM-to-3DGS with Importance-Guided MCMC Gaussian Allocation","abstract":"Reconstructing 3D scenes from unordered images remains bottlenecked by expensive Structure-from-Motion (SfM) preprocessing and frozen pose interfaces. We present SalientGS, a unified SfM-to-3D Gaussian Splatting (3DGS) pipeline. Its central contribution is importance-guided Markov Chain Monte Carlo (MCMC) Gaussian allocation, which aggregates multi-view residuals into per-Gaussian underfit and redundancy signals. These signals define a smooth importance-weighted sampling distribution that biases both birth and relocation toward underfit regions. This reallocates capacity from well-fit areas without altering the underlying stochastic gradient Langevin dynamics (SGLD). SalientGS achieves end-to-end reconstruction in 15 minutes with state-of-the-art perceptual quality. The supplementary material provides dedicated sections for Per-Scene Qualitative Comparisons and Per-Image Learned Perceptual Image Patch Similarity (LPIPS) Analysis, including failure cases. Code and evaluation scripts are available at https://github.com/Six-Bit-TX/SalientGS.","authors":["Tianyu Xiong","Rui Li","Suning Ge","Jiaqi Yang"],"published":"2026-07-13T09:06:49Z","updated":"2026-07-13T09:06:49Z","abstract_url":"https://arxiv.org/abs/2607.11285v1","html_url":"https://arxiv.org/html/2607.11285v1","pdf_url":"https://arxiv.org/pdf/2607.11285v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11281v1","title":"The Devil Is in the Leakage: A Disentangled Dual-Purification Framework for High-Fidelity Hairstyle Transfer","abstract":"Hairstyle transfer aims to synthesize a photorealistic portrait by transplanting the hairstyle from a reference image onto a source subject while preserving the source identity. Recent foundation models show strong generative capability, but they struggle with the zero-shot disentanglement required for precise local editing, often entangling the reference hairstyle with its original identity and pose. Existing diffusion-based pipelines typically decompose the task by first generating a \"bald\" image from the source and then injecting hairstyle features from the reference. However, we show that this paradigm suffers from a fundamental leakage problem. Identity Leakage in Hairstyle occurs when hairstyle features retain reference identity or pose information, while Flaw Leakage in Bald arises when residual artifacts in the bald image are propagated into the final synthesis. To address both issues, we propose the Dual-Purification Framework (DPF), which introduces two complementary training-time regularizers. Adversarial Hairstyle Purification (AHP) purifies hairstyle features by suppressing identity predictability under a mutual-information-inspired adversarial objective. Contrastive Geometric Purification (CGP) regularizes the ControlNet pathway with a contrastive objective, reducing the model's reliance on geometric artifacts in the bald condition. By jointly purifying the hairstyle representation and geometric pathway, DPF achieves high-fidelity, identity-preserving hairstyle transfer and state-of-the-art performance on diverse benchmarks.","authors":["Jijie Li","Jiankuo Zhao","Xiangyu Zhu","Zhen Lei"],"published":"2026-07-13T09:00:42Z","updated":"2026-07-13T09:00:42Z","abstract_url":"https://arxiv.org/abs/2607.11281v1","html_url":"https://arxiv.org/html/2607.11281v1","pdf_url":"https://arxiv.org/pdf/2607.11281v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11257v1","title":"LaGuadia: Language-Guided Adaptive Distillation from Pathology Foundation Models","abstract":"Pathology Foundation Models (PFMs) offer powerful Whole Slide Image (WSI) representations but suffer from massive computational costs. While Knowledge Distillation (KD) can create efficient student models, existing multi-teacher methods often use suboptimal uniform weighting that ignores tissue heterogeneity. We propose LaGuadia (Language-Guided Adaptive DistillAtion), a framework that develops a compact pathology image encoder by dynamically integrating expertise from multiple PFMs under clinical linguistic guidance. Our approach utilizes a multi-stage pipeline: first, extracting visually observable clinical keywords from pathology reports; second, aligning visual features with these keywords via a Vision-Language meta-teacher (MedSigLIP) to provide dense semantic guidance; and finally, performing adaptive KD where teacher contributions are weighted based on their semantic alignment with the clinical narrative. Experiments on WSI captioning, visual question answering, and slide-level classification tasks demonstrate that an 87M parameter LaGuadia student model matches or exceeds foundation-scale models such as GigaPath and UNI, achieving strong factual consistency and robust generalization. These results highlight clinical language as an effective semantic anchor for building efficient and reliable digital pathology systems. Code is available at https://github.com/hvcl/LaGuadia.","authors":["Gangsu Kim","Won-Ki Jeong"],"published":"2026-07-13T08:38:21Z","updated":"2026-07-13T08:38:21Z","abstract_url":"https://arxiv.org/abs/2607.11257v1","html_url":"https://arxiv.org/html/2607.11257v1","pdf_url":"https://arxiv.org/pdf/2607.11257v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11233v1","title":"Structure-Detail Decoupled Autoregressive Generation for Fast and High-Fidelity Virtual Try-On","abstract":"Virtual try-on (VTON) is a bi-conditional image generation problem that requires not only accurate person preservation but also faithful garment deformation and detail synthesis. Diffusion-based VTON methods can jointly model these factors in a compressed latent space, but suffer from high-frequency detail loss due to inherent latent compression, even with costly multi-step denoising. Recent visual autoregressive (VAR) models offer a promising alternative for high-quality generation with faster inference, yet remain unexplored for VTON due to the lack of effective bi-conditioning mechanisms. To bridge this gap, we first introduce VAR-VTON, a VAR-based VTON model that incorporates garment conditioning and structural guidance for efficient latent-space VTON. Despite its efficacy, latent-space generation still struggles to preserve fine-grained garment details. We argue that different VTON sub-tasks should be addressed in different representation spaces: structural synthesis such as garment warping and person layout is suited to the latent space, whereas fine-grained detail recovery should be tackled in the pixel space. Motivated by this insight, we further propose STAR-VTON, a Two-Stage AutoRegressive framework that builds upon VAR-VTON by decoupling latent-space structural synthesis from pixel-space detail recovery. Our idea is to resort to a matching-informed refiner to establish dense correspondences between the stage-one generation and the source garment to directly map fine-grained pixel-space details. Extensive experiments show that STAR-VTON achieves an impressive efficiency-fidelity trade-off: VAR-VTON runs at least $4\\times$ faster than diffusion-based counterparts without degrading quality, and the pixel-space refiner effectively restores fine details and acts as a plug-and-play module that can benefit existing VTON approaches.","authors":["Lu Yang","Xiaonan Hu","Yanan Li","Daqi Liu","Xiang Bai","Hao Lu"],"published":"2026-07-13T08:21:43Z","updated":"2026-07-13T08:21:43Z","abstract_url":"https://arxiv.org/abs/2607.11233v1","html_url":"https://arxiv.org/html/2607.11233v1","pdf_url":"https://arxiv.org/pdf/2607.11233v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11221v1","title":"HandFlow: Fully Generative 4D Hand Recovery with Flow Matching","abstract":"Accurate monocular 4D hand reconstruction remains challenging. Per-frame discriminative regressors lack temporal context and often produce jittery predictions. Temporal models improve consistency by aggregating information across frames, but they are typically deterministic regressors, making them vulnerable to ambiguous observations caused by occlusion and motion blur. Generative modeling offers a natural alternative by learning a prior over plausible hand motion sequences, enabling coherent hand-state recovery when visual evidence is incomplete or unreliable. Motivated by this observation, we present HandFlow, a fully generative flow-matching framework for temporally coherent 3D hand pose and shape estimation from monocular video. Given visual and skeletal observations, HandFlow denoises an entire temporal window of MANO parameters through a single ODE integration. To support this, we use a Flux-style dual-stream transformer that attends across the full sequence to capture long-range dependencies without autoregressive decoding, and a confidence-aware continuous masking mechanism that blends observed features with learnable mask tokens to handle noisy or missing observations. Experiments on DexYCB and HOT3D show that HandFlow achieves state-of-the-art performance, with particularly large gains in world-space accuracy and temporal smoothness. It reduces world-space pose error by over 30% compared with the strongest baseline and achieves the lowest acceleration error among all evaluated methods, while remaining competitive in per-frame pose accuracy. Moreover, on a single GPU HandFlow reconstructs a 150-frame sequence at 47 fps, about 12x faster than the fastest prior video-based method, with reconstruction itself accounting for only a small fraction of the end-to-end latency.","authors":["Mingxi Xu","Bowen Duan","Yi Gu","Zhengyang Shen","Renjing Xu","Yutao Yue"],"published":"2026-07-13T08:13:42Z","updated":"2026-07-13T08:13:42Z","abstract_url":"https://arxiv.org/abs/2607.11221v1","html_url":"https://arxiv.org/html/2607.11221v1","pdf_url":"https://arxiv.org/pdf/2607.11221v1.pdf","matched_keywords":["video","3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11199v1","title":"DynEval: Holistic Evaluations of T2I Generative Models in the Wild","abstract":"Recent advances in text-to-image (T2I) generation have led to models capable of producing highly realistic images. Yet, reliably evaluating their outputs remains challenging, especially at scale. Existing automatic evaluators, often relying on a static prompt set, struggle to capture subtle failure modes such as partial prompt misalignment, compositional errors, or visually plausible but semantically incorrect generations. In this work, we introduce DynEval, a Dynamic Evaluation framework designed to jointly assess text-to-image alignment and image quality of T2I models. To support scalable training beyond limited human-annotated data, we construct two large datasets. First, we build GenDB, a collection of 500K prompt-image pairs generated from human-written prompts drawn from DiffusionDB using a tiered prompt-model generation strategy. Second, building upon GenDB, we construct DynEvalInstruct, a 250K instruction dataset comprising prompt-image-response triplets distilled from a structured evaluation pipeline that decomposes evaluation into text-image alignment and visual quality reasoning. Using this dataset, we perform full fine-tuning of a compact evaluator through a curriculum learning strategy to effectively distill the superior evaluation capabilities of a larger teacher vision-language model, resulting in DynEval-2B and DynEval-4B. In extensive comparisons against existing evaluators across 11 benchmarks, our evaluator achieves a higher overall correlation with human judgments. Furthermore, it provides fine-grained analysis of the capabilities and failure modes of 36 T2I models across 42 subcategories and 9 semantic dimensions.","authors":["Shyam Marjit","Dheeraj Baiju","Anuj Shikarkhane","Akhil Sakthieswaran","Sayak Paul","Anirban Chakraborty"],"published":"2026-07-13T07:50:54Z","updated":"2026-07-13T07:50:54Z","abstract_url":"https://arxiv.org/abs/2607.11199v1","html_url":"https://arxiv.org/html/2607.11199v1","pdf_url":"https://arxiv.org/pdf/2607.11199v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11196v1","title":"Slot-RAE: Streamlining Object-Centric Learning via Direct Representation Auto-Encoders","abstract":"Deploying object-centric models for real-world scene understanding typically requires complex pipelines to achieve both robust scene decomposition and high-fidelity generation. Recent diffusion-based approaches have improved visual quality, but they almost universally rely on heavy, pretrained generative priors (e.g., Stable Diffusion) and external VAE latent spaces. In this paper, we propose Slot-RAE, a much simpler, fully integrated framework that operates directly within the continuous semantic feature space of visual foundation models (e.g., DINOv3). Slot-RAE employs a feature-space diffusion process using a Diffusion Transformer (DiT) decoder and a Representation Alignment (REPA) head. Unlike existing diffusion-based objectcentric methods that rely heavily on subsidized text-toimage priors, the generative core of Slot-RAE (Slot Attention and the DiT) is trained from scratch within the frozen VFM feature space. This eliminates the need for VAE bottlenecks and task-agnostic generative pre-training. Experiments on the COCO dataset demonstrate that despite its architectural simplicity, Slot-RAE achieves state-of-the-art results. It delivers comparable unsupervised object discovery, higher-fidelity image reconstruction, and robust zero-shot compositionality, all while being significantly faster and more computationally efficient than existing object-centric latent diffusion models.","authors":["Alexandre Chapin","Emmanuel Dellandrea","Liming Chen"],"published":"2026-07-13T07:47:09Z","updated":"2026-07-13T07:47:09Z","abstract_url":"https://arxiv.org/abs/2607.11196v1","html_url":"https://arxiv.org/html/2607.11196v1","pdf_url":"https://arxiv.org/pdf/2607.11196v1.pdf","matched_keywords":["representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11192v1","title":"GDP.pdf: Benchmarking Grounded Multimodal Reasoning over Professional PDF Documents","abstract":"A large share of day-to-day work in professional domains happens inside PDF files: benefits packets, leases, datasheets, clinical guidelines, construction plans. Benchmarks for document AI have generally measured the required capabilities in isolation: OCR, layout analysis, chart reasoning, table QA, document VQA. A high score on any one of them does not necessarily reveal whether a model can answer a realistic question that someone in the field would actually ask about a specific PDF. GDP.pdf is a benchmark built to measure this directly. It consists of question-document pairs authored by working professionals in ten fields, and a candidate question was kept only when at least two frontier multimodal models failed it in a way that mattered: a wrong answer, missed decisive evidence, or a fabricated claim, rather than a superficial difference such as style. Each item comes with a rubric of atomic criteria, so we can report a graded rubric score as well as a strict task-level pass rate, and each item is tagged against a taxonomy of eleven capabilities in three tiers, spanning text extraction and grounding, table and chart comprehension, cross-referencing, spatial reasoning, and abstention on unsupported queries. We evaluated seven frontier models on the 100-item benchmark. The best model passed only 15% of the items and the worst passed 1%. Most errors trace back to a small set of recurring loss patterns: misaligned tables, misread charts, skipped footnotes and exclusions, miscounted floor-plan symbols, scan noise, and amendments that supersede earlier text. The full 100-item benchmark is publicly available at https://huggingface.co/datasets/surgeai/GDP.pdf","authors":["Suhaas Garre","Emily Ritchie","Sushant Mehta","Edwin Chen"],"published":"2026-07-13T07:44:07Z","updated":"2026-07-13T07:44:07Z","abstract_url":"https://arxiv.org/abs/2607.11192v1","html_url":"https://arxiv.org/html/2607.11192v1","pdf_url":"https://arxiv.org/pdf/2607.11192v1.pdf","matched_keywords":["multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11173v1","title":"When Depth Is Better Told Than Shown: Depth-Ordinal Prompting for Vision-Language Spatial Reasoning","abstract":"Vision-language models (VLMs) are expected to reason about physical space -- which object is closer, what lies behind what, and how objects are arranged in 3D -- yet they still struggle with such spatial judgments. A natural remedy is to show the model a depth map, but we find that this can make performance worse. We show that depth is not absent: it reaches the language model, but becomes difficult to access for downstream reasoning, while rendered pseudo-depth maps act as noisy auxiliary images that frozen VLMs cannot easily regulate. We propose Depth-Ordinal Prompting (DOP), a training-free method that converts monocular depth into a single question-targeted ordinal text cue at the queried objects, without adding a depth image, training a module, injecting features, or using labels. Our key finding is form dependence: the same depth signal can hurt when shown as an image but help when told as text.Across benchmarks, models, and depth estimators, DOP improves spatial reasoning when pseudo-depth provides reliable object-level ordering and remains largely neutral in strong original-image regimes. It is also competitive with the strongest training-free depth-prompting alternative while being simpler and more targeted.","authors":["Quynh Vo","Phuc Dao","Cong-Duy Nguyen","Thong Nguyen"],"published":"2026-07-13T07:13:01Z","updated":"2026-07-13T07:13:01Z","abstract_url":"https://arxiv.org/abs/2607.11173v1","html_url":"https://arxiv.org/html/2607.11173v1","pdf_url":"https://arxiv.org/pdf/2607.11173v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11170v1","title":"TC-MAF: Train-Calibrated Bounded Multi-Evidence Fusion for Multimodal Industrial Anomaly Detection","abstract":"Multimodal anomaly detection benefits from complementary RGB and 3D evidence, yet auxiliary RGB reconstruction is not equally reliable across product categories and class-wise test-time policy selection is usually unavailable. We propose TC-MAF, a base-anchored multi-evidence fusion design that combines a multimodal detector, complementary Dinomaly evidence, and a small cross-modal consistency cue under one fixed pixel-level fusion formula. A lightweight training-dispersion confidence (TDC) term scales auxiliary participation using only normal training statistics. On MVTec-3D, TC-MAF reaches 0.979 image-level AUROC and 0.990 pixel-level AUPRO, achieving the best mean results on both detection and localization among the compared multimodal methods. Systematic ablations show that the fusion structure itself is the dominant factor, while TDC provides a smaller but reproducible calibration gain over no calibration or arbitrary calibration. Additional experiments show that the same design remains effective under a pooled-statistics variant, auxiliary-branch and backbone substitutions, few-shot settings, a missing-3D setting, and cross-dataset evaluation on Eyecandies. Code is available at https://anonymous.4open.science/r/TC_MAF-C3BB.","authors":["Ming Deng","Sijin Sun","Xiaochuan Hu","Xing Wu"],"published":"2026-07-13T07:07:54Z","updated":"2026-07-13T07:07:54Z","abstract_url":"https://arxiv.org/abs/2607.11170v1","html_url":"https://arxiv.org/html/2607.11170v1","pdf_url":"https://arxiv.org/pdf/2607.11170v1.pdf","matched_keywords":["3d","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11168v1","title":"SISA-Rec: A Semantically Integrated Sequential Recommender with Contrastive Alignment","abstract":"Recommendation systems help users recommend relevant items from a large collection of choices. Present work on transformer-based sequential recommendation learns user preferences from interaction logs, but it mostly focuses on item identifiers and doesn't fully use the semantic meaning of items. This limitation becomes a major challenge in sparse and cold-start scenarios where historical interaction data is limited. To solve this problem, we introduce SISA-Rec (Semantically Integrated Sequential Recommendation), a transformer-based framework that embeds semantic context directly into sequential modeling. Our approach fuses item ID embeddings with BERT-based text embeddings via a gated fusion module, injects semantic similarity into the self-attention mechanism, and leverages an attention-based aggregation module to construct comprehensive user representations. Finally, a joint learning objective which combines Bayesian Personalized Ranking (BPR) and contrastive alignment loss, aligns the underlying behavioral and semantic spaces. Experiments were conducted on the two highly sparse Amazon Beauty and Amazon Toys \\& Games datasets, both having 99.93\\% sparsity. The results show that SISA-Rec outperforms state-of-the-art baseline models across all evaluation metrics. Compared with the BERT4Rec \\cite{petrov2022systematic}, SISA-Rec improves HR@10 by 16.6\\% and NDCG@10 by 10.3\\% on Amazon Beauty, and HR@10 by 23.1\\% and NDCG@10 by 17.9\\% on Amazon Toys \\& Games. Cold-start analysis further shows that the proposed model achieves the largest improvements for users with limited interaction historical records. This showcases the value of semantic information when user behavior data is scarce. Overall, the results demonstrate that integrating semantic information into the attention mechanism leads to more accurate and reliable recommendations.","authors":["Soohan Abbasi","Shahid Munir Shah","Rafia Shaikh","Mahmoud Aljawarneh"],"published":"2026-07-13T07:03:51Z","updated":"2026-07-13T07:03:51Z","abstract_url":"https://arxiv.org/abs/2607.11168v1","html_url":"https://arxiv.org/html/2607.11168v1","pdf_url":"https://arxiv.org/pdf/2607.11168v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11120v1","title":"Simple Features and Honest Calibration for Ambivalence and Hesitancy Recognition in Video","abstract":"We address ambivalence and hesitancy (A/H) recognition in the ABAW 2026 BAH Challenge: given a short interview video, predict whether the person shows signs of A/H. Our system combines affect-specialised text, audio, and visual representations with a small set of readable linguistic hesitation cues, fused by a reliability gate we call Affective Marker Fusion (AMF), and finished with a simple AP-weighted ensemble at a fixed decision threshold. We also introduce \\emph{ASR-erased time}: speech recognisers delete fillers and hesitation pauses from the transcript, but the chunk timestamps keep the time those events took, and sixteen features built from these gaps form the strongest and most independent non-verbal channel we measured (AP $0.718$, correlation $0.11$--$0.36$ with all other members). Across controlled experiments we find three things: cross-modal conflict design does not reliably help on BAH; language is by far the strongest channel while affect-specialised audio is a useful second; and calibration matters more than architecture. Fitting ensemble weights and a threshold on the small validation split overfits: it scores $0.741$ macro-F1 on validation but only $0.690$ on the untouched test set. AP-weighting at a fixed threshold instead reaches $\\mathbf{0.731}$ on test.","authors":["Vikas Kumar","Aditya Mishra","Haroon R. Lone"],"published":"2026-07-13T05:52:40Z","updated":"2026-07-13T05:52:40Z","abstract_url":"https://arxiv.org/abs/2607.11120v1","html_url":"https://arxiv.org/html/2607.11120v1","pdf_url":"https://arxiv.org/pdf/2607.11120v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11118v1","title":"GHOST: Geometry-Guided Hallucination of Opaque Surface Textures","abstract":"Transparent objects pose a fundamental challenge for depth estimation and 3D reconstruction due to their violation of Lambertian assumptions, leading to severe geometry degradation in downstream tasks. To address this, we propose a novel geometry-guided preprocessing framework \\textbf{GHOST} that leverages visual foundation models to transform transparent regions into opaque, structurally consistent representations without requiring downstream model retraining. Specifically, our pipeline utilizes (1) \\textbf{TransDINO} and (2) \\textbf{TransDecomp} to disentangle masks and transparency physical properties, while (3) \\textbf{DAF-Net} recovers surface normal priors to encode geometric curvature. Subsequently, (4) \\textbf{GeoSemTransNet} integrates these multi-modal cues to synthesize a texture-rich opaque RGB image that preserves the transparent object's 3D structure. Extensive experiments demonstrate that our method significantly enhances the accuracy of state-of-the-art depth estimation and reconstruction models on transparent objects by restoring essential photometric cues.","authors":["Langxu Zhao","Zuan Gu","Tianhan Gao"],"published":"2026-07-13T05:50:19Z","updated":"2026-07-13T05:50:19Z","abstract_url":"https://arxiv.org/abs/2607.11118v1","html_url":"https://arxiv.org/html/2607.11118v1","pdf_url":"https://arxiv.org/pdf/2607.11118v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11106v1","title":"Beyond the Eye: Efficient Multimodal Reasoning via Self-Regulated Implicit Visual Tools","abstract":"Recent multimodal large language models (MLLMs) have made remarkable progress on fine-grained perception tasks under the \"Thinking with Images\" (TwI) paradigm by iteratively performing various visual tool operations. However, this paradigm relies heavily on frequent external tool calls and repeated image re-encoding, which leads to substantial computational overhead and inference latency. To address these issues, we propose Beyond the Eye (BEE), a novel implicit visual tool paradigm centered on self-regulated capability. BEE directly incorporates visual tool invocation behaviors into the training objective and encourages the model to develop a self-regulated invocation mechanism. This design enables the model to adaptively balance internal knowledge and implicit tools, avoiding redundant tool usage while substantially reducing inference latency. Specifically, BEE involves a two-stage training process: (1) Formalized Chain-of-Thought (CoT) Supervised Fine-tuning (SFT). We construct CoT trajectories with structured tool slots and mixed invocation states. This stage activates the model's implicit tool representations and adaptive switching capability. (2) Self-regulated Reward-Driven Alignment. To address redundant tool usage caused by ambiguous cognitive boundaries, we first introduce the Net Tool Gain (NTG) metric to quantify this phenomenon. Based on this observation, we further propose a self-regulated reward mechanism. This mechanism penalizes ineffective tool dependency and encourages the model to perform knowledge routing, ensuring that implicit tools are invoked only when the model's internal knowledge is insufficient. BEE achieves state-of-the-art performance in fine-grained visual perception while remaining competitive in general reasoning tasks and achieving substantial gains in inference efficiency.","authors":["Xiuwei Chen","Quanlin Chen","Wentao Hu","Zisheng Chen","Kun Xiang","Zehua Ma","Mingyang Zhang","Jianhua Han","Hanhui Li","Hang Xu","Xiaodan Liang"],"published":"2026-07-13T05:32:00Z","updated":"2026-07-13T05:32:00Z","abstract_url":"https://arxiv.org/abs/2607.11106v1","html_url":"https://arxiv.org/html/2607.11106v1","pdf_url":"https://arxiv.org/pdf/2607.11106v1.pdf","matched_keywords":["representation","multimodal"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11099v1","title":"Desc++: Efficient Descriptor Enhancement for Data Association in Existing Visual SLAM Systems","abstract":"Reliable visual data association is fundamental to visual SLAM (V-SLAM), as it directly determines the quality of the camera pose estimation and map consistency. However, the handcrafted descriptors used by most mature real-time systems degrade under illumination and viewpoint changes, while learning-based front-ends that address this weakness typically require replacing the extraction-and-matching pipeline and introduce substantial computational overhead. Descriptor enhancement offers a compromise by refining existing descriptors within their original format, yet current methods rely on simplified attention mechanisms whose limited contextual modeling constrains the achievable matching quality. To resolve this trade-off between contextual expressiveness and efficiency, we propose Desc++, a lightweight enhancement module that jointly encodes descriptor representations and keypoint geometry and aggregates spatial context through a hybrid architecture that combines order-agnostic global attention with geometry-aware sequential modeling in linear time. The enhanced descriptors retain their original dimensionality and matching interface, enabling integration into deployed V-SLAM systems without modifying the pipeline. Experiments across descriptor matching, correspondence analysis, and system-level benchmarks with four different V-SLAM systems demonstrate that Desc++ improves matching accuracy over the state-of-the-art enhancement method, translates these gains into more accurate and stable trajectory estimation, and achieves a favorable balance between accuracy and efficiency for practical integration into existing real-time V-SLAM pipelines.","authors":["Ting-Wei Ou","Huang-Ting Lin","Kuu-Young Young"],"published":"2026-07-13T05:15:13Z","updated":"2026-07-13T05:15:13Z","abstract_url":"https://arxiv.org/abs/2607.11099v1","html_url":"https://arxiv.org/html/2607.11099v1","pdf_url":"https://arxiv.org/pdf/2607.11099v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11097v1","title":"Revisiting Matching Response and Swept Feature Volumes for Wide-baseline Omnidirectional Stereo","abstract":"In this paper, we propose a training strategy for confidence estimation in omnidirectional stereo, targeting the ambiguous matches that frequently occur in wide-baseline setups. Reinterpreting the matching responses produced by the 3D encoder decoder block, we show that their expectation values provide intrinsic confidence signals. Building on this, our method directly penalizes ambiguous responses without auxiliary heads, multi-pass inference, or additional modules, resulting in more efficient and generalized predictions. Beyond confidence, we introduce swept feature volume resampling, where response features produced by 3D CNNs are resampled using regressed positive matching indices and then processed by 2D CNNs to predict meta-information such as surface normals. This joint learning introduces auxiliary geometric regularization and improves depth coherence by leveraging additional contextual cues during response aggregation stage. Experimental results demonstrate that our approach enhances both confidence estimation and surface normal prediction while maintaining deployment practicality for autonomous mobility applications.","authors":["Seungjin Jeon","Jongwoo Lim","Changhee Won"],"published":"2026-07-13T05:09:06Z","updated":"2026-07-13T05:09:06Z","abstract_url":"https://arxiv.org/abs/2607.11097v1","html_url":"https://arxiv.org/html/2607.11097v1","pdf_url":"https://arxiv.org/pdf/2607.11097v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11096v1","title":"Difference-Driven Gating: Adaptive Feature Fusion for U-Net Decoder","abstract":"The U-Net style models have been widely used in many applications. A critical step in these models is to reconstruct the lower-level features using a top-down decoder. This reconstruction requires precise fusion of high-level semantics and low-level details. Existing attention-based fusion methods typically derive attention weights from the top-down decoder features (global) alone or the correlation between the top-down decoder features and the bottom-up encoder features (local), then modulate the encoder features using these weights. In this work, we explore a different paradigm: deriving attention weights from the difference between the two feature streams. To this end, we propose two difference-based gating approaches: Feature-difference gating (FDG), which directly uses the absolute difference between global and local features to generate adaptive gating maps, and Entropy-difference gating (EDG), which measures the representational certainty of each stream via information entropy and uses their signed entropy difference to derive the attention weights. Both methods produce coupled gating maps that simultaneously modulate the global and local features. Experiments on different tasks including medical image segmentation, remote sensing image cloud removal and speech separation showed that both methods outperformed existing attention-based fusion methods, and EDG performed better. The results suggested a new paradigm for multi-scale feature fusion in the U-Net style structures.","authors":["Kai Li","Xuechao Zou","Jiashen Fu","Zijun Yan","Xintong Wang","Xiaolin Hu"],"published":"2026-07-13T05:06:35Z","updated":"2026-07-13T05:06:35Z","abstract_url":"https://arxiv.org/abs/2607.11096v1","html_url":"https://arxiv.org/html/2607.11096v1","pdf_url":"https://arxiv.org/pdf/2607.11096v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11081v1","title":"Controlling Motion Transfer in Diffusion Transformers via Attention Heads","abstract":"Diffusion Transformers (DiTs) have advanced video generation with high-quality, temporally coherent results. However, extending them to motion transfer, which requires following reference motion while aligning with a target prompt, remains challenging due to limited understanding of motion and structure representations within DiTs. We analyze video DiTs at the attention-head level and identify distinct heads specialized for motion and spatial structure. Based on this insight, we propose a head-aware controllable motion transfer framework that requires no parameter updates. Our method refines motion cues from motion-specialized heads via semantic correspondence guidance and preserves structure through selective feature injection. This head-level control not only enables accurate motion transfer but also provides an interpretable foundation for controllable video generation with DiTs.","authors":["Sunyoung Jung","Jiwoo Park","Yoonseok Choi","Kyobin Choo","Ming-Hsuan Yang","Seong Jae Hwang"],"published":"2026-07-13T04:44:14Z","updated":"2026-07-13T04:44:14Z","abstract_url":"https://arxiv.org/abs/2607.11081v1","html_url":"https://arxiv.org/html/2607.11081v1","pdf_url":"https://arxiv.org/pdf/2607.11081v1.pdf","matched_keywords":["video","representation","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11078v1","title":"Do Video-LLMs Actually Watch? Diagnosing Character-Tracking Failures in Long-Form Video","abstract":"Can a Video Large Language Model (Video-LLM) follow one person through a long video, keeping track of who they are well enough to report, in order, how their outfit changes across a full TV episode? Benchmarks increasingly score this kind of task, and the strongest open-source 7--8B models now reach 37--38% on InfiniBench's global appearance task, which asks exactly that. But does that score come from tracking the named character, or from something easier? We test this with a nine-condition diagnostic protocol applied to three architecturally distinct open-source Video-LLMs, with Gemini~2.5~Flash as a frontier reference, and find the accuracy does not come from character tracking. When we change the character named in the question to a different cast member, leaving the video and answer options untouched, the models change their answer only 4--31% of the time, so they are largely ignoring who the question asks about. Breaking that test down by the gender of the swapped name shows why: the models react more when the name is changed to a different-gender character than to a same-gender one (a 13--28 point gap), picking up coarse gender cues but unable to tell same-gender individuals apart. This shallow processing surfaces again when we drop the multiple-choice options and ask the same questions open-endedly: open-source accuracy drops 18--25 points, with none of 151 answers fully correct, versus a 12-point drop for Gemini. Further checks rule out the obvious innocent explanations, adding subtitles, using the most informative frames, or doubling the number of frames all leave character tracking unimproved, so the bottleneck is not how much video the model sees but how it ties that video to the person the question names. We release a diagnostic toolkit for auditing what such benchmark scores actually measure.","authors":["Mohammad Al-Ratrout","Shayla Sharmin","Aditya Raikwar","Roghayeh Leila Barmaki"],"published":"2026-07-13T04:37:07Z","updated":"2026-07-13T04:37:07Z","abstract_url":"https://arxiv.org/abs/2607.11078v1","html_url":"https://arxiv.org/html/2607.11078v1","pdf_url":"https://arxiv.org/pdf/2607.11078v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11071v1","title":"DDR-Net: Haze-Aware Dual-Domain Refinement for Single-Image Dehazing","abstract":"Single-image dehazing aims to recover clear scenes from haze-degraded images. It remains challenging due to the atmospheric scattering and the complexity of real-world haze distributions. Although recent end-to-end networks have achieved promising performance, two issues still limit their effectiveness: insufficient feature refinement at the bottleneck stage and weak local structural representation in encoder-decoder architectures. Thus, we propose a Haze-Aware Dual-Domain Refinement Network (DDR-Net) for single-image dehazing. Our method is built upon three modules: Haze Prior Extractor (HPE) provides multi-scale haze-aware priors by operating directly on downsampled hazy images; Detail-Enhanced Blocks (DE Blocks) serve as the core feature extraction units, capturing multi-scale structural information and enhancing edge and texture recovery via gradient-aware convolutions; and Spatial-Frequency Bottleneck Refinement (SFBR) at the bottleneck jointly exploits spatial and frequency information to refine bottleneck features. DDR-Net achieves more effective feature representation and reconstruction for haze removal. Extensive experiments on real-world benchmarks demonstrate that our method outperforms existing dehazing approaches. It achieves competitive performance on synthetic datasets.","authors":["Xinye Zheng","Ye Yu","Qiang Lu","Jinsheng Luo","Yiran Cui","Yongbin Cheng"],"published":"2026-07-13T04:20:22Z","updated":"2026-07-13T04:20:22Z","abstract_url":"https://arxiv.org/abs/2607.11071v1","html_url":"https://arxiv.org/html/2607.11071v1","pdf_url":"https://arxiv.org/pdf/2607.11071v1.pdf","matched_keywords":["representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11064v1","title":"WiFi-JEPA: Self-supervised Learning for WiFi-CSI 3D Human Pose Estimation","abstract":"WiFi Channel State Information (CSI) enables privacy-preserving human pose sensing in camera-denied environments, but existing WiFi-based pose estimators often fail under environment shifts and rely on costly camera-based annotation pipelines that limit scale. We propose WiFi-JEPA, a self-supervised framework that learns CSI-native representations by predicting masked latent embeddings instead of reconstructing raw CSI signals that may contain hardware-specific artifacts. WiFi-JEPA makes three contributions: (i) CSI-specific tokenization and link masking tailored to the CSI tensor over channel, time, and link (C,T,L); masking entire Tx-Rx antenna links forces the model to predict one spatial link view from others, capturing cross-link correlations informative of 3D spatial structure. (ii) A ray-tracing CSI simulation pipeline that generates diverse unlabeled CSI from randomized geometric primitives, providing scalable pre-training data without pose annotations. (iii) State-of-the-art results on Person-in-WiFi-3D: WiFi-JEPA outperforms prior WiFi-CSI baselines on both single- and multi-person 3D pose estimation under the same evaluation protocol. We also show that simulated CSI provides complementary pre-training signal to real CSI, and that four vision-native SSL objectives degrade performance below training from scratch, whereas WiFi-JEPA consistently improves downstream pose estimation.","authors":["Doeon Kim","Jungyoon Lee","Seongsin Kim","Seong-heum Kim"],"published":"2026-07-13T04:05:07Z","updated":"2026-07-13T04:05:07Z","abstract_url":"https://arxiv.org/abs/2607.11064v1","html_url":"https://arxiv.org/html/2607.11064v1","pdf_url":"https://arxiv.org/pdf/2607.11064v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11040v1","title":"FSFVE: Few Shot Compressed Face Video Enhancement","abstract":"Videocalling has become a popular form of communication in the world today, with many companies providing free services for it. However, there are still millions of people around the world that experience poor quality videocalls due to limitations in bandwidth. This despite, most people having the required hardware. In this paper we present a novel framework for enhancing highly compressed videocalls. We show, that with as little as 10 frames of the face, we can rapidly (in under 100 seconds) train a model to enhance that instance of the videocall. The model can be trained either prior to or during the call, enhancing the rest of the call by producing better quality video. The video conferencing application need not be modified - it can be off the shelf with our system as a layer on top that trains quickly then simply lets the video conferencing application (e.g. Zoom) run as usual, where our system intercepts and improves images before they are displayed. The model is designed to run in realtime on low-compute devices such as a typical laptop CPU. Experimentally, we show that the model significantly improves quality of compressed face video both quantitatively as well as perceptually. Code can be found at https://github.com/varun-jois/FSFVE.","authors":["Varun Ramesh Jois","Antonella DiLillo","James Storer"],"published":"2026-07-13T03:12:07Z","updated":"2026-07-13T03:12:07Z","abstract_url":"https://arxiv.org/abs/2607.11040v1","html_url":"https://arxiv.org/html/2607.11040v1","pdf_url":"https://arxiv.org/pdf/2607.11040v1.pdf","matched_keywords":["video","instance"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11034v1","title":"RTFVE: Realtime Face Video Enhancement","abstract":"There's been a surge in adoption of video conferencing applications for both personal and business use cases. However, the bandwidth limitations faced by many users worldwide may restrict the optimal use of such applications. Although deep learning offers a solution for enhancing low bit rate videos, most models today are either hard to incorporate with modern compression standards or require specialized hardware to run such as significant GPUs making these models impractical. To address these issues, we introduce the Realtime Face Video Enhancement (RTFVE) model which can be easily incorporated with any video decoder and can run in realtime on ordinary CPUs. Experiments show that our model improves perceptual quality over the compressed video baseline at multiple low bitrate settings. The source code will be made available at https://github.com/varun-jois/RTFVE.","authors":["Varun Ramesh Jois","Antonella DiLillo","James Storer"],"published":"2026-07-13T02:58:44Z","updated":"2026-07-13T02:58:44Z","abstract_url":"https://arxiv.org/abs/2607.11034v1","html_url":"https://arxiv.org/html/2607.11034v1","pdf_url":"https://arxiv.org/pdf/2607.11034v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.11029v1","title":"Learning to Navigate Efficiently with Only 0.58M Trainable Parameters","abstract":"Recent progress in visual navigation has largely been driven by scale: end-to-end policies with hundreds of millions of parameters trained on billions of frames or large-scale simulated data. We ask how much of this scale a single task family actually requires, and what structure can substitute for it. We propose a decomposed navigation model in which operations with known closed-form structure, such as projective geometry, occupancy, and coordinate transforms, are computed analytically and serve as interfaces between three small learned modules: an egress predictor that grounds the episode goal as a local subgoal in the current view, a navigation predictor that estimates a goal-conditioned posterior over where trajectories travel, and an endpoint-pinned residual diffusion generator that samples trajectory shapes from this posterior. The system trains only 0.58M out of a total of 22.7M parameters, on 44k frames in under one GPU-hour, yet approaches the performance of state-of-the-art models on navigation tasks across 6060 point-goal episodes and 60 environments, while having 233x fewer trainable parameters, the lowest collision rate among all evaluated methods, and 50 Hz inference speed. The decomposition further transfers to no-goal exploration by retraining only the 123k-parameter egress head, and its failure modes under sensor corruption are transparent and analytically correctable.","authors":["Edward Beng Wai Tan","Siew-Kei Lam"],"published":"2026-07-13T02:49:55Z","updated":"2026-07-13T02:49:55Z","abstract_url":"https://arxiv.org/abs/2607.11029v1","html_url":"https://arxiv.org/html/2607.11029v1","pdf_url":"https://arxiv.org/pdf/2607.11029v1.pdf","matched_keywords":["diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.10998v1","title":"Temporal Feature Distillation for Label-Efficient Precise Event Spotting in Sports Videos","abstract":"Precise Event Spotting (PES) requires distinguishing visually similar yet semantically distinct adjacent frames, making it fundamentally different from image classification and coarse action recognition. Although self-distillation methods such as DINO have shown strong representation learning ability in images, we find that directly applying them to PES is ineffective: without supervised guidance, subtle but crucial motion cues are often suppressed as noise, leading to representations that are insensitive to precise event boundaries. To address this, we propose Temporal Feature Distillation, a semi-supervised objective that aligns temporally informative backbone features, rather than projection-head outputs, to preserve motion-sensitive and boundary-aware cues for frame-level localization. A supervised warm-up with a ramp-up schedule further stabilizes training by ensuring that meaningful event cues are learned before unlabeled distillation begins. We also introduce Transformer Gate Shift, a multi-scale gated shifting module that injects motion-aware temporal information into Vision Transformers. Experiments on four fine-grained sports benchmarks show consistent improvements over fully supervised and semi-supervised baselines. Under 10\\% supervision on FSPerf, our method improves mAP by 4.54 points over the strongest competing approach, and with only 80\\% labeled data, it matches or surpasses the fully supervised 100\\% baseline on two of the four datasets.","authors":["Hao Xu","Xinyu Wei","Sam Wells","Sunil Aryal"],"published":"2026-07-13T01:53:46Z","updated":"2026-07-13T01:53:46Z","abstract_url":"https://arxiv.org/abs/2607.10998v1","html_url":"https://arxiv.org/html/2607.10998v1","pdf_url":"https://arxiv.org/pdf/2607.10998v1.pdf","matched_keywords":["video","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.10995v1","title":"AsySplat: Efficient Asymmetric 3D Gaussian Splatting for Long-Sequence Scene Modeling","abstract":"Recent generalizable 3D Gaussian Splatting models have advanced long-sequence novel view synthesis (NVS), but at the cost of substantial redundant computation. We identify that the redundancy can be mitigated based on two observations: (i) high-precision geometry is not strictly required for high-quality NVS; (ii) appearance learning is generally easier than geometry recovery. Motivated by these insights, we propose an asymmetric architecture that decouples geometry and appearance modeling. The geometry branch processes coarse-grained tokens with most of the parameters for multi-view reconstruction, while the appearance branch operates on fine-grained tokens to capture details using significantly fewer parameters. The two branches interact through bilateral connections, enabling mutual guidance for their respective tasks. This task-aware asymmetry reduces the computational redundancy and allocates the computation more judiciously, thereby increasing parameter efficiency and enabling smaller models to achieve strong performance. On 32-view 960P inputs, our model matches optimization-based methods while delivering nearly 800x speedup, and surpasses the zero-shot performance of state-of-the-art generalizable models with markedly fewer parameters and reduced training/inference overhead, achieving an overall efficiency improvement.","authors":["Yingji Zhong","Dave Zhenyu Chen","Fuzhao Ou","Youyu Chen","Zhihao Li","Lanqing Hong","Dan Xu"],"published":"2026-07-13T01:39:19Z","updated":"2026-07-13T01:39:19Z","abstract_url":"https://arxiv.org/abs/2607.10995v1","html_url":"https://arxiv.org/html/2607.10995v1","pdf_url":"https://arxiv.org/pdf/2607.10995v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.10992v1","title":"LoSA-Net: A Localized and Scale-Adaptive Network for Boundary-Sensitive Prediction of Perineural Invasion in 3D MRI","abstract":"Perineural invasion (PNI) is a clinically relevant indicator of tumor aggressiveness and can influence surgical decision-making, motivating interest in reliable preoperative assessment. The subtle MRI features of PNI, however, often resemble nearby anatomy, complicating noninvasive prediction. These fine perineural cues are easily attenuated by routine downsampling or overly global feature aggregation, reducing the effectiveness of conventional volumetric models. We present LoSA-Net, a localized and scale-adaptive architecture for boundary-sensitive PNI prediction in 3D MRI. Talking Neighborhood Attention (TNA) preserves nerve-aligned detail through localized self-attention with head-wise mixing, and Scale-Adaptive Feature Mixing (SAFM) modulates the receptive field using multi-scale depthwise processing. Cross-Scale Refinement and Alignment (CSRA) maintains consistency between semantic context and high-resolution boundaries across stages. In contrast-enhanced MRI scans from 168 patients with cholangiocarcinoma, LoSA-Net achieves an AUC of 0.7567 and outperforms representative convolutional and transformer baselines under matched preprocessing and optimization settings.","authors":["Youngung Han","Hyunsu Go","Kyeonghun Kim","Induk Um","Junga Kim","Jaewon Jung","Woo Kyoung Jeong","Won Jae Lee","Pa Hong","Ken Ying-Kai Liao","Hyuk-Jae Lee","Nam-Joon Kim"],"published":"2026-07-13T01:31:01Z","updated":"2026-07-13T01:31:01Z","abstract_url":"https://arxiv.org/abs/2607.10992v1","html_url":"https://arxiv.org/html/2607.10992v1","pdf_url":"https://arxiv.org/pdf/2607.10992v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.10991v1","title":"Think When It Matters: Conditional VLM Reasoning for Social Navigation with RL Policies","abstract":"As mobile robots become more integrated into everyday human environments, social robot navigation is becoming essential for ensuring human comfort, safety, and trust. While reinforcement learning (RL) navigation policies provide the fast inference and reactive behavior necessary for real-time deployment, they still lack flexible semantic reasoning capabilities and often fail to generalize to complex social scenarios. Recent approaches have increasingly turned to vision-language models (VLMs) in place of RL policies to improve semantic and social reasoning in robot navigation. Nevertheless, their high computational cost and slow inference remain major barriers to real-time deployment. To overcome these limitations, we introduce HUMA (Hybrid Understanding for Multi-modal social Navigation), a hybrid architecture that dynamically balances the computational efficiency of RL policies with the deep semantic understanding of VLMs. Our approach uses a reactive RL policy to handle low-density, routine navigation tasks, while conditioning it on a post-trained high-level VLM when a human enters sensitive situations, such as the robot's proximity zone. We evaluate HUMA on the Social-MP3D and Social-HM3D benchmarks, where it achieves task success improvements of 20% and 3%, respectively, while significantly reducing personal space violations and human collisions against state-of-the-art baselines. Extensive ablation studies validate each architectural component, and real-world deployment on the Mirokaï mobile robot further demonstrates the practical viability of our approach.","authors":["Ali Ahmadi","Hamed Rahimi","Adrien Jacquet Cretides","Marie Samson","Mahdi Khoramshahi","Mohamed Chetouani"],"published":"2026-07-13T01:27:27Z","updated":"2026-07-13T01:27:27Z","abstract_url":"https://arxiv.org/abs/2607.10991v1","html_url":"https://arxiv.org/html/2607.10991v1","pdf_url":"https://arxiv.org/pdf/2607.10991v1.pdf","matched_keywords":["3d"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.10990v1","title":"TreeSoc: Tree-Structured Dynamic Reasoning and Tool Synergy for Soccer Video Understanding","abstract":"Automated understanding of complex soccer scenarios from video remains a significant challenge for contemporary vision-language models (VLMs), which suffer from shallow cross-modal alignment and exhibit fundamental limitations in multi-step reasoning and coordinated tool integration. We present TreeSoc, a structured reasoning framework that reformulates soccer video question answering as a hierarchical search problem rather than a single-pass prediction. Specifically, TreeSoc employs a dynamic depth-first search (DFS) mechanism that decomposes complex queries into sequentially ordered sub-tasks, enabling iterative reasoning refinement through explicit intermediate states. This tree-structured decomposition naturally supports adaptive tool routing, wherein domain-specific modules are selectively activated and their outputs incorporated at each reasoning node to produce contextually grounded predictions. On SoccerBench, TreeSoc achieves state-of-the-art performance, with accuracies of 85.2%, 87.4%, and 82.2% on TextQA, ImageQA, and VideoQA, respectively. Additionally, TreeSoc further demonstrates strong cross-domain generalization, attaining 74.16% accuracy on NExT-QA. These results establish structured, tool-augmented tree reasoning as an effective paradigm for robust video understanding. Code is available at: https://github.com/thanhnhan29/TreeSoc.","authors":["Thanh-Nhan Vo","Thanh-Khoi Nguyen","Trong-Thuan Nguyen","Trung-Hoang Le","Minh-Triet Tran"],"published":"2026-07-13T01:27:20Z","updated":"2026-07-13T01:27:20Z","abstract_url":"https://arxiv.org/abs/2607.10990v1","html_url":"https://arxiv.org/html/2607.10990v1","pdf_url":"https://arxiv.org/pdf/2607.10990v1.pdf","matched_keywords":["video"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.10988v1","title":"MMA-Former: Multi-Window Mixture-of-Head Attention Transformer for Adaptive PNI Prediction in 3D MRI","abstract":"Perineural invasion (PNI) is a critical prognostic factor in cholangiocarcinoma. Non-invasive prediction from 3D MRI is challenging, demanding models that efficiently capture both fine-grained details and global context. We propose the Multi-window Mixture-of-Head Attention Transformer (MMA-Former), a novel end-to-end 3D architecture featuring a Coarse-Fine Transformer (CFT) structure for parallel multi-scale feature extraction. We advance this structure by integrating a novel Window-Specific Mixture-of-Head attention (WS-MoH) mechanism. Unlike standard Multi-Head Self Attention (MSA), WS-MoH generates a representation for each 3D window and dynamically routes the entire window to specialized or common attention heads. This enables spatially adaptive feature extraction tailored to the local context of each window, enhancing specialization and reducing redundancy without increasing parameters. Evaluated on a retrospective dataset of 168 T1-weighted MRI scans, MMA-Former achieved an AUC of 0.752, outperforming other 3D architectures, including the best CNN (AUC of 0.708) and Transformer baselines (AUC of 0.681).","authors":["Youngung Han","Induk Um","Kyeonghun Kim","Junga Kim","Hyunsu Go","Jaewon Jung","Woo Kyoung Jeong","Won Jae Lee","Pa Hong","Ken Ying-Kai Liao","Hyuk-Jae Lee","Nam-Joon Kim"],"published":"2026-07-13T01:22:16Z","updated":"2026-07-13T01:22:16Z","abstract_url":"https://arxiv.org/abs/2607.10988v1","html_url":"https://arxiv.org/html/2607.10988v1","pdf_url":"https://arxiv.org/pdf/2607.10988v1.pdf","matched_keywords":["3d","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.10984v1","title":"EquiFusion: Kinematics-Agnostic Human Motion Prediction via Equivariant Latent Diffusion","abstract":"Existing Stochastic 3D Human Motion Prediction models are fundamentally constrained by hard-coding the skeleton kinematics, severely limiting generalization, preventing cross-dataset training, and requiring complex data retargeting. We introduce EquiFusion, the first kinematics-agnostic model to solve this bottleneck, implementing a latent diffusion model with a permutation equivariant architecture. EquiFusion treats the kinematics' connectivity as an explicit input parameter, ensuring its internal computations are inherently agnostic to joint ordering and graph structure. This novel design enables truly cross-dataset generalization to unseen kinematics and unlocks novel zero-shot directions, such as motion prediction from partial or occluded observations and targeted limb generation. EquiFusion achieves state-of-the-art results on major benchmarks, being up to 75% more compact than previous kinematics-specific methods, while achieving faster training and inference. EquiFusion thus establishes a new, flexible standard for robust human motion prediction. Model and training code are available at https://ceveloper.github.io/publications/equifusion/.","authors":["Cecilia Curreli","Florian Hofherr","Dominik Muhle","Abhishek Saroha","Riccardo Marin","Daniel Cremers"],"published":"2026-07-13T01:16:18Z","updated":"2026-07-13T01:16:18Z","abstract_url":"https://arxiv.org/abs/2607.10984v1","html_url":"https://arxiv.org/html/2607.10984v1","pdf_url":"https://arxiv.org/pdf/2607.10984v1.pdf","matched_keywords":["3d","diffusion"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"},{"id":"2607.10953v1","title":"Learning Anatomy-Grounded CT Vision-Language Representations with Organ-Hierarchical Report Knowledge","abstract":"Medical vision-language pretraining (VLP) from paired CT images and radiology reports enables scalable representation learning, but most existing methods align either whole scans with entire reports or local image regions with text fragments. These formulations underuse a key property of radiology reports: findings are organized around anatomical structures, with abnormalities described by organs, disease concepts, locations, and severity-related attributes. We propose OKA-CT, an organ-hierarchical knowledge-augmented framework for CT-report VLP. OKA-CT first converts free-text reports into organ-conditioned knowledge using radiology report parsing and LLM-assisted semantic structuring. The extracted hierarchy is used across two learning stages. Stage~1 injects anatomy-grounded evidence into the CT visual representation through fine-grained organ-conditioned supervision, while Stage~2 uses organ-specific report evidence to guide structured report-CT contrastive learning, where hierarchy-derived semantic soft targets treat non-paired cases with shared organ-level findings as weak semantic positives rather than uniform negatives. A lightweight query-based global branch further aggregates disease-relevant volumetric evidence for whole-scan representation. On CT-RATE and RAD-ChestCT datasets, OKA-CT achieves zero-shot abnormality diagnosis AUROCs of 84.9 and 72.2, outperforming prior CT VLP baselines. Retrieval and patch-occlusion analyses further show improved report-image alignment and stronger sensitivity to disease-associated anatomical regions.","authors":["Guoliang You","Hongming Li","Yuanwang Zhang","Yong Fan"],"published":"2026-07-12T23:09:23Z","updated":"2026-07-12T23:09:23Z","abstract_url":"https://arxiv.org/abs/2607.10953v1","html_url":"https://arxiv.org/html/2607.10953v1","pdf_url":"https://arxiv.org/pdf/2607.10953v1.pdf","matched_keywords":["retrieval","representation"],"source_used":"abstract","source_text_chars":0,"summary":null,"first_seen_at":"2026-07-14T03:53:24+00:00","last_seen_at":"2026-07-14T03:53:24+00:00"}],"tracked_paper_count":64,"storage_mode":"latest_overwrite"}};
